class DocumentationScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._active_section = 0
        Clock.schedule_once(self.build_ui, 0)

    _DOC_SECTIONS = [
        ('Overview',          'overview'),
        ('Products',          'products'),
        ('Daily Workflow',    'workflow'),
        ('Licensing Deep',    'licensing'),
        ('Backups',           'backups'),
        ('Revocations',       'revocations'),
        ('Add New Product',   'new_product'),
        ('PEM / Keys',        'pem'),
    ]

    def _get_section_text(self, key):
        if key == 'overview':
            return (
                "SH VERTEX ADMIN PANEL - OVERVIEW\n"
                "==================================\n\n"
                "Private enterprise admin panel for SH Vertex Technologies.\n"
                "Manages licensing, authority keys, backups, revocations,\n"
                "customer records, release tracking, and website registries.\n\n"
                "PRODUCTS MANAGED (5 total):\n"
                "  1. Synapse by SHV - project management\n"
                "  2. Casino Tools Pro - gambling analytics\n"
                "  3. Strategy Suite Pro - shares auth with CTP\n"
                "  4. SimpliBudget by SHV - budget management\n"
                "  5. SHV Supa - standalone Supabase admin\n\n"
                "ARCHITECTURE:\n"
                "  Each product has its own license DB and revocation lane.\n"
                "  CTP and SSP share the same authority keypair.\n"
                "  All others have independent RSA 2048-bit keypairs.\n"
                "  License codes = RSA-signed + zlib-compressed + base64.\n"
                "  Revocation lists = signed JSON fetched from GitHub raw URL.\n\n"
                "DATA LOCATION:\n"
                "  Android: app.user_data_dir (private app storage)\n"
                "  Exports: Downloads/SH Vertex Admin Panel/Licensing/<Product>/"
            )
        if key == 'products':
            return (
                "PRODUCT DETAILS\n"
                "================\n\n"
                "1. SYNAPSE BY SHV\n"
                "   Prefix: LIC-   Code: CTP6A-\n"
                "   Tiers: demo, pro, pro_plus\n"
                "   Auth: license_private.pem / license_public.pem\n"
                "   DB: licenses_db.json\n\n"
                "2. CASINO TOOLS PRO\n"
                "   Prefix: LIC-   Code: CTP6A-\n"
                "   Tiers: demo, pro, pro_plus\n"
                "   Auth: license_private.pem / license_public.pem (shared with SSP)\n"
                "   DB: licenses_db.json\n\n"
                "3. STRATEGY SUITE PRO\n"
                "   Shares all auth with Casino Tools Pro.\n"
                "   Same keypair, same DB, same revocation file.\n"
                "   Shown separately in the admin panel for clarity.\n\n"
                "4. SIMPLIBUDGET BY SHV\n"
                "   Prefix: BGT-   Code: BGT6A-\n"
                "   Tiers: pro\n"
                "   Auth: shv_admin_private.pem / shv_admin_public.pem\n"
                "   DB: budget_licenses_db.json\n\n"
                "5. SHV SUPA\n"
                "   Prefix: SPA-   Code: SPA6A-\n"
                "   Tiers: pro\n"
                "   Auth: supa_private.pem / supa_public.pem\n"
                "   DB: supa_licenses_db.json\n"
                "   GitHub: LICENSING/APPS/REVOCATIONS/supa-revo.json"
            )
        if key == 'workflow':
            return (
                "DAILY WORKFLOW\n"
                "===============\n\n"
                "ISSUING A LICENSE:\n"
                "  1. Customer sends Device Code from within their app.\n"
                "  2. Licensing > Apps > Open <Product> > Generate tab.\n"
                "  3. Paste device code, select tier and payment source.\n"
                "  4. Tap Generate License.\n"
                "  5. Copy the activation code and send to customer.\n\n"
                "REVOKING A LICENSE:\n"
                "  1. Product manager > Licenses tab > find > tap Revoke.\n"
                "  2. Revocations tab > Generate Signed Revocation File.\n"
                "  3. Upload to GitHub or save and deploy manually.\n"
                "  4. Customer app detects revocation on next launch.\n\n"
                "CHECKING AUTHORITY HEALTH:\n"
                "  Home > Company Modules > Authority Status.\n"
                "  All 5 products should show Authority Loaded = Yes.\n"
                "  Fingerprint should match your backup copy.\n\n"
                "AFTER ADDING A NEW CUSTOMER:\n"
                "  Details appear under Licensing > Customers automatically.\n"
                "  Generate a Full Backup after issuing to protect the record."
            )
        if key == 'licensing':
            return (
                "LICENSING SYSTEM - DEEP DIVE\n"
                "=============================\n\n"
                "HOW IT WORKS:\n"
                "  Admin holds RSA private key (never shared).\n"
                "  Customer app has RSA public key embedded at build time.\n\n"
                "  When you generate a license the admin panel:\n"
                "    a) Builds payload JSON (app, tier, device_code, issued_at)\n"
                "    b) Signs it with the private key using SHA-256\n"
                "    c) Encodes: payload+sig > zlib compress > base64 > chunks\n"
                "    d) Prefixes with app code (e.g. SPA6A-)\n\n"
                "  Customer pastes the code. App decodes, verifies signature\n"
                "  with embedded public key. If valid + device matches > unlocked.\n\n"
                "DEVICE CODE:\n"
                "  Generated inside customer app from device ANDROID_ID.\n"
                "  = first 8 chars of SHA256(android_id).upper()\n"
                "  Example: 3FA8B20C\n"
                "  License is bound to this code - cannot transfer devices.\n\n"
                "TIERS:\n"
                "  demo     - limited features\n"
                "  pro      - full features\n"
                "  pro_plus - full features + extras (CTP/Synapse only)\n\n"
                "SOURCES (payment methods):\n"
                "  crypto, bank, promo, partner, personal, test"
            )
        if key == 'backups':
            return (
                "BACKUP AND RESTORE GUIDE\n"
                "=========================\n\n"
                "THREE BACKUP TYPES:\n\n"
                "1. AUTHORITY BACKUP (.ctp)\n"
                "   Contains: private key PEM + public key PEM\n"
                "   Use: moving admin to new device, or safety copy.\n"
                "   WARNING: Contains your private key. Store securely!\n"
                "   Encryption: XOR cipher with PBKDF2 (200,000 rounds).\n\n"
                "2. LICENSE LIST BACKUP (.ctlist)\n"
                "   Contains: all license records for that product.\n"
                "   Use: syncing license DB, or after a device reset.\n"
                "   Does NOT change your authority keys.\n\n"
                "3. FULL BACKUP (.ctfull)\n"
                "   Contains: authority keys + license list + revocations.\n"
                "   Use: complete migration or disaster recovery.\n"
                "   Safest single-file backup option.\n\n"
                "RECOMMENDED FREQUENCY:\n"
                "  Authority backup: once after init, store offsite.\n"
                "  Full backup: after every 5+ new licenses issued.\n"
                "  License list: daily if actively selling.\n\n"
                "RESTORE PROCESS:\n"
                "  1. Product manager > Authority tab.\n"
                "  2. Enter backup password.\n"
                "  3. Paste backup text or tap Import File.\n"
                "  4. Tap Import Authority or Import Full Backup.\n"
                "  5. Verify fingerprint matches your backup copy."
            )
        if key == 'revocations':
            return (
                "REVOCATION SYSTEM\n"
                "==================\n\n"
                "HOW REVOCATION WORKS:\n"
                "  Admin panel maintains a list of revoked license IDs.\n"
                "  When you revoke a license it is marked in the local DB.\n"
                "  You then generate and publish a signed revocation JSON.\n"
                "  Customer apps fetch this JSON from the GitHub raw URL on launch.\n"
                "  If the customer license ID appears in the list > app locks.\n\n"
                "REVOCATION JSON FORMAT:\n"
                "  { payload: { app, version, updated_at, revoked_ids: [...] },\n"
                "    signature: <RSA-SHA256 base64> }\n\n"
                "PUBLISHING (Option A - GitHub Upload, recommended):\n"
                "  1. Configure owner/repo/branch/path/token in Revocations tab.\n"
                "  2. Tap Upload Revocation JSON.\n"
                "  3. Apps will fetch it automatically on next launch.\n\n"
                "PUBLISHING (Option B - Manual):\n"
                "  1. Tap Save <product>_revoked_licenses.json.\n"
                "  2. Upload the file to your GitHub repo manually.\n\n"
                "GITHUB RAW URL PATTERN:\n"
                "  https://raw.githubusercontent.com/<owner>/<repo>/<branch>/<path>\n\n"
                "IMPORTANT:\n"
                "  Revoked licenses deleted from DB disappear from future exports.\n"
                "  Only delete test keys - never delete real revocations."
            )
        if key == 'new_product':
            return (
                "HOW TO ADD A NEW PRODUCT\n"
                "=========================\n\n"
                "STEP 1 - DEFINE THE MODULE SOURCE STRING\n"
                "  Copy an existing _SUPA_MODULE_SOURCE block.\n"
                "  Rename all identifiers. Key items to change:\n"
                "    PRIVATE_KEY_FILE = '<product>_private.pem'\n"
                "    PUBLIC_KEY_FILE  = '<product>_public.pem'\n"
                "    LICENSE_DB_FILE  = '<product>_licenses_db.json'\n"
                "    BACKUP_BUNDLE_APP = '<product_id>'\n"
                "    Activation prefix (e.g. XYZ6A-)\n"
                "    build_revocation_bundle app field\n\n"
                "STEP 2 - EXEC INTO NAMESPACE\n"
                "  _NEW_NS = {'__name__': '_new_product_module'}\n"
                "  exec(_NEW_MODULE_SOURCE, _NEW_NS)\n"
                "  _NEW_NS.update({shared helpers})\n"
                "  NewLicenseScreen = _NEW_NS['LicenseManagerScreen']\n\n"
                "STEP 3 - CREATE SHELL SCREEN\n"
                "  class NewManagerShellScreen(Screen):\n"
                "      # Same deferred-load pattern as SupaManagerShellScreen\n\n"
                "STEP 4 - WIRE INTO HUB SCREENS\n"
                "  Add overrides for:\n"
                "    product_summary(), product_backup_categories(),\n"
                "    aggregated_customer_rows()\n"
                "  Add to FINAL OVERRIDES block:\n"
                "    _supa_apps_refresh_ui - add new item to items tuple\n"
                "    _supa_backup_vault_refresh_ui - add new section\n"
                "    _supa_authority_status_refresh_ui - add new row\n"
                "  Update _supa_premium_admin_home_refresh_ui:\n"
                "    Add product_summary() call\n"
                "    Update totals and Products chip count\n\n"
                "STEP 5 - REGISTER IN app.build()\n"
                "  sm.add_widget(NewManagerShellScreen(name='new_manager'))\n\n"
                "STEP 6 - UPDATE BACK BUTTON REGISTRY\n"
                "  Add to _SCREEN_BACK_TARGETS: 'new_manager': 'apps'\n\n"
                "STEP 7 - INJECT NAV\n"
                "  _inject_nav(NewManagerShellScreen, 'new_manager', 'apps')\n\n"
                "STEP 8 - GENERATE AUTHORITY\n"
                "  Admin Panel > Licensing > Apps > Open New Product\n"
                "  Tap Initialize Authority > Copy Public Key PEM\n"
                "  Embed PEM in customer app license_manager.py"
            )
        if key == 'pem':
            return (
                "PUBLIC KEY PEM - GUIDE\n"
                "=======================\n\n"
                "WHAT IS A PEM FILE:\n"
                "  PEM (Privacy Enhanced Mail) is the standard text encoding\n"
                "  for RSA keys. It looks like:\n"
                "    -----BEGIN RSA PUBLIC KEY-----\n"
                "    MIIBCgKCAQEA...(base64)...\n"
                "    -----END RSA PUBLIC KEY-----\n\n"
                "ADMIN PANEL HOLDS:\n"
                "  Private key - used to SIGN license payloads.\n"
                "  Public key  - used to VERIFY signatures in customer app.\n"
                "  NEVER share the private key. Back it up encrypted.\n\n"
                "CUSTOMER APP HOLDS:\n"
                "  Only the public key, hardcoded as bytes literal:\n"
                "    PUBLIC_KEY_PEM = b'-----BEGIN RSA PUBLIC KEY-----...'\n\n"
                "HOW TO GET THE PUBLIC KEY FOR A NEW PRODUCT:\n"
                "  1. Admin Panel > Licensing > Apps > Open <Product>\n"
                "  2. If no authority: tap Initialize Authority\n"
                "  3. Tap Copy Public Key PEM\n"
                "  4. Paste into customer app as PUBLIC_KEY_PEM constant\n"
                "  5. Rebuild and distribute the APK\n\n"
                "IMPORTANT RULES:\n"
                "  Each product has its own unique keypair.\n"
                "  CTP and SSP share one keypair.\n"
                "  If you regenerate a keypair ALL existing licenses for that\n"
                "  product become invalid. Only do this if key is compromised.\n"
                "  Fingerprint = first 16 chars of SHA256(pub_key_pem).upper()\n"
                "  Use fingerprint to confirm correct key is loaded."
            )
        return "Section not available."

    def build_ui(self, *_):
        self.clear_widgets()
        root = BoxLayout(orientation='vertical', padding=[dp(10), dp(10), dp(10), dp(10)], spacing=dp(8))
        root.add_widget(build_screen_header(
            'Documents',
            'In-depth guides for licensing, backups, revocations, and adding new products.',
            'home', [('Modules', 'company_modules')]))

        # Section selector — horizontal scroll tabs
        tab_scroll = ScrollView(
            do_scroll_x=True, do_scroll_y=False,
            bar_width=0, scroll_type=['content'],
            size_hint_y=None, height=dp(52))
        tab_row = BoxLayout(
            orientation='horizontal', spacing=dp(8),
            size_hint=(None, 1), padding=[dp(2), dp(4), dp(2), dp(4)])
        tab_row.bind(minimum_width=tab_row.setter('width'))

        self._tab_btns = []
        for i, (title, key) in enumerate(self._DOC_SECTIONS):
            active = (i == self._active_section)
            btn = RoundedButton(
                text=title,
                bg_hex=UI_CYAN if active else '#182432',
                text_color=get_color_from_hex('#000000' if active else TEXT),
                radius=14,
                size_hint=(None, None),
                width=dp(130), height=dp(42),
                font_size='12sp', bold=True,
            )
            btn.bind(on_release=lambda *_, idx=i: self._switch_section(idx))
            self._tab_btns.append(btn)
            tab_row.add_widget(btn)
        tab_scroll.add_widget(tab_row)
        root.add_widget(tab_scroll)

        # Content scroll area
        self._content_scroll = ScrollView(
            do_scroll_x=False, scroll_type=['bars', 'content'], bar_width=dp(6))
        self._content_outer = GridLayout(
            cols=1, size_hint_y=None, spacing=dp(8), padding=[0, 0, 0, dp(8)])
        self._content_outer.bind(minimum_height=self._content_outer.setter('height'))
        self._content_scroll.add_widget(self._content_outer)
        root.add_widget(self._content_scroll)

        self.add_widget(root)
        self._render_section(self._active_section)

    def _switch_section(self, idx):
        self._active_section = idx
        for i, btn in enumerate(self._tab_btns):
            active = (i == idx)
            try:
                btn._bg_hex = UI_CYAN if active else '#182432'
                btn._border_hex = btn._derive_neon_border(btn._bg_hex)
                btn.color = get_color_from_hex('#000000' if active else TEXT)
                btn._rounded_bg.rgba = get_color_from_hex(btn._bg_hex)
            except Exception:
                pass
        self._render_section(idx)

    def _render_section(self, idx):
        if not hasattr(self, '_content_outer'):
            return
        self._content_outer.clear_widgets()
        title, key = self._DOC_SECTIONS[idx]
        text = self._get_section_text(key)

        card = SectionCard(title, '')
        copy_row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
        copy_btn = make_button('Copy This Section', UI_CYAN)
        copy_btn.bind(on_release=lambda *_: copy_to_clipboard(title, text))
        copy_full_btn = make_button('Copy Full Guide', GREEN)
        copy_full_btn.bind(on_release=lambda *_: copy_to_clipboard('Full Guide', ADMIN_PANEL_FULL_GUIDE))
        copy_row.add_widget(copy_btn)
        copy_row.add_widget(copy_full_btn)
        card.add_widget(copy_row)

        lbl = Label(
            text=text,
            color=get_color_from_hex(TEXT),
            font_size='13sp',
            halign='left',
            valign='top',
            size_hint_y=None,
            markup=False,
        )
        def _sync(*_):
            w = max(dp(240), self._content_scroll.width - dp(32))
            lbl.text_size = (w, None)
            lbl.texture_update()
            lbl.height = max(dp(200), lbl.texture_size[1] + dp(16))
        self._content_scroll.bind(size=lambda *_: _sync())
        lbl.bind(texture_size=lambda *_: _sync())
        Clock.schedule_once(lambda *_: _sync(), 0)
        card.add_widget(lbl)
        self._content_outer.add_widget(card)

