    # ── Dashboard refresh ──────────────────────────────────────────────────

    def refresh_dashboard(self):
        if not hasattr(self,"dashboard_box"):
            return
        self.dashboard_box.clear_widgets()
        records = self.store.records
        total   = len(records)
        active  = len([r for r in records if r.get("status") == "active"])
        revoked = len([r for r in records if r.get("status") == "revoked"])
        pro     = len([r for r in records if r.get("tier") == "pro"])
        auth_card = SectionCard("Authority status")
        if self.public_key and self.private_key:
            auth_card.add_widget(make_label("Authority loaded", GREEN))
            auth_card.add_widget(make_label(f"Data folder: {app_data_dir()}", height=dp(38)))
        else:
            auth_card.add_widget(make_label(
                "No authority loaded. Initialize or import authority.", RED, height=dp(38)))
        self.dashboard_box.add_widget(auth_card)
        stats = SectionCard("License totals")
        for t in [f"Total licenses: {total}", f"Active: {active}",
                  f"Revoked: {revoked}", f"Pro: {pro}"]:
            stats.add_widget(make_label(
                t,
                GREEN if "Active" in t else (RED if "Revoked" in t else TEXT)))
        self.dashboard_box.add_widget(stats)
        latest = SectionCard("Latest issued")
        if records:
            for rec in records[:8]:
                latest.add_widget(make_label(
                    f"{rec['license_id']}  |  {rec['tier']}  |  "
                    f"{rec.get('customer_name','-')}  |  {rec.get('status','active')}",
                    height=dp(22)))
        else:
            latest.add_widget(make_label("No licenses yet."))
        self.dashboard_box.add_widget(latest)

