def _supa_backup_vault_refresh_ui(self, *_):
    self.root_box.clear_widgets()
    self.root_box.add_widget(build_screen_header(
        'Backup Vault',
        'Central vault for authority backups, full backups, license-list backups, and revocation exports.',
        'home', [('Licensing','licensing')]))
    top = SectionCard('Vault Actions',
                      'Open product managers to create new backups, then return here to review the latest saved files.')
    for label, sn, color in (
        ('Open Synapse Vault',     'synapse_manager', GREEN),
        ('Open Casino Tools Vault','casino_manager',  PURPLE),
        ('Open SHV Budget Vault',  'budget_manager',  BLUE),
        ('Open SHV Supa Vault',    'supa_manager',    UI_TEAL),
    ):
        btn = make_button(label, color)
        btn.bind(on_release=lambda *_, s=sn: setattr(self.manager,'current',s))
        top.add_widget(btn)
    self.root_box.add_widget(top)
    for product, color in (
        ('Synapse',          GREEN),
        ('Casino Tools Pro', PURPLE),
        ('SHV Budget',       BLUE),
        ('SHV Supa',         UI_TEAL),
    ):
        pcard = SectionCard(product, 'Latest files across all backup categories for this product.')
        for label, directory in product_backup_categories(product):
            files = []
            try:
                files = [os.path.join(directory, n) for n in os.listdir(directory)
                         if os.path.isfile(os.path.join(directory, n))]
            except Exception:
                files = []
            latest = latest_file_from(files)
            sub    = SectionCard(label, f"Count: {len(files)}")
            if latest:
                sub.add_widget(make_label(f"Latest: {os.path.basename(latest)}", height=dp(22)))
                sub.add_widget(make_label(
                    f"Saved: {file_stamp(latest)}  •  Size: {file_size_text(latest)}",
                    color=SUBTEXT, height=dp(22)))
                copy_btn = make_button('Copy Latest Path', color)
                copy_btn.bind(on_release=lambda *_, p=latest: copy_to_clipboard('Latest backup path', p))
                sub.add_widget(copy_btn)
            else:
                sub.add_widget(make_label('No files yet.', color=SUBTEXT, height=dp(22)))
            pcard.add_widget(sub)
        self.root_box.add_widget(pcard)
