def _render_product_dashboard_state(self, animate=False):
    if not hasattr(self, '_product_dash_body_host'):
        return
    syn = product_summary('Synapse')
    ctp = product_summary('Casino Tools Pro')
    bgt = product_summary('SHV Budget')
    spa = product_summary('SHV Supa')
    product_rows = [
        (syn, UI_GREEN,  'synapse_manager'),
        (ctp, UI_PURPLE, 'casino_manager'),
        (bgt, BLUE,      'budget_manager'),
        (spa, UI_TEAL,   'supa_manager'),
    ]
    collapsed = bool(getattr(self, '_product_dashboard_collapsed', False))
    if hasattr(self, '_product_dash_toggle_lbl'):
        self._product_dash_toggle_lbl.text = (
            'Expand to show all product lanes and quick open buttons.'
            if collapsed else
            'Collapse product cards to save main-screen space.')
    if hasattr(self, '_product_dash_toggle_btn'):
        btn = self._product_dash_toggle_btn
        btn.text = 'Expand' if collapsed else 'Collapse'
        try:
            btn._bg_hex    = UI_GREEN if collapsed else UI_ORANGE
            btn._border_hex= btn._derive_neon_border(btn._bg_hex)
            btn.color      = (0,0,0,1) if btn._bg_hex == GREEN else (1,1,1,1)
            btn._update_bg()
        except Exception:
            pass
    if collapsed:
        new_body = GridLayout(cols=1, spacing=dp(8), size_hint_y=None)
        new_body.bind(minimum_height=new_body.setter('height'))
        compact = GridLayout(cols=4, spacing=dp(8), size_hint_y=None, height=dp(72))
        compact.add_widget(build_stat_chip(
            sum(int(x[0].get('active',0)) for x in product_rows), 'Active', UI_GREEN))
        compact.add_widget(build_stat_chip(
            sum(int(x[0].get('licenses',0)) for x in product_rows), 'Total', UI_CYAN))
        compact.add_widget(build_stat_chip(
            sum(int(x[0].get('revoked',0)) for x in product_rows), 'Revoked', UI_RED))
        compact.add_widget(build_stat_chip(4, 'Products', UI_TEAL))
        new_body.add_widget(compact)
        compact_line = make_label(
            f"Syn {syn.get('active',0)}/{syn.get('licenses',0)}"
            f"  •  CTP {ctp.get('active',0)}/{ctp.get('licenses',0)}"
            f"  •  Bgt {bgt.get('active',0)}/{bgt.get('licenses',0)}"
            f"  •  Supa {spa.get('active',0)}/{spa.get('licenses',0)}",
            color=SUBTEXT, height=dp(28))
        new_body.add_widget(compact_line)
    else:
        new_body = _build_product_dashboard_body(self, product_rows, collapsed=False)
    host    = self._product_dash_body_host
    old_body= getattr(self, '_product_dash_current_body', None)
    if old_body is None or not animate:
        host.clear_widgets()
        host.add_widget(new_body)
        self._product_dash_current_body = new_body
        return
    if getattr(self, '_product_dash_animating', False):
        return
    self._product_dash_animating = True
    def _swap(*_):
        host.clear_widgets()
        new_body.opacity = 0.0
        host.add_widget(new_body)
        self._product_dash_current_body = new_body
        from kivy.animation import Animation as _Anim
        _ai = _Anim(opacity=1.0, duration=0.18, t='out_quad')
        _ai.bind(on_complete=lambda *_: setattr(self,'_product_dash_animating',False))
        _ai.start(new_body)
    from kivy.animation import Animation as _Anim
    _ao = _Anim(opacity=0.0, duration=0.12, t='out_quad')
    _ao.bind(on_complete=_swap)
    _ao.start(old_body)


