# ── Fresh-authority override (no embedded default PEM) ────────────────────────
_SUPA_NS['PRIVATE_KEY_FILE'] = 'supa_private.pem'
_SUPA_NS['PUBLIC_KEY_FILE']  = 'supa_public.pem'

def _supa_fresh_load_existing_keypair():
    priv_path = _SUPA_NS['file_path'](_SUPA_NS['PRIVATE_KEY_FILE'])
    pub_path  = _SUPA_NS['file_path'](_SUPA_NS['PUBLIC_KEY_FILE'])
    if os.path.exists(priv_path) and os.path.exists(pub_path):
        with open(priv_path, 'rb') as f:
            private_key = rsa.PrivateKey.load_pkcs1(f.read())
        with open(pub_path, 'rb') as f:
            public_key  = rsa.PublicKey.load_pkcs1(f.read())
        return public_key, private_key
    return None, None

def _supa_fresh_initialize_authority_keypair():
    priv_path = _SUPA_NS['file_path'](_SUPA_NS['PRIVATE_KEY_FILE'])
    pub_path  = _SUPA_NS['file_path'](_SUPA_NS['PUBLIC_KEY_FILE'])
    if os.path.exists(priv_path) or os.path.exists(pub_path):
        raise RuntimeError('SHV Supa authority already exists on this device.')
    public_key, private_key = rsa.newkeys(2048)
    with open(priv_path, 'wb') as f:
        f.write(private_key.save_pkcs1('PEM'))
    with open(pub_path, 'wb') as f:
        f.write(public_key.save_pkcs1('PEM'))
    return public_key, private_key

def _supa_no_default_authority_files():
    return

_SUPA_NS['load_existing_keypair']       = _supa_fresh_load_existing_keypair
_SUPA_NS['initialize_authority_keypair']= _supa_fresh_initialize_authority_keypair
_SUPA_NS['ensure_default_authority_files'] = _supa_no_default_authority_files

