# PERMANENT BOTTOM NAV BAR — injected at the very end after all patches
# Two rows, 4 buttons each. Teal active, slate idle. Rounded edges.
# ALL logic untouched — layout wrappers only.
# ═══════════════════════════════════════════════════════════════════════════════

NAV_BG       = '#04080d'
NAV_HEIGHT   = dp(58)

# ─────────────────────────────────────────────────────────────────────────────
# BOTTOM NAV BAR — clean fixed 3-button bar
#   Home screen : [HOME]  [LICNSING]  [VAULT]   +  Exit button in top title
#   Other screens: [BACK]  [HOME]     [VAULT]
#
# "active_name" is the screen name string used to decide button highlight.
# "back_target"  is the screen to go to when BACK is pressed (None = go back
#                in history via manager, or to 'home' as fallback).
# ─────────────────────────────────────────────────────────────────────────────

def _make_bottom_nav(screen_instance, active_name='', back_target=None):
    from kivy.graphics import Color as _C, RoundedRectangle as _R

    is_home = (active_name == 'home')

    outer = BoxLayout(orientation='vertical', size_hint_y=None, height=NAV_HEIGHT)

    sep = Widget(size_hint_y=None, height=dp(1))
    with sep.canvas:
        _C(rgba=get_color_from_hex('#0f2130'))
        _sr = _R(pos=sep.pos, size=sep.size, radius=[0])
    sep.bind(pos=lambda *_: setattr(_sr, 'pos', sep.pos),
             size=lambda *_: setattr(_sr, 'size', sep.size))

    bar = BoxLayout(
        orientation='horizontal',
        size_hint_y=None, height=dp(57),
        spacing=dp(8), padding=[dp(8), dp(6), dp(8), dp(6)],
    )
    with bar.canvas.before:
        _C(rgba=get_color_from_hex('#08111b'))
        bar._bg = _R(pos=bar.pos, size=bar.size, radius=[0])
    bar.bind(pos=lambda *_: setattr(bar._bg, 'pos', bar.pos),
             size=lambda *_: setattr(bar._bg, 'size', bar.size))

    def _go(target):
        try:
            screen_instance.manager.current = target
        except Exception:
            pass

    if is_home:
        # Home screen — 3 navigation shortcuts
        buttons = [
            ('HOME',     'home',         '#8b8000'),
            ('LICNSING', 'licensing',    '#8b8000'),
            ('VAULT',    'backup_vault', '#8b8000'),
        ]
        for lbl, tgt, bg in buttons:
            btn = RoundedButton(
                text=lbl, bg_hex=bg,
                text_color=get_color_from_hex('#aaaaaa' if tgt == active_name else '#c1cbe0'),
                radius=14, size_hint=(1, 1), font_size='17sp', bold=True,
            )
            btn.bind(on_release=lambda *_, t=tgt: _go(t))
            bar.add_widget(btn)
    else:
        # Non-home screens — Back | Home | Vault
        # Determine back destination
        _back_dest = back_target or 'home'

        back_btn = RoundedButton(
            text='BACK', bg_hex='#8b8000',
            text_color=get_color_from_hex('#c1cbe0'),
            radius=14, size_hint=(1, 1), font_size='17sp', bold=True,
        )
        home_btn = RoundedButton(
            text='HOME', bg_hex='#8b8000',
            text_color=get_color_from_hex('#c1cbe0'),
            radius=14, size_hint=(1, 1), font_size='17sp', bold=True,
        )
        vault_btn = RoundedButton(
            text='VAULT', bg_hex='#8b8000',
            text_color=get_color_from_hex('#c1cbe0'),
            radius=14, size_hint=(1, 1), font_size='17sp', bold=True,
        )
        back_btn.bind(on_release=lambda *_: _go(_back_dest))
        home_btn.bind(on_release=lambda *_: _go('home'))
        vault_btn.bind(on_release=lambda *_: _go('backup_vault'))
        bar.add_widget(back_btn)
        bar.add_widget(home_btn)
        bar.add_widget(vault_btn)

    outer.add_widget(sep)
    outer.add_widget(bar)
    return outer

def _inject_nav(screen_cls, active_name, back_target=None):
    """
    Wrap build_ui to append a permanent bottom nav bar.
    For screens that use build_ui + refresh_ui pattern:
      - build_ui sets up the scroll/root_box structure ONCE
      - refresh_ui only repopulates root_box content
    We wrap build_ui so the nav bar is added once at build time,
    and the scroll area sits inside a wrapper that already has the nav.
    """
    if getattr(screen_cls, '_nav_bar_injected', False):
        return

    _orig_build = screen_cls.build_ui

    def _nav_build_ui(self, *a, **kw):
        _orig_build(self, *a, **kw)
        if not self.children:
            return
        children = list(reversed(self.children))
        self.clear_widgets()
        outer = BoxLayout(orientation='vertical')
        for child in children:
            outer.add_widget(child)
        outer.add_widget(_make_bottom_nav(self, active_name, back_target))
        self.add_widget(outer)

    _nav_build_ui.__name__ = 'build_ui'
    _nav_build_ui.__qualname__ = screen_cls.__name__ + '.build_ui'
    screen_cls.build_ui = _nav_build_ui
    screen_cls._nav_build_ui = _nav_build_ui
    screen_cls._nav_bar_injected = True


# Inject nav into every main screen
