SSP_PRODUCT_NAME = 'Strategy Suite Pro'
SSP_ACCENT = UI_CYAN

_prev_product_backup_categories = product_backup_categories

def product_backup_categories(product):
    if product == SSP_PRODUCT_NAME:
        return [
            ('Authority Backups', _CTP_NS['authority_backup_dir']()),
            ('Full Backups', _CTP_NS['full_backup_dir']()),
            ('License-List Backups', _CTP_NS['license_list_backup_dir']()),
            ('Revocation Jsons', _CTP_NS['revocation_backup_dir']()),
        ]
    return _prev_product_backup_categories(product)

_prev_product_summary_ssp = product_summary

def product_summary(product):
    if product == SSP_PRODUCT_NAME:
        base = dict(_prev_product_summary_ssp('Casino Tools Pro'))
        base['product'] = SSP_PRODUCT_NAME
        return base
    return _prev_product_summary_ssp(product)


def _retitle_widget_texts(widget, mapping):
    try:
        if hasattr(widget, 'text'):
            current = str(getattr(widget, 'text', ''))
            if current in mapping:
                widget.text = mapping[current]
    except Exception:
        pass
    for child in getattr(widget, 'children', []) or []:
        _retitle_widget_texts(child, mapping)


class StrategySuiteManagerShellScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.manager_widget = None
        Clock.schedule_once(self.build_ui, 0)

    def build_ui(self, *_):
        self.clear_widgets()
        root = BoxLayout(orientation='vertical', padding=dp(10), spacing=dp(10))
        nav = BoxLayout(size_hint_y=None, height=dp(46), spacing=dp(8))
        back_btn = make_button('Back to Apps', UI_CYAN)
        home_btn = make_button('Admin Home', UI_CYAN)
        vault_btn = make_button('Vault', UI_CYAN)
        back_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'apps'))
        home_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'home'))
        vault_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'backup_vault'))
        nav.add_widget(back_btn)
        nav.add_widget(home_btn)
        nav.add_widget(vault_btn)
        root.add_widget(nav)
        placeholder = SectionCard('Strategy Suite Pro Licensing', 'This lane uses the same activation foundation as Casino Tools Pro, but is presented separately for the clean version buyer package.')
        placeholder.add_widget(make_label('Open this screen to load the Strategy Suite Pro licensing tools.', color=SUBTEXT, height=dp(28)))
        self._body_host = BoxLayout()
        self._body_host.add_widget(placeholder)
        root.add_widget(self._body_host)
        self.add_widget(root)

    def _apply_ssp_titles(self):
        if getattr(self, 'manager_widget', None) is None:
            return
        mapping = {
            'Casino Tools License Manager': 'Strategy Suite Pro Licensing',
            'Casino Tools Pro': 'Strategy Suite Pro',
            'Open Casino Tools Pro': 'Open Strategy Suite Pro',
        }
        _retitle_widget_texts(self.manager_widget, mapping)

    def on_pre_enter(self, *_):
        if getattr(self, 'manager_widget', None) is None:
            if hasattr(self, '_body_host'):
                self._body_host.clear_widgets()
                loading = SectionCard('Strategy Suite Pro Licensing', 'Loading the interface...')
                loading.add_widget(make_label('Please wait while the licensing tools initialize.', color=SUBTEXT, height=dp(28)))
                self._body_host.add_widget(loading)

            def _load_widget(*__):
                try:
                    self.manager_widget = CasinoToolsLicenseManagerScreen()
                    if hasattr(self, '_body_host'):
                        self._body_host.clear_widgets()
                        wrapper = BoxLayout(orientation='vertical', spacing=dp(8))
                        intro = SectionCard('Strategy Suite Pro', 'Shared authority and shared key engine with Casino Tools Pro, exposed here as a separate product lane for the buyer package.')
                        intro.add_widget(make_label('Use this lane when you want the clean-version branding visible inside the Admin Panel.', color=SUBTEXT, height=dp(28)))
                        wrapper.add_widget(intro)
                        wrapper.add_widget(self.manager_widget)
                        self._body_host.add_widget(wrapper)
                    Clock.schedule_once(lambda *_: self._apply_ssp_titles(), 0)
                    Clock.schedule_once(lambda *_: self._apply_ssp_titles(), 0.1)
                except Exception as e:
                    if hasattr(self, '_body_host'):
                        self._body_host.clear_widgets()
                        failed = SectionCard('Strategy Suite Pro Licensing Error', 'The APK hit an initialization error while opening this module.')
                        failed.add_widget(make_label(str(e), color=RED, height=dp(72)))
                        retry_btn = make_button('Retry', GREEN)
                        retry_btn.bind(on_release=lambda *_: self.on_pre_enter())
                        failed.add_widget(retry_btn)
                        self._body_host.add_widget(failed)

            Clock.schedule_once(_load_widget, 0)
        else:
            Clock.schedule_once(lambda *_: self._apply_ssp_titles(), 0)


_inject_nav(StrategySuiteManagerShellScreen, 'ssp_manager')


