# ---- final compact UI refinement patch (UI only; logic preserved) ----

def _shorten_subtitle(text, max_len=88):
    txt = str(text or '').strip()
    if not txt:
        return ''
    if len(txt) <= max_len:
        return txt
    return txt[: max_len - 1].rstrip() + '…'


class RoundedButton(Button):
    def __init__(self, bg_hex=UI_GREEN, text_color=None, radius=16, border_hex=None, **kwargs):
        kwargs.setdefault('background_normal', '')
        kwargs.setdefault('background_down', '')
        kwargs.setdefault('background_color', (0, 0, 0, 0))
        kwargs.setdefault('color', get_color_from_hex(UI_TEXT))
        kwargs.setdefault('font_size', '13sp')
        kwargs.setdefault('bold', True)
        kwargs.setdefault('size_hint_y', None)
        kwargs.setdefault('height', dp(44))
        kwargs.setdefault('halign', 'center')
        kwargs.setdefault('valign', 'middle')
        super().__init__(**kwargs)
        self._bg_hex = str(bg_hex or UI_GREEN)
        self._fill_hex = _button_fill_for(self._bg_hex)
        self._border_hex = border_hex or self._derive_neon_border(self._bg_hex)
        self._radius = dp(radius)
        self._inset = dp(2)
        if text_color is not None:
            self.color = text_color
        self.bind(size=lambda inst, val: setattr(inst, 'text_size', (max(0, val[0] - dp(10)), max(0, val[1] - dp(4)))))
        with self.canvas.before:
            self._shadow_color = _UIColor(*_hex_rgba('#000000', 0.18))
            self._shadow = _UIRoundedRectangle(pos=(self.x, self.y - dp(1)), size=self.size, radius=[self._radius])
            self._fill_color = _UIColor(*_hex_rgba(self._fill_hex, 1.0))
            self._fill = _UIRoundedRectangle(pos=self.pos, size=self.size, radius=[self._radius])
            self._border_color = _UIColor(*_hex_rgba(self._border_hex, 0.85))
            self._border = _UILine(rounded_rectangle=(self.x, self.y, self.width, self.height, self._radius), width=1.0)
        self.bind(pos=self._update_bg, size=self._update_bg, state=self._update_bg, disabled=self._update_bg)
        self._update_bg()

    def _derive_neon_border(self, bg_hex):
        return _button_border_for(bg_hex)

    def _update_bg(self, *_):
        pressed = self.state == 'down'
        fill = _button_fill_for(self._bg_hex)
        border = self._derive_neon_border(self._bg_hex)
        fill_rgba = _mix_hex(fill, self._bg_hex, 0.18 if pressed else 0.06)
        self._shadow.pos = (self.x, self.y - dp(1))
        self._shadow.size = self.size
        self._fill.pos = self.pos
        self._fill.size = self.size
        self._border.rounded_rectangle = (self.x, self.y, self.width, self.height, self._radius)
        self._shadow_color.rgba = _hex_rgba('#000000', 0.22 if not self.disabled else 0.10)
        self._fill_color.rgba = fill_rgba if not self.disabled else _hex_rgba(UI_SOFT, 0.90)
        self._border_color.rgba = _hex_rgba(border, 0.88 if not self.disabled else 0.40)
        self.opacity = 0.96 if pressed else 1.0


class SectionCard(BoxLayout):
    def __init__(self, title, subtitle='', accent=None, **kwargs):
        kwargs.setdefault('orientation', 'vertical')
        kwargs.setdefault('spacing', dp(8))
        kwargs.setdefault('padding', [dp(12), dp(12), dp(12), dp(12)])
        kwargs.setdefault('size_hint_y', None)
        super().__init__(**kwargs)
        self.bind(minimum_height=self.setter('height'))
        self._accent = accent or _section_accent(title)
        self._radius = dp(18)
        with self.canvas.before:
            self._bg_color = _UIColor(*_hex_rgba(UI_CARD, 1.0))
            self._bg = _UIRoundedRectangle(pos=self.pos, size=self.size, radius=[self._radius])
            self._border_color = _UIColor(*_hex_rgba(UI_LINE, 0.95))
            self._border = _UILine(rounded_rectangle=(self.x, self.y, self.width, self.height, self._radius), width=1.0)
        self.bind(pos=self._update_bg, size=self._update_bg)
        self._update_bg()

        head = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(2))
        head.bind(minimum_height=head.setter('height'))
        title_row = BoxLayout(size_hint_y=None, height=dp(24), spacing=dp(6))
        dot = AccentDot(self._accent, dp(8))
        dot.pos_hint = {'center_y': 0.5}
        title_row.add_widget(dot)
        title_lbl = Label(text=str(title or ''), color=get_color_from_hex(UI_TEXT), bold=True, font_size='17sp', size_hint_y=None, height=dp(24), halign='left', valign='middle')
        title_lbl.bind(size=lambda inst, val: setattr(inst, 'text_size', val))
        title_row.add_widget(title_lbl)
        head.add_widget(title_row)
        short_sub = _shorten_subtitle(subtitle, 96)
        if short_sub:
            sub_lbl = Label(text=short_sub, color=get_color_from_hex(UI_MUTE), font_size='11sp', size_hint_y=None, halign='left', valign='middle')
            sub_lbl.bind(size=lambda inst, val: setattr(inst, 'text_size', (val[0], None)))
            sub_lbl.bind(texture_size=lambda inst, val: setattr(inst, 'height', max(dp(16), val[1])))
            head.add_widget(sub_lbl)
        self.add_widget(head)

    def _update_bg(self, *_):
        self._bg.pos = self.pos
        self._bg.size = self.size
        self._border.rounded_rectangle = (self.x, self.y, self.width, self.height, self._radius)


def make_button(text, color=UI_GREEN):
    return RoundedButton(text=text, size_hint_y=None, height=dp(44), bg_hex=color, text_color=get_color_from_hex(UI_TEXT), radius=16)


def make_nav_button(text):
    return RoundedButton(text=text, size_hint=(1, None), height=dp(40), bg_hex=UI_CYAN, text_color=get_color_from_hex(UI_TEXT), radius=16)


def build_top_title(text, size='28sp'):
    box = BoxLayout(orientation='vertical', spacing=dp(3), size_hint_y=None)
    box.bind(minimum_height=box.setter('height'))
    pill = BoxLayout(size_hint_y=None, height=dp(16), spacing=dp(5))
    pill.add_widget(Widget())
    pill.add_widget(AccentDot(UI_GREEN, dp(7)))
    pill.add_widget(_soft_text('SH VERTEX ADMIN', size='10sp', color=UI_GREEN, bold=True, height=dp(16), halign='center'))
    pill.add_widget(Widget())
    box.add_widget(pill)
    lbl = Label(text=text, color=get_color_from_hex(UI_TEXT), bold=True, font_size=size, size_hint_y=None, height=dp(42), halign='center', valign='middle')
    lbl.bind(size=lambda inst, val: setattr(inst, 'text_size', val))
    box.add_widget(lbl)
    box._title_label = lbl
    return box


def build_screen_header(title, subtitle='', back_target='home', extra=None):
    box = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(6))
    box.bind(minimum_height=box.setter('height'))
    head = SectionCard(title, _shorten_subtitle(subtitle, 72) if subtitle else '', accent=_section_accent(title))
    row = BoxLayout(size_hint_y=None, height=dp(40), spacing=dp(8))
    if back_target:
        back_btn = make_button('Back', UI_CYAN)
        back_btn.bind(on_release=lambda *_: setattr(App.get_running_app().root, 'current', back_target))
        row.add_widget(back_btn)
    if extra:
        for label, target in extra:
            btn = make_button(label, UI_CYAN)
            btn.bind(on_release=lambda *_ , t=target: setattr(App.get_running_app().root, 'current', t) if isinstance(t, str) else t())
            row.add_widget(btn)
    if row.children:
        head.add_widget(row)
    box.add_widget(head)
    return box


def build_stat_chip(value, label, accent=UI_GREEN):
    card = BoxLayout(orientation='vertical', size_hint_y=None, height=dp(58), padding=[dp(10), dp(8), dp(10), dp(7)], spacing=dp(1))
    radius = dp(14)
    with card.canvas.before:
        card._bg_c = _UIColor(*_hex_rgba(UI_CARD_2, 1.0))
        card._bg = _UIRoundedRectangle(pos=card.pos, size=card.size, radius=[radius])
        card._border_c = _UIColor(*_hex_rgba(_button_border_for(accent), 0.70))
        card._border = _UILine(rounded_rectangle=(card.x, card.y, card.width, card.height, radius), width=1.0)
    def _upd(*_):
        card._bg.pos = card.pos
        card._bg.size = card.size
        card._border.rounded_rectangle = (card.x, card.y, card.width, card.height, radius)
    card.bind(pos=_upd, size=_upd)
    _upd()
    v = Label(text=str(value), color=get_color_from_hex(UI_TEXT), bold=True, font_size='16sp', size_hint_y=None, height=dp(22), halign='left', valign='middle')
    v.bind(size=lambda inst, val: setattr(inst, 'text_size', val))
    l = Label(text=str(label).upper(), color=get_color_from_hex(UI_MUTE), font_size='9sp', size_hint_y=None, height=dp(14), halign='left', valign='middle', bold=True)
    l.bind(size=lambda inst, val: setattr(inst, 'text_size', val))
    card.add_widget(v)
    card.add_widget(l)
    return card


