def _find_first_descendant(root, predicate):
    if root is None:
        return None
    queue = [root]
    seen = set()
    while queue:
        node = queue.pop(0)
        if id(node) in seen:
            continue
        seen.add(id(node))
        try:
            if predicate(node):
                return node
        except Exception:
            pass
        for child in getattr(node, 'children', []) or []:
            queue.append(child)
    return None


def _patch_generate_view_with_device_paste(screen_cls, accent=UI_CYAN, clear_color=UI_RED):
    original = getattr(screen_cls, 'build_generate_view', None)
    if not callable(original) or getattr(screen_cls, '_device_paste_patch_done', False):
        return
    def patched(self, *args, **kwargs):
        view = original(self, *args, **kwargs)
        try:
            if getattr(view, '_device_paste_controls_added', False):
                return view
            device_widget = getattr(self, 'device_input', None)
            if device_widget is None:
                return view
            parent = _find_first_descendant(view, lambda w: hasattr(w, 'children') and device_widget in list(getattr(w, 'children', [])))
            if parent is None or not hasattr(parent, 'add_widget'):
                return view
            existing = _find_first_descendant(view, lambda w: getattr(w, '_is_device_tools_row', False))
            if existing is not None:
                view._device_paste_controls_added = True
                return view
            row = BoxLayout(size_hint_y=None, height=dp(44), spacing=dp(8))
            row._is_device_tools_row = True
            paste_btn = make_button('Paste Device Code', accent)
            clear_btn = make_button('Clear Device Code', clear_color)
            paste_btn.bind(on_release=lambda *_: paste_clipboard_into(device_widget))
            clear_btn.bind(on_release=lambda *_: setattr(device_widget, 'text', ''))
            row.add_widget(paste_btn)
            row.add_widget(clear_btn)
            try:
                insert_index = max(0, parent.children.index(device_widget))
                parent.add_widget(row, index=insert_index)
            except Exception:
                parent.add_widget(row)
            view._device_paste_controls_added = True
        except Exception:
            pass
        return view
    screen_cls.build_generate_view = patched
    screen_cls._device_paste_patch_done = True


