# ---- final UI polish patch: SimpliBudget naming, keyboard behavior, authority lights, duplicate device-row cleanup ----
from kivy.graphics import Color as _BlinkColor, Ellipse as _BlinkEllipse

SIMPLIBUDGET_PRODUCT_NAME = 'SimpliBudget by SHV'


def _walk_widgets(root):
    if root is None:
        return
    queue = [root]
    seen = set()
    while queue:
        node = queue.pop(0)
        if id(node) in seen:
            continue
        seen.add(id(node))
        yield node
        for child in getattr(node, 'children', []) or []:
            queue.append(child)


def _retitle_budget_mentions_in_widget(root):
    replacements = {
        'SHV Budget': SIMPLIBUDGET_PRODUCT_NAME,
        'Open SHV Budget Vault': f'Open {SIMPLIBUDGET_PRODUCT_NAME} Vault',
    }
    for node in _walk_widgets(root):
        for attr in ('text', 'title'):
            if not hasattr(node, attr):
                continue
            try:
                current = str(getattr(node, attr, '') or '')
            except Exception:
                continue
            updated = current
            for old, new in replacements.items():
                if old in updated:
                    updated = updated.replace(old, new)
            if updated != current:
                try:
                    setattr(node, attr, updated)
                except Exception:
                    pass


def _normalize_textinput_behavior(root):
    for node in _walk_widgets(root):
        if not isinstance(node, TextInput):
            continue
        try:
            node.input_type = 'text'
        except Exception:
            pass
        try:
            node.keyboard_suggestions = not bool(getattr(node, 'readonly', False) or getattr(node, 'password', False))
        except Exception:
            pass
        try:
            node.input_filter = None
        except Exception:
            pass
        try:
            node.write_tab = False
        except Exception:
            pass
        try:
            node.use_bubble = True
            node.use_handles = True
        except Exception:
            pass
        try:
            node.autocapitalize = 'none'
        except Exception:
            pass


def _row_button_texts(node):
    try:
        children = list(reversed(getattr(node, 'children', []) or []))
    except Exception:
        return []
    out = []
    for child in children:
        if isinstance(child, Button):
            try:
                out.append(str(getattr(child, 'text', '') or '').strip())
            except Exception:
                out.append('')
    return out


def _cleanup_duplicate_device_tool_rows(root):
    seen = False
    for node in list(_walk_widgets(root)):
        texts = _row_button_texts(node)
        if texts == ['Paste Device Code', 'Clear Device Code']:
            if seen:
                parent = getattr(node, 'parent', None)
                if parent is not None:
                    try:
                        parent.remove_widget(node)
                    except Exception:
                        pass
            else:
                seen = True


def _postprocess_admin_ui(root):
    _retitle_budget_mentions_in_widget(root)
    _normalize_textinput_behavior(root)
    _cleanup_duplicate_device_tool_rows(root)


def make_input(hint='', multiline=False, readonly=False, password=False):
    ti = TextInput(
        hint_text=hint,
        multiline=multiline,
        readonly=readonly,
        password=password,
        size_hint_y=None,
        height=dp(48) if not multiline else dp(110),
        background_normal='',
        background_active='',
        background_color=(0.08, 0.08, 0.08, 1),
        foreground_color=(1, 1, 1, 1),
        hint_text_color=(0.7, 0.7, 0.7, 1),
        cursor_color=(1, 1, 1, 1),
        cursor_width='3sp',
        padding=[dp(12), dp(14), dp(12), dp(12)],
        input_type='text',
        keyboard_suggestions=not bool(readonly or password),
        write_tab=False,
    )
    try:
        ti.use_bubble = True
        ti.use_handles = True
    except Exception:
        pass
    try:
        ti.input_filter = None
    except Exception:
        pass
    return ti


