# ---- final fix pack v5: remove duplicate Synapse device row, default collapsed dashboard, brighter home blink dots ----
HOME_BLINK_GREEN = '#39ff14'


class HomeBlinkDot(Widget):
    def __init__(self, color_hex=HOME_BLINK_GREEN, interval=0.42, **kwargs):
        kwargs.setdefault('size_hint', (None, None))
        kwargs.setdefault('size', (dp(12), dp(12)))
        super().__init__(**kwargs)
        self._on_rgba = _hex_rgba(color_hex, 1.0)
        self._off_rgba = _hex_rgba(color_hex, 0.18)
        self._state_on = True
        with self.canvas:
            self._color = _BlinkColor(*self._on_rgba)
            self._ellipse = _BlinkEllipse(pos=self.pos, size=self.size)
        self.bind(pos=self._update_canvas, size=self._update_canvas)
        self._update_canvas()
        Clock.schedule_interval(self._blink, interval)

    def _update_canvas(self, *_):
        self._ellipse.pos = self.pos
        self._ellipse.size = self.size

    def _blink(self, *_):
        self._state_on = not self._state_on
        self._color.rgba = self._on_rgba if self._state_on else self._off_rgba


def _attach_home_card_blink(card, color_hex):
    try:
        head = None
        for child in list(getattr(card, 'children', []) or []):
            if isinstance(child, BoxLayout) and len(getattr(child, 'children', []) or []) >= 1:
                head = child
                break
        if head is None:
            return
        title_row = None
        for child in list(getattr(head, 'children', []) or []):
            if isinstance(child, BoxLayout):
                title_row = child
                break
        if title_row is None:
            return

        for child in list(getattr(title_row, 'children', []) or []):
            if isinstance(child, HomeBlinkDot):
                try:
                    title_row.remove_widget(child)
                except Exception:
                    pass

        blink = HomeBlinkDot(color_hex)
        insert_index = 1 if len(getattr(title_row, 'children', []) or []) >= 1 else 0
        title_row.add_widget(blink, index=insert_index)
        title_row._home_blink_added = True
    except Exception:
        pass


