# ---- final fix pack v7: remove accent dots on blinking cards, corner splash animation, stronger Synapse cleanup ----
try:
    from kivy.uix.floatlayout import FloatLayout
except Exception:
    FloatLayout = None


def _attach_home_card_blink(card, color_hex):
    try:
        head = None
        for child in list(getattr(card, 'children', []) or []):
            if isinstance(child, BoxLayout) and len(getattr(child, 'children', []) or []) >= 1:
                head = child
                break
        if head is None:
            return
        title_row = None
        for child in list(getattr(head, 'children', []) or []):
            if isinstance(child, BoxLayout):
                title_row = child
                break
        if title_row is None:
            return

        kept = []
        for child in list(reversed(getattr(title_row, 'children', []) or [])):
            if isinstance(child, (HomeBlinkDot, AccentDot)):
                continue
            kept.append(child)

        title_row.clear_widgets()
        blink = HomeBlinkDot(color_hex, interval=0.40)
        blink.size_hint = (None, None)
        blink.size = (dp(12), dp(12))
        title_row.add_widget(blink)
        for child in kept:
            title_row.add_widget(child)
        title_row._home_blink_added = True
    except Exception:
        pass


def _get_splash_hold_seconds():
    startup_len = 0.0
    try:
        app = App.get_running_app()
        startup_len = float(getattr(app, '_admin_last_startup_duration', 0.0) or 0.0)
        if startup_len <= 0:
            startup_path = _resolve_admin_sound_path('shv startup.wav', 'shvstartup.wav')
            if startup_path:
                probe = SoundLoader.load(startup_path)
                startup_len = float(getattr(probe, 'length', 0.0) or 0.0)
                if probe is not None:
                    try:
                        probe.unload()
                    except Exception:
                        pass
    except Exception:
        startup_len = 0.0
    return max(2.0, 0.75 + startup_len + 0.2)


def _build_corner_splash_ui(self, *_):
    self.clear_widgets()
    if FloatLayout is None:
        return

    root = FloatLayout()
    self.add_widget(root)

    w = float(Window.width or dp(360))
    h = float(Window.height or dp(720))
    center_x = w / 2.0
    center_y = h / 2.0

    def _make_part(text, font_size, color_hex, start_pos, target_pos, width_pad=dp(18), height=dp(34)):
        lbl = Label(
            text=text,
            color=get_color_from_hex(color_hex),
            bold=True,
            font_size=font_size,
            size_hint=(None, None),
            height=height,
            halign='center',
            valign='middle',
            opacity=0.0,
        )
        lbl.texture_update()
        lbl.width = max(dp(58), lbl.texture_size[0] + width_pad)
        lbl.text_size = (lbl.width, None)
        lbl.pos = start_pos
        lbl._target_pos = target_pos
        root.add_widget(lbl)
        return lbl

    row1_y = center_y + dp(28)
    row2_y = center_y - dp(6)
    row_gap = dp(10)

    # Build centered target positions from actual text widths.
    tmp1 = Label(text='SH VERTEX', font_size='16sp', bold=True, size_hint=(None, None))
    tmp1.texture_update()
    total_row1 = max(dp(180), tmp1.texture_size[0] + dp(24))
    row1_start = center_x - (total_row1 / 2.0)

    sh_probe = Label(text='SH', font_size='16sp', bold=True, size_hint=(None, None))
    sh_probe.texture_update()
    sh_w = sh_probe.texture_size[0] + dp(18)
    vertex_probe = Label(text='VERTEX', font_size='16sp', bold=True, size_hint=(None, None))
    vertex_probe.texture_update()
    vertex_w = vertex_probe.texture_size[0] + dp(18)
    row1_total = sh_w + row_gap + vertex_w
    row1_start = center_x - (row1_total / 2.0)

    admin_probe = Label(text='ADMIN', font_size='24sp', bold=True, size_hint=(None, None))
    admin_probe.texture_update()
    admin_w = admin_probe.texture_size[0] + dp(20)
    panel_probe = Label(text='PANEL', font_size='24sp', bold=True, size_hint=(None, None))
    panel_probe.texture_update()
    panel_w = panel_probe.texture_size[0] + dp(20)
    row2_total = admin_w + row_gap + panel_w
    row2_start = center_x - (row2_total / 2.0)

    self._splash_parts = [
        _make_part('SH', '16sp', UI_GREEN, (-dp(110), h - dp(90)), (row1_start, row1_y), width_pad=dp(18), height=dp(24)),
        _make_part('VERTEX', '16sp', UI_GREEN, (w + dp(20), h - dp(90)), (row1_start + sh_w + row_gap, row1_y), width_pad=dp(18), height=dp(24)),
        _make_part('ADMIN', '24sp', UI_TEXT, (-dp(180), -dp(20)), (row2_start, row2_y), width_pad=dp(22), height=dp(36)),
        _make_part('PANEL', '24sp', UI_TEXT, (w + dp(20), -dp(20)), (row2_start + admin_w + row_gap, row2_y), width_pad=dp(22), height=dp(36)),
    ]

    self.sub_lbl = Label(
        text='SH Vertex Technologies',
        color=get_color_from_hex(UI_MUTE),
        font_size='11sp',
        size_hint=(None, None),
        width=max(dp(180), w * 0.65),
        height=dp(24),
        halign='center',
        valign='middle',
        opacity=0.0,
    )
    self.sub_lbl.text_size = (self.sub_lbl.width, None)
    self.sub_lbl.pos = (center_x - self.sub_lbl.width / 2.0, center_y - dp(42))
    root.add_widget(self.sub_lbl)

    dot_row = BoxLayout(size_hint=(None, None), width=dp(110), height=dp(26), spacing=dp(10), pos=(center_x - dp(55), center_y - dp(80)))
    dot_row.add_widget(Widget())
    self._dots = []
    for _ in range(3):
        d = Label(text='•', color=(0.22, 1.0, 0.08, 1), font_size='22sp', size_hint_x=None, width=dp(22), opacity=0.0)
        self._dots.append(d)
        dot_row.add_widget(d)
    dot_row.add_widget(Widget())
    root.add_widget(dot_row)

    self._do_splash_anim()


def _corner_splash_anim(self):
    parts = getattr(self, '_splash_parts', []) or []
    delays = [0.02, 0.08, 0.14, 0.20]
    for idx, part in enumerate(parts):
        target = getattr(part, '_target_pos', tuple(part.pos))
        anim = Animation(opacity=1.0, d=0.08) & Animation(pos=target, d=0.62, t='out_cubic')
        Clock.schedule_once(lambda *_dt, a=anim, p=part: a.start(p), delays[idx] if idx < len(delays) else 0.0)

    Animation(opacity=1.0, d=0.30, t='out_quad').start(self.sub_lbl)

    for i, dot in enumerate(getattr(self, '_dots', []) or []):
        def _pulse(_dt, d=dot):
            (Animation(opacity=1.0, d=0.18) + Animation(opacity=0.30, d=0.22)).repeat = True
            ((Animation(opacity=1.0, d=0.18) + Animation(opacity=0.30, d=0.22))).start(d)
        Clock.schedule_once(_pulse, 0.78 + i * 0.15)

    Clock.schedule_once(lambda *_: setattr(self.manager, 'current', 'home'), _get_splash_hold_seconds())


# Bind helper names onto the class as real attributes before reassigning callbacks.
# Kivy's WeakMethod stores the underlying function name, so if we only set
# SplashScreen.build_ui = _build_corner_splash_ui, scheduled callbacks may later
# look for self._build_corner_splash_ui and crash. Keep both names attached.
SplashScreen._build_corner_splash_ui = _build_corner_splash_ui
SplashScreen._corner_splash_anim = _corner_splash_anim
SplashScreen.build_ui = SplashScreen._build_corner_splash_ui
SplashScreen._do_splash_anim = SplashScreen._corner_splash_anim


_prev_synapse_generate_view_v7 = LicenseManagerScreen.build_generate_view

def _synapse_generate_view_cleanup_v7(self, *args, **kwargs):
    view = _prev_synapse_generate_view_v7(self, *args, **kwargs)
    try:
        rows = []
        for node in list(_walk_widgets(view)):
            if _row_button_texts(node) == ['Paste Device Code', 'Clear Device Code']:
                rows.append(node)
        for extra in rows[1:]:
            parent = getattr(extra, 'parent', None)
            if parent is not None:
                try:
                    parent.remove_widget(extra)
                except Exception:
                    pass
        view._device_paste_controls_added = True
    except Exception:
        pass
    return view

LicenseManagerScreen.build_generate_view = _synapse_generate_view_cleanup_v7



# ---- final fix pack v7b: simplify splash dot pulse loop ----
def _corner_splash_anim(self):
    parts = getattr(self, '_splash_parts', []) or []
    delays = [0.02, 0.08, 0.14, 0.20]
    for idx, part in enumerate(parts):
        target = getattr(part, '_target_pos', tuple(part.pos))
        anim = Animation(opacity=1.0, d=0.08) & Animation(pos=target, d=0.62, t='out_cubic')
        Clock.schedule_once(lambda *_dt, a=anim, p=part: a.start(p), delays[idx] if idx < len(delays) else 0.0)

    Animation(opacity=1.0, d=0.30, t='out_quad').start(self.sub_lbl)

    for i, dot in enumerate(getattr(self, '_dots', []) or []):
        def _pulse(_dt, d=dot):
            (Animation(opacity=1.0, d=0.18) + Animation(opacity=0.30, d=0.22)).start(d)
        Clock.schedule_once(_pulse, 0.78 + i * 0.15)

    Clock.schedule_once(lambda *_: setattr(self.manager, 'current', 'home'), _get_splash_hold_seconds())

SplashScreen._corner_splash_anim = _corner_splash_anim
SplashScreen._do_splash_anim = SplashScreen._corner_splash_anim




# ── SH Vertex cloud backup + emergency vault patch ───────────────────────────
# Optional Supabase-backed cloud lane for normal app content only.
# Licensing, authority, revocation, and GitHub licensing flows remain untouched.

SUPABASE_CLOUD_CONFIG_FILE = 'supabase_cloud_config.json'
SUPABASE_CLOUD_SESSION_FILE = 'supabase_cloud_session.json'
EMERGENCY_VAULT_DB_FILE = 'emergency_vault_registry.json'
SUPABASE_CLOUD_BACKUPS_TABLE = 'shv_admin_cloud_backups'
SUPABASE_EMERGENCY_TABLE = 'shv_admin_emergency_vault'
SUPABASE_APP_CODE = 'sh_vertex_admin_panel'

# Include the new emergency vault in the existing non-licensing backup bundle.
try:
    _APP_DATA_BACKUP_FILES['emergency_vault'] = EMERGENCY_VAULT_DB_FILE
except Exception:
    pass

_SUPABASE_SQL_SETUP = """-- SH Vertex Admin Panel optional cloud tables
create extension if not exists pgcrypto;

create table if not exists public.shv_admin_cloud_backups (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references auth.users(id) on delete cascade,
  app_code text not null default 'sh_vertex_admin_panel',
  backup_name text not null,
  bundle_type text not null default 'app_data_backup',
  blob_text text not null,
  created_at timestamptz not null default now()
);

alter table public.shv_admin_cloud_backups enable row level security;

do $$ begin
  create policy "Users manage own admin backups"
  on public.shv_admin_cloud_backups
  for all
  using (auth.uid() = user_id)
  with check (auth.uid() = user_id);
exception when duplicate_object then null;
end $$;

create table if not exists public.shv_admin_emergency_vault (
  id uuid primary key,
  user_id uuid not null references auth.users(id) on delete cascade,
  category text not null default 'General',
  title text not null,
  value text not null default '',
  notes text not null default '',
  updated_at timestamptz not null default now(),
  created_at timestamptz not null default now()
);

alter table public.shv_admin_emergency_vault enable row level security;

do $$ begin
  create policy "Users manage own emergency vault rows"
  on public.shv_admin_emergency_vault
  for all
  using (auth.uid() = user_id)
  with check (auth.uid() = user_id);
exception when duplicate_object then null;
end $$;
"""


def _supabase_cloud_config_path():
    return admin_data_path(SUPABASE_CLOUD_CONFIG_FILE)


def _supabase_cloud_session_path():
    return admin_data_path(SUPABASE_CLOUD_SESSION_FILE)


def load_supabase_cloud_config():
    data = load_json(_supabase_cloud_config_path(), {})
    if not isinstance(data, dict):
        data = {}
    return {
        'url': str(data.get('url', '') or '').strip(),
        'anon_key': str(data.get('anon_key', '') or '').strip(),
        'email': str(data.get('email', '') or '').strip(),
    }


def save_supabase_cloud_config(cfg):
    clean = {
        'url': str(cfg.get('url', '') or '').strip().rstrip('/'),
        'anon_key': str(cfg.get('anon_key', '') or '').strip(),
        'email': str(cfg.get('email', '') or '').strip(),
    }
    save_json(_supabase_cloud_config_path(), clean)


def load_supabase_cloud_session():
    data = load_json(_supabase_cloud_session_path(), {})
    return data if isinstance(data, dict) else {}


def save_supabase_cloud_session(session):
    save_json(_supabase_cloud_session_path(), session or {})


def clear_supabase_cloud_session():
    save_json(_supabase_cloud_session_path(), {})


def _supabase_normalize_url(url):
    return str(url or '').strip().rstrip('/')


def _supabase_require_config(cfg):
    url = _supabase_normalize_url(cfg.get('url', ''))
    anon_key = str(cfg.get('anon_key', '') or '').strip()
    if not url or not anon_key:
        raise ValueError('Enter and save the Supabase Project URL and Anon Key first.')
    return {'url': url, 'anon_key': anon_key, 'email': str(cfg.get('email', '') or '').strip()}


def _supabase_error_text(resp):
    try:
        data = resp.json()
        if isinstance(data, dict):
            for key in ('msg', 'message', 'error_description', 'error', 'hint'):
                value = str(data.get(key, '') or '').strip()
                if value:
                    return f'{resp.status_code}: {value}'
            return f'{resp.status_code}: {json.dumps(data)[:260]}'
    except Exception:
        pass
    return f'{resp.status_code}: {resp.text[:260]}'


def _supabase_extract_session(payload):
    if not isinstance(payload, dict):
        return {}
    src = payload.get('session') if isinstance(payload.get('session'), dict) else payload
    user = payload.get('user') if isinstance(payload.get('user'), dict) else src.get('user', {}) if isinstance(src, dict) else {}
    access_token = str(src.get('access_token', '') or '').strip() if isinstance(src, dict) else ''
    refresh_token = str(src.get('refresh_token', '') or '').strip() if isinstance(src, dict) else ''
    if not access_token:
        return {}
    return {
        'access_token': access_token,
        'refresh_token': refresh_token,
        'token_type': str(src.get('token_type', 'bearer') or 'bearer').strip(),
        'expires_in': src.get('expires_in', 0),
        'expires_at': src.get('expires_at', 0),
        'user_id': str(user.get('id', '') or '').strip(),
        'email': str(user.get('email', '') or '').strip(),
        'user': user if isinstance(user, dict) else {},
        'saved_at': utc_now_iso(),
    }


def _supabase_auth_headers(cfg, token=None):
    headers = {
        'apikey': str(cfg.get('anon_key', '') or '').strip(),
        'Content-Type': 'application/json',
    }
    if token:
        headers['Authorization'] = f'Bearer {token}'
    return headers


def _supabase_auth_signup(cfg, email, password):
    cfg = _supabase_require_config(cfg)
    resp = requests.post(
        cfg['url'] + '/auth/v1/signup',
        headers=_supabase_auth_headers(cfg),
        json={'email': email, 'password': password},
        timeout=30,
    )
    if resp.status_code not in (200, 201):
        raise RuntimeError(_supabase_error_text(resp))
    return resp.json()


def _supabase_auth_login(cfg, email, password):
    cfg = _supabase_require_config(cfg)
    resp = requests.post(
        cfg['url'] + '/auth/v1/token?grant_type=password',
        headers=_supabase_auth_headers(cfg),
        json={'email': email, 'password': password},
        timeout=30,
    )
    if resp.status_code != 200:
        raise RuntimeError(_supabase_error_text(resp))
    return resp.json()


def _supabase_auth_refresh(cfg, refresh_token):
    cfg = _supabase_require_config(cfg)
    resp = requests.post(
        cfg['url'] + '/auth/v1/token?grant_type=refresh_token',
        headers=_supabase_auth_headers(cfg),
        json={'refresh_token': refresh_token},
        timeout=30,
    )
    if resp.status_code != 200:
        raise RuntimeError(_supabase_error_text(resp))
    return resp.json()


def _supabase_get_user(cfg, access_token):
    cfg = _supabase_require_config(cfg)
    resp = requests.get(
        cfg['url'] + '/auth/v1/user',
        headers=_supabase_auth_headers(cfg, access_token),
        timeout=20,
    )
    if resp.status_code != 200:
        raise RuntimeError(_supabase_error_text(resp))
    return resp.json()


def _supabase_logout(cfg, access_token):
    cfg = _supabase_require_config(cfg)
    resp = requests.post(
        cfg['url'] + '/auth/v1/logout',
        headers=_supabase_auth_headers(cfg, access_token),
        timeout=20,
    )
    if resp.status_code not in (200, 204, 401):
        raise RuntimeError(_supabase_error_text(resp))
    return True


def ensure_supabase_cloud_session(cfg, session=None):
    cfg = _supabase_require_config(cfg)
    session = session or load_supabase_cloud_session()
    access_token = str(session.get('access_token', '') or '').strip()
    refresh_token = str(session.get('refresh_token', '') or '').strip()
    if not access_token and not refresh_token:
        raise ValueError('Log in to SH Vertex Cloud first.')
    if access_token:
        try:
            user = _supabase_get_user(cfg, access_token)
            session['user'] = user
            session['user_id'] = str(user.get('id', '') or session.get('user_id', '')).strip()
            session['email'] = str(user.get('email', '') or session.get('email', '')).strip()
            save_supabase_cloud_session(session)
            return session
        except Exception:
            pass
    if refresh_token:
        payload = _supabase_auth_refresh(cfg, refresh_token)
        new_session = _supabase_extract_session(payload)
        if not new_session:
            raise RuntimeError('Could not refresh the cloud session. Please log in again.')
        save_supabase_cloud_session(new_session)
        return new_session
    raise RuntimeError('The cloud session has expired. Please log in again.')


def _supabase_rest(cfg, method, table_name, session, params=None, payload=None, prefer=None):
    cfg = _supabase_require_config(cfg)
    session = ensure_supabase_cloud_session(cfg, session)
    headers = _supabase_auth_headers(cfg, session.get('access_token', ''))
    if prefer:
        headers['Prefer'] = prefer
    resp = requests.request(
        method.upper(),
        cfg['url'] + '/rest/v1/' + table_name,
        headers=headers,
        params=params,
        json=payload,
        timeout=30,
    )
    if resp.status_code not in (200, 201, 204):
        raise RuntimeError(_supabase_error_text(resp))
    if not resp.text.strip():
        return None, session
    try:
        return resp.json(), session
    except Exception:
        return resp.text, session


def _supabase_insert_backup(cfg, session, blob_text, backup_name):
    payload = {
        'user_id': str(session.get('user_id', '') or '').strip(),
        'app_code': SUPABASE_APP_CODE,
        'backup_name': backup_name,
        'bundle_type': APP_DATA_BACKUP_BUNDLE_TYPE,
        'blob_text': blob_text,
        'created_at': utc_now_iso(),
    }
    return _supabase_rest(
        cfg,
        'POST',
        SUPABASE_CLOUD_BACKUPS_TABLE,
        session,
        payload=payload,
        prefer='return=representation',
    )


def _supabase_list_backups(cfg, session, limit=20):
    params = {
        'select': 'id,backup_name,bundle_type,created_at',
        'app_code': f'eq.{SUPABASE_APP_CODE}',
        'order': 'created_at.desc',
        'limit': str(limit),
    }
    return _supabase_rest(cfg, 'GET', SUPABASE_CLOUD_BACKUPS_TABLE, session, params=params)


def _supabase_get_backup_blob(cfg, session, backup_id):
    params = {
        'select': 'id,backup_name,blob_text,created_at',
        'id': f'eq.{backup_id}',
        'limit': '1',
    }
    data, session = _supabase_rest(cfg, 'GET', SUPABASE_CLOUD_BACKUPS_TABLE, session, params=params)
    if not data:
        raise RuntimeError('That cloud backup could not be found.')
    if isinstance(data, list):
        return (data[0] if data else {}), session
    return data, session


def emergency_vault_data_path(name):
    return admin_data_path(name)


def load_emergency_vault_db():
    data = load_json(emergency_vault_data_path(EMERGENCY_VAULT_DB_FILE), [])
    rows = data if isinstance(data, list) else []
    return [_normalize_emergency_vault_entry(x) for x in rows if isinstance(x, dict)]


def save_emergency_vault_db(items):
    rows = [_normalize_emergency_vault_entry(x) for x in (items or []) if isinstance(x, dict)]
    save_json(emergency_vault_data_path(EMERGENCY_VAULT_DB_FILE), rows)


def _normalize_emergency_vault_entry(item):
    if not isinstance(item, dict):
        item = {}
    return {
        'id': str(item.get('id') or uuid.uuid4()),
        'category': str(item.get('category', 'General') or 'General').strip() or 'General',
        'title': str(item.get('title', 'Item') or 'Item').strip() or 'Item',
        'value': str(item.get('value', '') or ''),
        'notes': str(item.get('notes', '') or ''),
        'updated_at': str(item.get('updated_at', now_local_stamp()) or now_local_stamp()),
        'created_at': str(item.get('created_at', now_local_stamp()) or now_local_stamp()),
    }


def _emergency_vault_summary():
    rows = load_emergency_vault_db()
    latest = ''
    if rows:
        latest = max((str(r.get('updated_at', '') or '') for r in rows), default='')
    return {
        'count': len(rows),
        'latest': short_time(latest) if latest else 'Never',
    }


def _supabase_push_emergency_rows(cfg, session, rows):
    payload = []
    user_id = str(session.get('user_id', '') or '').strip()
    for row in rows:
        item = _normalize_emergency_vault_entry(row)
        item['user_id'] = user_id
        payload.append(item)
    if not payload:
        return [], session
    return _supabase_rest(
        cfg,
        'POST',
        SUPABASE_EMERGENCY_TABLE,
        session,
        payload=payload,
        params={'on_conflict': 'id'},
        prefer='resolution=merge-duplicates,return=representation',
    )


def _supabase_pull_emergency_rows(cfg, session):
    params = {
        'select': 'id,category,title,value,notes,updated_at,created_at',
        'order': 'updated_at.desc',
        'limit': '500',
    }
    data, session = _supabase_rest(cfg, 'GET', SUPABASE_EMERGENCY_TABLE, session, params=params)
    rows = data if isinstance(data, list) else []
    rows = [_normalize_emergency_vault_entry(x) for x in rows if isinstance(x, dict)]
    return rows, session


class AccountsScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._cfg = load_supabase_cloud_config()
        self._session = load_supabase_cloud_session()
        Clock.schedule_once(self.build_ui, 0)

    def on_pre_enter(self, *_):
        self._cfg = load_supabase_cloud_config()
        self._session = load_supabase_cloud_session()
        Clock.schedule_once(self._refresh_runtime_state, 0)

    def build_ui(self, *_):
        self.clear_widgets()
        root = BoxLayout(orientation='vertical', padding=[dp(10), dp(12), dp(10), dp(12)], spacing=dp(10))
        root.add_widget(build_screen_header(
            'Accounts',
            'Optional SH Vertex Cloud login and encrypted cloud backup for normal app content only. Licensing stays untouched.',
            'home',
            [('Emergency Vault', 'emergency_vault')],
        ))
        scroll = ScrollView(do_scroll_x=False)
        box = BoxLayout(orientation='vertical', spacing=dp(10), size_hint_y=None)
        box.bind(minimum_height=box.setter('height'))

        cfg_card = SectionCard('SH Vertex Cloud', 'Paste your Supabase project details here. The app stores only the URL, anon key, and cloud session locally.')
        self._sb_url = make_input('Supabase Project URL')
        self._sb_anon = make_input('Supabase Anon Key')
        self._sb_email = make_input('Account email')
        self._sb_password = make_input('Account password', password=True)
        self._sb_url.text = self._cfg.get('url', '')
        self._sb_anon.text = self._cfg.get('anon_key', '')
        self._sb_email.text = self._cfg.get('email', '')
        for title, widget in (
            ('Project URL', self._sb_url),
            ('Anon Key', self._sb_anon),
            ('Email', self._sb_email),
            ('Password', self._sb_password),
        ):
            cfg_card.add_widget(make_label(title))
            cfg_card.add_widget(widget)
            if widget in (self._sb_anon, self._sb_password):
                row = BoxLayout(size_hint_y=None, height=dp(40), spacing=dp(8))
                paste_btn = make_button('Paste', UI_CYAN)
                clear_btn = make_button('Clear', RED)
                paste_btn.bind(on_release=lambda *_ , w=widget: paste_clipboard_into(w))
                clear_btn.bind(on_release=lambda *_ , w=widget: setattr(w, 'text', ''))
                row.add_widget(paste_btn)
                row.add_widget(clear_btn)
                cfg_card.add_widget(row)
        self._cloud_state_lbl = make_label('Not signed in.', color=SUBTEXT, height=dp(48))
        cfg_card.add_widget(self._cloud_state_lbl)
        row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
        save_btn = make_button('Save Cloud Settings', UI_CYAN)
        signup_btn = make_button('Create Account', GREEN)
        login_btn = make_button('Log In', UI_CYAN)
        logout_btn = make_button('Log Out', RED)
        save_btn.bind(on_release=lambda *_: self._save_cloud_settings())
        signup_btn.bind(on_release=lambda *_: self._cloud_signup())
        login_btn.bind(on_release=lambda *_: self._cloud_login())
        logout_btn.bind(on_release=lambda *_: self._cloud_logout())
        for btn in (save_btn, signup_btn, login_btn, logout_btn):
            row.add_widget(btn)
        cfg_card.add_widget(row)
        box.add_widget(cfg_card)

        backup_card = SectionCard('Cloud Backup', 'Backs up all normal app content as one encrypted snapshot. This does not touch licenses, authorities, revocations, or GitHub licensing backup lanes.')
        backup_card.add_widget(make_label('Includes: activity log, customer overrides, releases, websites, Synapse projects, emergency vault', color=SUBTEXT, height=dp(28)))
        backup_card.add_widget(make_label('Excludes: all licensing PEMs, authority backups, license lists, revocation exports', color=RED, height=dp(28)))
        backup_card.add_widget(make_label('Backup Password'))
        self._cloud_backup_password = make_input('Backup password for encrypted cloud snapshot', password=True)
        backup_card.add_widget(self._cloud_backup_password)
        actions = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
        backup_btn = make_button('Backup All to Cloud', GREEN)
        list_btn = make_button('Refresh Cloud List', UI_CYAN)
        latest_btn = make_button('Restore Latest', ORANGE)
        vault_btn = make_button('Open Emergency Vault', UI_CYAN)
        backup_btn.bind(on_release=lambda *_: self._cloud_backup_now())
        list_btn.bind(on_release=lambda *_: self._load_cloud_backups())
        latest_btn.bind(on_release=lambda *_: self._restore_latest_cloud_backup())
        vault_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'emergency_vault'))
        for btn in (backup_btn, list_btn, latest_btn, vault_btn):
            actions.add_widget(btn)
        backup_card.add_widget(actions)
        self._backup_list_box = BoxLayout(orientation='vertical', spacing=dp(8), size_hint_y=None)
        self._backup_list_box.bind(minimum_height=self._backup_list_box.setter('height'))
        backup_card.add_widget(self._backup_list_box)
        box.add_widget(backup_card)

        setup_card = SectionCard('Supabase Setup', 'Use your own Supabase project. Run the SQL once, then log in from the app. The app uses the anon key plus user auth — not a service role key.')
        setup_row = BoxLayout(size_hint_y=None, height=dp(46), spacing=dp(8))
        copy_sql_btn = make_button('Copy Setup SQL', UI_CYAN)
        copy_sql_btn.bind(on_release=lambda *_: copy_to_clipboard('Supabase setup SQL', _SUPABASE_SQL_SETUP))
        test_btn = make_button('Test Session', UI_CYAN)
        test_btn.bind(on_release=lambda *_: self._test_cloud_session())
        setup_row.add_widget(copy_sql_btn)
        setup_row.add_widget(test_btn)
        setup_card.add_widget(setup_row)
        setup_card.add_widget(make_label('Tip: if login works but backup fails, run the setup SQL and verify RLS is enabled on both tables.', color=SUBTEXT, height=dp(44)))
        box.add_widget(setup_card)

        scroll.add_widget(box)
        root.add_widget(scroll)
        self.add_widget(root)
        self._refresh_runtime_state()

    def _collect_cfg(self):
        return {
            'url': self._sb_url.text.strip(),
            'anon_key': self._sb_anon.text.strip(),
            'email': self._sb_email.text.strip(),
        }

    def _save_cloud_settings(self):
        cfg = self._collect_cfg()
        save_supabase_cloud_config(cfg)
        self._cfg = cfg
        info_popup('Saved', 'Cloud settings saved locally.')
        self._refresh_runtime_state()

    def _refresh_runtime_state(self, *_):
        if hasattr(self, '_sb_url'):
            self._sb_url.text = self._cfg.get('url', '')
            self._sb_anon.text = self._cfg.get('anon_key', '')
            if not self._sb_email.text.strip():
                self._sb_email.text = self._cfg.get('email', '')
        session = load_supabase_cloud_session()
        self._session = session
        email = str(session.get('email', '') or '').strip()
        user_id = str(session.get('user_id', '') or '').strip()
        if email:
            self._cloud_state_lbl.text = f'Signed in as: {email}\nUser ID: {user_id[:8]}...' if user_id else f'Signed in as: {email}'
            self._cloud_state_lbl.color = get_color_from_hex(GREEN)
        else:
            self._cloud_state_lbl.text = 'Not signed in. Save your Supabase URL / anon key, then create or log into your SH Vertex Cloud account.'
            self._cloud_state_lbl.color = get_color_from_hex(SUBTEXT)
        if hasattr(self, '_backup_list_box'):
            self._load_cloud_backups(silent=True)

    def _cloud_signup(self):
        email = self._sb_email.text.strip()
        password = self._sb_password.text.strip()
        if not email or not password:
            info_popup('Missing details', 'Enter your email and password first.')
            return
        cfg = self._collect_cfg()
        try:
            save_supabase_cloud_config(cfg)
            self._cfg = cfg
            payload = _supabase_auth_signup(cfg, email, password)
            session = _supabase_extract_session(payload)
            if session:
                save_supabase_cloud_session(session)
                self._session = session
                info_popup('Account created', 'Account created and signed in successfully.')
            else:
                info_popup('Account created', 'Account created. If your Supabase project requires email confirmation, verify the email first and then log in.')
            self._refresh_runtime_state()
        except Exception as e:
            info_popup('Create account failed', str(e))

    def _cloud_login(self):
        email = self._sb_email.text.strip()
        password = self._sb_password.text.strip()
        if not email or not password:
            info_popup('Missing details', 'Enter your email and password first.')
            return
        cfg = self._collect_cfg()
        try:
            payload = _supabase_auth_login(cfg, email, password)
            session = _supabase_extract_session(payload)
            if not session:
                raise RuntimeError('Login succeeded but no session token was returned.')
            save_supabase_cloud_config(cfg)
            save_supabase_cloud_session(session)
            self._cfg = cfg
            self._session = session
            info_popup('Logged in', f'Cloud login successful for {session.get("email", email)}.')
            self._refresh_runtime_state()
        except Exception as e:
            info_popup('Login failed', str(e))

    def _cloud_logout(self):
        cfg = self._collect_cfg()
        session = load_supabase_cloud_session()
        try:
            token = str(session.get('access_token', '') or '').strip()
            if token and cfg.get('url') and cfg.get('anon_key'):
                try:
                    _supabase_logout(cfg, token)
                except Exception:
                    pass
            clear_supabase_cloud_session()
            self._session = {}
            info_popup('Logged out', 'Cloud session cleared from this device.')
            self._refresh_runtime_state()
        except Exception as e:
            info_popup('Log out failed', str(e))

    def _test_cloud_session(self):
        try:
            session = ensure_supabase_cloud_session(self._collect_cfg(), load_supabase_cloud_session())
            user = session.get('user', {}) or {}
            email = str(user.get('email', '') or session.get('email', '')).strip() or 'Unknown'
            info_popup('Cloud session OK', f'Signed in as {email}. The session is valid.')
            self._refresh_runtime_state()
        except Exception as e:
            info_popup('Session test failed', str(e))

    def _cloud_backup_now(self):
        password = self._cloud_backup_password.text.strip()
        if not password:
            info_popup('Backup password required', 'Enter the backup password first.')
            return
        try:
            cfg = self._collect_cfg()
            session = ensure_supabase_cloud_session(cfg, load_supabase_cloud_session())
            blob = build_app_data_backup_blob(password)
            backup_name = 'admin_cloud_' + datetime.utcnow().strftime('%Y%m%d_%H%M%S')
            _, session = _supabase_insert_backup(cfg, session, blob, backup_name)
            save_supabase_cloud_session(session)
            log_admin_activity('System', 'Cloud backup uploaded', backup_name)
            info_popup('Cloud backup complete', f'Uploaded encrypted cloud backup:\n{backup_name}')
            self._refresh_runtime_state()
        except Exception as e:
            info_popup('Cloud backup failed', str(e))

    def _load_cloud_backups(self, silent=False):
        if not hasattr(self, '_backup_list_box'):
            return
        self._backup_list_box.clear_widgets()
        try:
            cfg = self._collect_cfg()
            session = ensure_supabase_cloud_session(cfg, load_supabase_cloud_session())
            data, session = _supabase_list_backups(cfg, session)
            save_supabase_cloud_session(session)
            rows = data if isinstance(data, list) else []
            if not rows:
                self._backup_list_box.add_widget(make_label('No cloud backups found yet.', color=SUBTEXT, height=dp(28)))
                return
            for row in rows:
                name = str(row.get('backup_name', 'Cloud Backup') or 'Cloud Backup')
                created_at = short_time(str(row.get('created_at', '') or '')) or str(row.get('created_at', '') or '--')
                card = SectionCard(name, f'Created: {created_at}')
                btn_row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
                restore_btn = make_button('Restore', ORANGE)
                copy_btn = make_button('Copy Name', UI_CYAN)
                restore_btn.bind(on_release=lambda *_ , backup_id=row.get('id', ''), backup_name=name: self._confirm_restore_cloud_backup(backup_id, backup_name))
                copy_btn.bind(on_release=lambda *_ , txt=name: copy_to_clipboard('Cloud backup name', txt))
                btn_row.add_widget(restore_btn)
                btn_row.add_widget(copy_btn)
                card.add_widget(btn_row)
                self._backup_list_box.add_widget(card)
        except Exception as e:
            if not silent:
                info_popup('Cloud list failed', str(e))
            self._backup_list_box.add_widget(make_label('Sign in to view cloud backups.', color=SUBTEXT, height=dp(28)))

    def _restore_latest_cloud_backup(self):
        try:
            cfg = self._collect_cfg()
            session = ensure_supabase_cloud_session(cfg, load_supabase_cloud_session())
            data, session = _supabase_list_backups(cfg, session, limit=1)
            save_supabase_cloud_session(session)
            rows = data if isinstance(data, list) else []
            if not rows:
                info_popup('No backups', 'There are no cloud backups to restore.')
                return
            row = rows[0]
            self._confirm_restore_cloud_backup(row.get('id', ''), row.get('backup_name', 'Latest Backup'))
        except Exception as e:
            info_popup('Restore latest failed', str(e))

    def _confirm_restore_cloud_backup(self, backup_id, backup_name):
        if not backup_id:
            info_popup('Missing backup', 'That cloud backup record is missing an ID.')
            return
        password = self._cloud_backup_password.text.strip()
        if not password:
            info_popup('Backup password required', 'Enter the backup password before restoring.')
            return
        _confirm_action_popup(
            'Restore Cloud Backup',
            f'Restore all normal app content from:\n{backup_name}\n\nLicensing, authorities, revocations, and GitHub licensing backups remain untouched.',
            'Restore', ORANGE,
            lambda: self._execute_cloud_restore(backup_id, backup_name, password),
        )

    def _execute_cloud_restore(self, backup_id, backup_name, password):
        try:
            cfg = self._collect_cfg()
            session = ensure_supabase_cloud_session(cfg, load_supabase_cloud_session())
            row, session = _supabase_get_backup_blob(cfg, session, backup_id)
            save_supabase_cloud_session(session)
            blob_text = str(row.get('blob_text', '') or '')
            restored, backed_up_at = restore_app_data_backup_blob(blob_text, password)
            log_admin_activity('System', 'Cloud backup restored', backup_name)
            info_popup('Cloud restore complete', f'Restored from {backup_name}\nOriginal backup: {backed_up_at}\nFiles: {", ".join(restored)}')
        except Exception as e:
            info_popup('Cloud restore failed', str(e))


class EmergencyVaultScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.rows = []
        Clock.schedule_once(self.build_ui, 0)

    def on_pre_enter(self, *_):
        Clock.schedule_once(self.refresh_ui, 0)

    def build_ui(self, *_):
        self.clear_widgets()
        self.scroll = ScrollView(do_scroll_x=False)
        self.root_box = BoxLayout(orientation='vertical', padding=[dp(10), dp(12), dp(10), dp(18)], spacing=dp(10), size_hint_y=None)
        self.root_box.bind(minimum_height=self.root_box.setter('height'))
        self.scroll.add_widget(self.root_box)
        self.add_widget(self.scroll)
        self.refresh_ui()

    def refresh_ui(self, *_):
        self.rows = load_emergency_vault_db()
        self.root_box.clear_widgets()
        self.root_box.add_widget(build_screen_header(
            'Emergency Vault',
            'Store critical URLs, repos, IDs, endpoints, and notes in one emergency-ready module. Optional cloud sync is tied to the Accounts screen.',
            'accounts',
            [('Accounts', 'accounts')],
        ))
        summary = _emergency_vault_summary()
        top = SectionCard('Vault Actions', 'Keep only the critical things you may need fast in an emergency.')
        stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(72))
        stats.add_widget(build_stat_chip(summary['count'], 'Items', UI_CYAN))
        stats.add_widget(build_stat_chip(summary['latest'], 'Updated', GREEN))
        top.add_widget(stats)
        actions = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
        add_btn = make_button('Add Item', GREEN)
        push_btn = make_button('Push to Cloud', UI_CYAN)
        pull_btn = make_button('Pull from Cloud', ORANGE)
        home_btn = make_button('Back Home', UI_CYAN)
        add_btn.bind(on_release=lambda *_: self.open_editor())
        push_btn.bind(on_release=lambda *_: self.push_to_cloud())
        pull_btn.bind(on_release=lambda *_: self.pull_from_cloud())
        home_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'home'))
        for btn in (add_btn, push_btn, pull_btn, home_btn):
            actions.add_widget(btn)
        top.add_widget(actions)
        self.root_box.add_widget(top)

        if not self.rows:
            self.root_box.add_widget(SectionCard('No emergency items yet', 'Add your first critical URL, repo, ID, or note here.'))
            return

        for row in self.rows:
            card = SectionCard(row.get('title', 'Item'), row.get('category', 'General'))
            value = str(row.get('value', '') or '')
            notes = str(row.get('notes', '') or '')
            if value:
                card.add_widget(make_label(value[:200] + ('...' if len(value) > 200 else ''), color=SUBTEXT, height=dp(42)))
            if notes:
                card.add_widget(make_label(notes[:180] + ('...' if len(notes) > 180 else ''), color=SUBTEXT, height=dp(42)))
            card.add_widget(make_label(f'Updated: {row.get("updated_at", "--")}', color=SUBTEXT, height=dp(22)))
            btn_row = GridLayout(cols=4, spacing=dp(8), size_hint_y=None, height=dp(42))
            edit_btn = make_button('Edit', UI_CYAN)
            copy_btn = make_button('Copy', UI_CYAN)
            del_btn = make_button('Delete', RED)
            open_btn = make_button('Open URL', GREEN)
            edit_btn.bind(on_release=lambda *_ , rid=row.get('id', ''): self.open_editor(rid))
            copy_btn.bind(on_release=lambda *_ , txt=(str(row.get('title', '')) + '\n' + str(row.get('value', '')) + ('\n' + str(row.get('notes', '')) if row.get('notes') else '')): copy_to_clipboard('Emergency vault item', txt))
            del_btn.bind(on_release=lambda *_ , rid=row.get('id', ''): self.confirm_delete(rid))
            if value and str(value).strip().lower().startswith(('http://', 'https://')):
                open_btn.bind(on_release=lambda *_ , txt=value: copy_to_clipboard('URL', txt))
            else:
                open_btn.text = 'Copy Value'
                open_btn.bind(on_release=lambda *_ , txt=value: copy_to_clipboard('Emergency vault value', txt))
            for btn in (edit_btn, copy_btn, del_btn, open_btn):
                btn_row.add_widget(btn)
            card.add_widget(btn_row)
            self.root_box.add_widget(card)

    def _find_row(self, row_id):
        for row in self.rows:
            if row.get('id') == row_id:
                return row
        return None

    def _save_rows(self):
        save_emergency_vault_db(self.rows)

    def open_editor(self, row_id=None):
        row = _normalize_emergency_vault_entry(self._find_row(row_id) or {})
        is_new = not bool(row_id)
        content = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(10))
        category = Spinner(text=row.get('category', 'General') or 'General', values=('General', 'Project', 'URL', 'Repo', 'Endpoint', 'Server', 'Credential Hint', 'Note'), size_hint_y=None, height=dp(46))
        title_in = make_input('Title'); title_in.text = row.get('title', '')
        value_in = make_input('Value / URL / repo / ID', multiline=True); value_in.text = row.get('value', ''); value_in.height = dp(90)
        notes_in = make_input('Notes', multiline=True); notes_in.text = row.get('notes', ''); notes_in.height = dp(90)
        for title, widget in (('Category', category), ('Title', title_in), ('Value', value_in), ('Notes', notes_in)):
            content.add_widget(make_label(title))
            content.add_widget(widget)
        btn_row = BoxLayout(size_hint_y=None, height=dp(46), spacing=dp(8))
        save_btn = make_button('Save Item', GREEN)
        cancel_btn = make_button('Cancel', UI_CYAN)
        btn_row.add_widget(save_btn)
        btn_row.add_widget(cancel_btn)
        content.add_widget(btn_row)
        popup = Popup(title='Add Emergency Item' if is_new else 'Edit Emergency Item', content=content, size_hint=(0.92, 0.88), background_color=get_color_from_hex(CARD))
        cancel_btn.bind(on_release=popup.dismiss)

        def do_save(*_):
            title = title_in.text.strip()
            if not title:
                info_popup('Title required', 'Enter a title for this emergency item.')
                return
            updated = _normalize_emergency_vault_entry(row)
            updated['category'] = category.text.strip() or 'General'
            updated['title'] = title
            updated['value'] = value_in.text.strip()
            updated['notes'] = notes_in.text.strip()
            updated['updated_at'] = now_local_stamp()
            if is_new:
                self.rows.insert(0, updated)
            else:
                for idx, existing in enumerate(self.rows):
                    if existing.get('id') == updated.get('id'):
                        updated['created_at'] = existing.get('created_at', updated.get('created_at', now_local_stamp()))
                        self.rows[idx] = updated
                        break
            self._save_rows()
            log_admin_activity('Emergency Vault', 'Item saved', updated['title'])
            popup.dismiss()
            self.refresh_ui()
        save_btn.bind(on_release=do_save)
        popup.open()

    def confirm_delete(self, row_id):
        row = self._find_row(row_id)
        if not row:
            info_popup('Missing item', 'That emergency item no longer exists.')
            return
        _confirm_action_popup(
            'Delete Emergency Item',
            f'Delete {row.get("title", "this item")} from the emergency vault?',
            'Delete', RED,
            lambda: self._delete_row(row_id),
        )

    def _delete_row(self, row_id):
        row = self._find_row(row_id)
        self.rows = [x for x in self.rows if x.get('id') != row_id]
        self._save_rows()
        if row:
            log_admin_activity('Emergency Vault', 'Item deleted', row.get('title', 'Item'))
        self.refresh_ui()

    def push_to_cloud(self):
        if not self.rows:
            info_popup('Nothing to sync', 'There are no emergency vault items to push.')
            return
        try:
            cfg = load_supabase_cloud_config()
            session = ensure_supabase_cloud_session(cfg, load_supabase_cloud_session())
            _, session = _supabase_push_emergency_rows(cfg, session, self.rows)
            save_supabase_cloud_session(session)
            log_admin_activity('Emergency Vault', 'Pushed to cloud', str(len(self.rows)))
            info_popup('Cloud sync complete', f'Pushed {len(self.rows)} emergency vault item(s) to the cloud.')
        except Exception as e:
            info_popup('Push failed', str(e))

    def pull_from_cloud(self):
        try:
            cfg = load_supabase_cloud_config()
            session = ensure_supabase_cloud_session(cfg, load_supabase_cloud_session())
            rows, session = _supabase_pull_emergency_rows(cfg, session)
            save_supabase_cloud_session(session)
            if not rows:
                info_popup('No cloud items', 'No emergency vault items were found in the cloud.')
                return
            _confirm_action_popup(
                'Replace Local Emergency Vault',
                f'Replace local emergency vault items with {len(rows)} cloud item(s)?',
                'Replace', ORANGE,
                lambda rows=rows: self._finish_cloud_pull(rows),
            )
        except Exception as e:
            info_popup('Pull failed', str(e))

    def _finish_cloud_pull(self, rows):
        self.rows = [_normalize_emergency_vault_entry(x) for x in rows]
        self._save_rows()
        log_admin_activity('Emergency Vault', 'Pulled from cloud', str(len(rows)))
        info_popup('Cloud pull complete', f'Restored {len(rows)} emergency vault item(s) from the cloud.')
        self.refresh_ui()


