def _home_card_title_text(card):
    try:
        for child in list(getattr(card, 'children', []) or []):
            if isinstance(child, BoxLayout):
                for sub in list(getattr(child, 'children', []) or []):
                    if isinstance(sub, BoxLayout):
                        for item in list(reversed(getattr(sub, 'children', []) or [])):
                            if isinstance(item, Label):
                                return str(getattr(item, 'text', '') or '').strip()
    except Exception:
        pass
    return ''


