# ---- real anti-flicker pass: based on the current cloud fix3 file ----
# This patch keeps the minimal look, keeps the left-side blinking lights,
# preserves the Exit card at the bottom, and reduces shimmer on Android by:
# - disabling the idle title opacity pulse
# - disabling home child fade-ins
# - disabling product dashboard crossfade
# - reducing repeated postprocess scheduling to one deduped pass
# - replacing line-based borders with filled rounded layers on buttons/cards/chips
# - snapping canvas geometry to whole pixels

def _snap_px(value):
    try:
        return float(int(round(float(value))))
    except Exception:
        try:
            return float(value or 0)
        except Exception:
            return 0.0


def _snap_rect(pos, size):
    x, y = pos
    w, h = size
    return (_snap_px(x), _snap_px(y)), (max(0.0, _snap_px(w)), max(0.0, _snap_px(h)))


class RoundedButton(Button):
    def __init__(self, bg_hex=UI_GREEN, text_color=None, radius=16, border_hex=None, **kwargs):
        kwargs.setdefault('background_normal', '')
        kwargs.setdefault('background_down', '')
        kwargs.setdefault('background_color', (0, 0, 0, 0))
        kwargs.setdefault('color', get_color_from_hex(UI_TEXT))
        kwargs.setdefault('font_size', '13sp')
        kwargs.setdefault('bold', True)
        kwargs.setdefault('size_hint_y', None)
        kwargs.setdefault('height', dp(44))
        kwargs.setdefault('halign', 'center')
        kwargs.setdefault('valign', 'middle')
        super().__init__(**kwargs)
        self._bg_hex = str(bg_hex or UI_GREEN)
        self._fill_hex = _button_fill_for(self._bg_hex)
        self._border_hex = border_hex or self._derive_neon_border(self._bg_hex)
        self._radius = dp(radius)
        self._inset = max(1.0, float(dp(1)))
        if text_color is not None:
            self.color = text_color
        self.bind(size=lambda inst, val: setattr(inst, 'text_size', (max(0, val[0] - dp(10)), max(0, val[1] - dp(4)))))
        with self.canvas.before:
            self._border_color_instr = Color(*_hex_rgba(self._border_hex, 0.92))
            self._border_bg = RoundedRectangle(pos=self.pos, size=self.size, radius=[self._radius])
            self._fill_color_instr = Color(*_hex_rgba(self._fill_hex, 1.0))
            self._fill_bg = RoundedRectangle(pos=self.pos, size=self.size, radius=[max(dp(4), self._radius - self._inset)])
        self.bind(pos=self._update_bg, size=self._update_bg, state=self._update_bg, disabled=self._update_bg)
        self._update_bg()

    def _derive_neon_border(self, bg_hex):
        return _button_border_for(bg_hex)

    def _update_bg(self, *_):
        self._fill_hex = _button_fill_for(self._bg_hex)
        self._border_hex = self._derive_neon_border(self._bg_hex)
        pressed = (self.state == 'down')
        fill_rgba = _mix_hex(self._fill_hex, self._bg_hex, 0.14 if pressed else 0.05)
        pos, size = _snap_rect(self.pos, self.size)
        self._border_bg.pos = pos
        self._border_bg.size = size
        self._border_bg.radius = [self._radius]
        inner_pos = (pos[0] + self._inset, pos[1] + self._inset)
        inner_size = (max(0.0, size[0] - self._inset * 2), max(0.0, size[1] - self._inset * 2))
        self._fill_bg.pos = inner_pos
        self._fill_bg.size = inner_size
        self._fill_bg.radius = [max(dp(4), self._radius - self._inset)]
        self._border_color_instr.rgba = _hex_rgba(self._border_hex, 0.55 if self.disabled else 0.88)
        self._fill_color_instr.rgba = _hex_rgba(UI_SOFT, 0.94) if self.disabled else fill_rgba
        self.opacity = 1.0


class SectionCard(BoxLayout):
    def __init__(self, title, subtitle='', accent=None, **kwargs):
        kwargs.setdefault('orientation', 'vertical')
        kwargs.setdefault('spacing', dp(8))
        kwargs.setdefault('padding', [dp(12), dp(12), dp(12), dp(12)])
        kwargs.setdefault('size_hint_y', None)
        super().__init__(**kwargs)
        self.bind(minimum_height=self.setter('height'))
        self._accent = accent or _section_accent(title)
        self._radius = dp(18)
        self._inset = max(1.0, float(dp(1)))
        with self.canvas.before:
            self._border_color_instr = Color(*_hex_rgba(UI_LINE, 0.78))
            self._border_bg = RoundedRectangle(pos=self.pos, size=self.size, radius=[self._radius])
            self._bg_color_instr = Color(*_hex_rgba(UI_CARD, 1.0))
            self._bg = RoundedRectangle(pos=self.pos, size=self.size, radius=[max(dp(6), self._radius - self._inset)])
        self.bind(pos=self._update_bg, size=self._update_bg)
        self._update_bg()

        head = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(2))
        head.bind(minimum_height=head.setter('height'))
        title_row = BoxLayout(size_hint_y=None, height=dp(24), spacing=dp(6))
        dot = AccentDot(self._accent, dp(8))
        dot.pos_hint = {'center_y': 0.5}
        title_row.add_widget(dot)
        title_lbl = Label(text=str(title or ''), color=get_color_from_hex(UI_TEXT), bold=True, font_size='17sp', size_hint_y=None, height=dp(24), halign='left', valign='middle')
        title_lbl.bind(size=lambda inst, val: setattr(inst, 'text_size', val))
        title_row.add_widget(title_lbl)
        head.add_widget(title_row)
        short_sub = _shorten_subtitle(subtitle, 96)
        if short_sub:
            sub_lbl = Label(text=short_sub, color=get_color_from_hex(UI_MUTE), font_size='11sp', size_hint_y=None, halign='left', valign='middle')
            sub_lbl.bind(size=lambda inst, val: setattr(inst, 'text_size', (val[0], None)))
            sub_lbl.bind(texture_size=lambda inst, val: setattr(inst, 'height', max(dp(16), val[1])))
            head.add_widget(sub_lbl)
        self.add_widget(head)

    def _update_bg(self, *_):
        pos, size = _snap_rect(self.pos, self.size)
        self._border_bg.pos = pos
        self._border_bg.size = size
        self._border_bg.radius = [self._radius]
        inner_pos = (pos[0] + self._inset, pos[1] + self._inset)
        inner_size = (max(0.0, size[0] - self._inset * 2), max(0.0, size[1] - self._inset * 2))
        self._bg.pos = inner_pos
        self._bg.size = inner_size
        self._bg.radius = [max(dp(6), self._radius - self._inset)]


def make_button(text, color=UI_GREEN):
    return RoundedButton(text=text, size_hint_y=None, height=dp(44), bg_hex=color, text_color=get_color_from_hex(UI_TEXT), radius=16)


def make_nav_button(text):
    return RoundedButton(text=text, size_hint=(1, None), height=dp(40), bg_hex=UI_CYAN, text_color=get_color_from_hex(UI_TEXT), radius=16)


def build_stat_chip(value, label, accent=UI_GREEN):
    card = BoxLayout(orientation='vertical', size_hint_y=None, height=dp(58), padding=[dp(10), dp(8), dp(10), dp(7)], spacing=dp(1))
    radius = dp(14)
    inset = max(1.0, float(dp(1)))
    with card.canvas.before:
        card._border_c = Color(*_hex_rgba(_button_border_for(accent), 0.78))
        card._border_bg = RoundedRectangle(pos=card.pos, size=card.size, radius=[radius])
        card._bg_c = Color(*_hex_rgba(UI_CARD_2, 1.0))
        card._bg = RoundedRectangle(pos=card.pos, size=card.size, radius=[max(dp(4), radius - inset)])
        card._bar_c = Color(*_hex_rgba(_button_border_for(accent), 0.92))
        card._bar = RoundedRectangle(pos=card.pos, size=(card.width, dp(3)), radius=[radius])
    def _upd(*_):
        pos, size = _snap_rect(card.pos, card.size)
        card._border_bg.pos = pos
        card._border_bg.size = size
        inner_pos = (pos[0] + inset, pos[1] + inset)
        inner_size = (max(0.0, size[0] - inset * 2), max(0.0, size[1] - inset * 2))
        card._bg.pos = inner_pos
        card._bg.size = inner_size
        card._bar.pos = inner_pos
        card._bar.size = (inner_size[0], dp(3))
    card.bind(pos=_upd, size=_upd)
    _upd()
    v = Label(text=str(value), color=get_color_from_hex(UI_TEXT), bold=True, font_size='16sp', size_hint_y=None, height=dp(22), halign='left', valign='middle')
    v.bind(size=lambda inst, val: setattr(inst, 'text_size', val))
    l = Label(text=str(label).upper(), color=get_color_from_hex(UI_MUTE), font_size='9sp', size_hint_y=None, height=dp(14), halign='left', valign='middle', bold=True)
    l.bind(size=lambda inst, val: setattr(inst, 'text_size', val))
    card.add_widget(v)
    card.add_widget(l)
    return card


