def _attach_home_card_blink(card, color_hex):
    try:
        head = None
        for child in list(getattr(card, 'children', []) or []):
            if isinstance(child, BoxLayout) and len(getattr(child, 'children', []) or []) >= 1:
                head = child
                break
        if head is None:
            return
        title_row = None
        for child in list(getattr(head, 'children', []) or []):
            if isinstance(child, BoxLayout):
                title_row = child
                break
        if title_row is None:
            return

        kept = []
        for child in list(reversed(getattr(title_row, 'children', []) or [])):
            if isinstance(child, (HomeBlinkDot, AccentDot)):
                continue
            kept.append(child)

        title_row.clear_widgets()
        blink = HomeBlinkDot(color_hex, interval=0.42)
        blink.size_hint = (None, None)
        blink.size = (dp(12), dp(12))
        title_row.add_widget(blink)
        for child in kept:
            title_row.add_widget(child)
        title_row._home_blink_added = True
    except Exception:
        pass


def _schedule_postprocess_once(target, delay=0.03):
    if target is None:
        return
    try:
        if getattr(target, '_shv_postprocess_scheduled', False):
            return
        target._shv_postprocess_scheduled = True
    except Exception:
        pass

    def _run(*_):
        try:
            _postprocess_admin_ui(target)
        except Exception:
            pass
        try:
            target._shv_postprocess_scheduled = False
        except Exception:
            pass

    Clock.schedule_once(_run, delay)


