# ---- admin users view + home accounts/music order patch ----
SHV_ADMIN_EMAIL = 'ceo.shvertex@gmail.com'
SHV_ADMIN_UUID = '9803254b-861a-4dba-b134-a558fd9229ba'
SUPABASE_ADMIN_USERS_FUNCTION = 'shv-admin-users'

_SUPABASE_ADMIN_USERS_FUNCTION_TS = f"""import {{ createClient }} from 'https://esm.sh/@supabase/supabase-js@2'\n\nconst corsHeaders = {{\n  'Access-Control-Allow-Origin': '*',\n  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',\n}}\n\nconst ADMIN_UUID = '{SHV_ADMIN_UUID}'\nconst ADMIN_EMAIL = '{SHV_ADMIN_EMAIL}'\n\nDeno.serve(async (req) => {{\n  if (req.method === 'OPTIONS') {{\n    return new Response('ok', {{ headers: corsHeaders }})\n  }}\n\n  const supabaseUrl = Deno.env.get('SUPABASE_URL') ?? ''\n  const anonKey = Deno.env.get('SUPABASE_ANON_KEY') ?? ''\n  const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''\n\n  if (!supabaseUrl || !anonKey || !serviceRoleKey) {{\n    return new Response(JSON.stringify({{ error: 'Missing Edge Function secrets.' }}), {{\n      status: 500,\n      headers: {{ ...corsHeaders, 'Content-Type': 'application/json' }},\n    }})\n  }}\n\n  const authHeader = req.headers.get('Authorization') ?? ''\n  if (!authHeader) {{\n    return new Response(JSON.stringify({{ error: 'Missing Authorization header.' }}), {{\n      status: 401,\n      headers: {{ ...corsHeaders, 'Content-Type': 'application/json' }},\n    }})\n  }}\n\n  const userClient = createClient(supabaseUrl, anonKey, {{\n    global: {{ headers: {{ Authorization: authHeader }} }},\n  }})\n  const adminClient = createClient(supabaseUrl, serviceRoleKey)\n\n  const {{ data: userData, error: userError }} = await userClient.auth.getUser()\n  if (userError || !userData?.user) {{\n    return new Response(JSON.stringify({{ error: userError?.message || 'Not authenticated.' }}), {{\n      status: 401,\n      headers: {{ ...corsHeaders, 'Content-Type': 'application/json' }},\n    }})\n  }}\n\n  const currentUser = userData.user\n  const currentEmail = String(currentUser.email || '').toLowerCase()\n  if (currentUser.id !== ADMIN_UUID && currentEmail !== ADMIN_EMAIL.toLowerCase()) {{\n    return new Response(JSON.stringify({{ error: 'Admin access required.' }}), {{\n      status: 403,\n      headers: {{ ...corsHeaders, 'Content-Type': 'application/json' }},\n    }})\n  }}\n\n  let page = 1\n  const perPage = 200\n  const users = []\n  while (true) {{\n    const {{ data, error }} = await adminClient.auth.admin.listUsers({{ page, perPage }})\n    if (error) {{\n      return new Response(JSON.stringify({{ error: error.message }}), {{\n        status: 500,\n        headers: {{ ...corsHeaders, 'Content-Type': 'application/json' }},\n      }})\n    }}\n    const pageUsers = data?.users ?? []\n    for (const u of pageUsers) {{\n      users.push({{\n        id: u.id,\n        email: u.email ?? '',\n        phone: u.phone ?? '',\n        created_at: u.created_at ?? '',\n        last_sign_in_at: u.last_sign_in_at ?? '',\n        email_confirmed_at: u.email_confirmed_at ?? '',\n        phone_confirmed_at: u.phone_confirmed_at ?? '',\n        banned_until: u.banned_until ?? '',\n        role: u.role ?? '',\n        aud: u.aud ?? '',\n        is_anonymous: Boolean(u.is_anonymous),\n        user_metadata: u.user_metadata ?? {{}},\n        app_metadata: u.app_metadata ?? {{}},\n      }})\n    }}\n    if (pageUsers.length < perPage) break\n    page += 1\n  }}\n\n  return new Response(JSON.stringify({{ ok: true, count: users.length, users }}), {{\n    headers: {{ ...corsHeaders, 'Content-Type': 'application/json' }},\n  }})\n}})\n"""


def _is_shv_admin_session(session):
    session = session or {}
    uid = str(session.get('user_id', '') or '').strip().lower()
    email = str(session.get('email', '') or '').strip().lower()
    return uid == SHV_ADMIN_UUID.lower() or email == SHV_ADMIN_EMAIL.lower()


def _supabase_call_admin_users_function(cfg, session, function_name=SUPABASE_ADMIN_USERS_FUNCTION):
    cfg = _supabase_require_config(cfg)
    session = ensure_supabase_cloud_session(cfg, session)
    headers = _supabase_auth_headers(cfg, session.get('access_token', ''))
    resp = requests.post(
        cfg['url'] + '/functions/v1/' + str(function_name or SUPABASE_ADMIN_USERS_FUNCTION).strip(),
        headers=headers,
        json={},
        timeout=45,
    )
    if resp.status_code not in (200, 201):
        raise RuntimeError(_supabase_error_text(resp))
    try:
        data = resp.json()
    except Exception:
        raise RuntimeError('Admin users function returned invalid JSON.')
    if isinstance(data, dict) and isinstance(data.get('users'), list):
        return data.get('users') or [], session
    if isinstance(data, list):
        return data, session
    raise RuntimeError('Admin users function did not return a users list.')


def _admin_user_summary(users):
    total = len(users or [])
    confirmed = 0
    recent = ''
    for item in users or []:
        if str(item.get('email_confirmed_at', '') or '').strip():
            confirmed += 1
        stamp = str(item.get('last_sign_in_at', '') or item.get('created_at', '') or '').strip()
        if stamp and stamp > recent:
            recent = stamp
    return {
        'total': total,
        'confirmed': confirmed,
        'recent': short_time(recent) if recent else 'Never',
    }


class CloudUsersScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.rows = []
        Clock.schedule_once(self.build_ui, 0)

    def on_pre_enter(self, *_):
        Clock.schedule_once(self.refresh_ui, 0)

    def build_ui(self, *_):
        self.clear_widgets()
        self.scroll = ScrollView(do_scroll_x=False)
        self.root_box = BoxLayout(orientation='vertical', padding=[dp(10), dp(12), dp(10), dp(18)], spacing=dp(10), size_hint_y=None)
        self.root_box.bind(minimum_height=self.root_box.setter('height'))
        self.scroll.add_widget(self.root_box)
        self.add_widget(self.scroll)
        self.refresh_ui()

    def refresh_ui(self, *_):
        self.root_box.clear_widgets()
        self.root_box.add_widget(build_screen_header(
            'SH Vertex Users',
            'Admin-only view of SH Vertex accounts created through Supabase Auth.',
            'accounts',
            [('Accounts', 'accounts')],
        ))
        session = load_supabase_cloud_session()
        admin_ok = _is_shv_admin_session(session)
        email = str(session.get('email', '') or '').strip() or 'Offline'

        summary_card = SectionCard('Admin Access', 'This screen works only for the SH Vertex admin account and requires the Edge Function below to be deployed.', accent=UI_CYAN)
        stats = GridLayout(cols=3, spacing=dp(8), size_hint_y=None, height=dp(72))
        stats.add_widget(build_stat_chip('YES' if admin_ok else 'NO', 'Admin', GREEN if admin_ok else UI_RED))
        stats.add_widget(build_stat_chip(email[:18], 'Signed In', UI_CYAN if admin_ok else UI_ORANGE))
        stats.add_widget(build_stat_chip(str(len(self.rows)), 'Loaded', UI_PURPLE))
        summary_card.add_widget(stats)
        self.root_box.add_widget(summary_card)

        actions_card = SectionCard('Admin User Tools', 'Deploy the Supabase Edge Function once, then refresh the user list here.', accent=UI_PURPLE)
        action_grid = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
        refresh_btn = make_button('Refresh Users', UI_CYAN)
        copy_code_btn = make_button('Copy Function Code', GREEN)
        copy_name_btn = make_button('Copy Function Name', UI_CYAN)
        back_btn = make_button('Back Accounts', UI_ORANGE)
        refresh_btn.bind(on_release=lambda *_: self.load_users())
        copy_code_btn.bind(on_release=lambda *_: copy_to_clipboard('Supabase admin users function', _SUPABASE_ADMIN_USERS_FUNCTION_TS))
        copy_name_btn.bind(on_release=lambda *_: copy_to_clipboard('Function name', SUPABASE_ADMIN_USERS_FUNCTION))
        back_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'accounts'))
        for btn in (refresh_btn, copy_code_btn, copy_name_btn, back_btn):
            action_grid.add_widget(btn)
        actions_card.add_widget(action_grid)
        actions_card.add_widget(make_label('Required secret in Supabase Edge Functions: SUPABASE_SERVICE_ROLE_KEY', color=SUBTEXT, height=dp(28)))
        self.root_box.add_widget(actions_card)

        if not admin_ok:
            warn = SectionCard('Access Needed', 'Sign in using the SH Vertex admin cloud account before loading the full user list.', accent=UI_RED)
            warn.add_widget(make_label('Allowed admin email: ' + SHV_ADMIN_EMAIL, color=SUBTEXT, height=dp(24)))
            warn.add_widget(make_label('Allowed admin UUID: ' + SHV_ADMIN_UUID, color=SUBTEXT, height=dp(24)))
            self.root_box.add_widget(warn)
            return

        if not self.rows:
            hint = SectionCard('User List', 'Tap Refresh Users after you deploy the function. If the function is already live, the accounts will appear here.', accent=UI_CYAN)
            hint.add_widget(make_label('Nothing loaded yet.', color=SUBTEXT, height=dp(24)))
            self.root_box.add_widget(hint)
            return

        summary = _admin_user_summary(self.rows)
        list_card = SectionCard('Accounts Summary', 'All available account details returned by the admin function are visible here.', accent=GREEN)
        list_stats = GridLayout(cols=3, spacing=dp(8), size_hint_y=None, height=dp(72))
        list_stats.add_widget(build_stat_chip(summary['total'], 'Users', UI_CYAN))
        list_stats.add_widget(build_stat_chip(summary['confirmed'], 'Confirmed', GREEN))
        list_stats.add_widget(build_stat_chip(summary['recent'], 'Recent', UI_ORANGE))
        list_card.add_widget(list_stats)
        self.root_box.add_widget(list_card)

        for user in self.rows:
            email_txt = str(user.get('email', '') or '').strip() or 'No email'
            created_at = short_time(str(user.get('created_at', '') or '')) or '--'
            last_seen = short_time(str(user.get('last_sign_in_at', '') or '')) or 'Never'
            uid = str(user.get('id', '') or '').strip()
            confirmed = 'Confirmed' if str(user.get('email_confirmed_at', '') or '').strip() else 'Unconfirmed'
            subtitle = f'Created: {created_at}  •  Last sign-in: {last_seen}  •  {confirmed}'
            card = SectionCard(email_txt, subtitle, accent=UI_CYAN if confirmed == 'Confirmed' else UI_ORANGE)
            card.add_widget(make_label('UID: ' + (uid[:8] + '...' if uid else '--'), color=SUBTEXT, height=dp(22)))
            phone = str(user.get('phone', '') or '').strip()
            if phone:
                card.add_widget(make_label('Phone: ' + phone, color=SUBTEXT, height=dp(22)))
            row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
            details_btn = make_button('Details', UI_CYAN)
            copy_email_btn = make_button('Copy Email', UI_CYAN)
            copy_uid_btn = make_button('Copy UID', UI_ORANGE)
            details_btn.bind(on_release=lambda *_ , item=user: self.show_user_details(item))
            copy_email_btn.bind(on_release=lambda *_ , txt=email_txt: copy_to_clipboard('User email', txt))
            copy_uid_btn.bind(on_release=lambda *_ , txt=uid: copy_to_clipboard('User UID', txt))
            row.add_widget(details_btn)
            row.add_widget(copy_email_btn)
            row.add_widget(copy_uid_btn)
            card.add_widget(row)
            self.root_box.add_widget(card)

    def load_users(self):
        try:
            cfg = load_supabase_cloud_config()
            session = ensure_supabase_cloud_session(cfg, load_supabase_cloud_session())
            if not _is_shv_admin_session(session):
                raise RuntimeError('Sign in with the SH Vertex admin account first.')
            rows, session = _supabase_call_admin_users_function(cfg, session)
            save_supabase_cloud_session(session)
            self.rows = rows if isinstance(rows, list) else []
            self.refresh_ui()
            info_popup('Users loaded', f'Loaded {len(self.rows)} SH Vertex account(s).')
        except Exception as e:
            info_popup('Load users failed', str(e))

    def show_user_details(self, user):
        meta = {
            'id': str(user.get('id', '') or ''),
            'email': str(user.get('email', '') or ''),
            'phone': str(user.get('phone', '') or ''),
            'created_at': str(user.get('created_at', '') or ''),
            'last_sign_in_at': str(user.get('last_sign_in_at', '') or ''),
            'email_confirmed_at': str(user.get('email_confirmed_at', '') or ''),
            'phone_confirmed_at': str(user.get('phone_confirmed_at', '') or ''),
            'banned_until': str(user.get('banned_until', '') or ''),
            'role': str(user.get('role', '') or ''),
            'aud': str(user.get('aud', '') or ''),
            'is_anonymous': bool(user.get('is_anonymous', False)),
            'user_metadata': user.get('user_metadata', {}) if isinstance(user.get('user_metadata', {}), dict) else user.get('user_metadata'),
            'app_metadata': user.get('app_metadata', {}) if isinstance(user.get('app_metadata', {}), dict) else user.get('app_metadata'),
        }
        pretty = json.dumps(meta, indent=2, ensure_ascii=False)
        content = BoxLayout(orientation='vertical', padding=dp(12), spacing=dp(10))
        body = make_input('', multiline=True, readonly=True)
        body.height = dp(320)
        body.text = pretty
        content.add_widget(body)
        row = BoxLayout(size_hint_y=None, height=dp(46), spacing=dp(8))
        copy_btn = make_button('Copy Details', UI_CYAN)
        close_btn = make_button('Close', UI_RED)
        row.add_widget(copy_btn)
        row.add_widget(close_btn)
        content.add_widget(row)
        popup = Popup(title='User Details', content=content, size_hint=(0.94, 0.82), separator_color=get_color_from_hex(UI_CYAN), background_color=get_color_from_hex(UI_CARD))
        copy_btn.bind(on_release=lambda *_: copy_to_clipboard('User details', pretty))
        close_btn.bind(on_release=popup.dismiss)
        popup.open()


