def _accounts_build_ui_with_admin_tools(self, *a, **kw):
    _prev_accounts_build_ui_admin(self, *a, **kw)
    try:
        outer = self.children[0] if self.children else None
        content_root = None
        if isinstance(outer, BoxLayout):
            for child in list(reversed(getattr(outer, 'children', []) or [])):
                if isinstance(child, BoxLayout):
                    content_root = child
                    break
        if content_root is None:
            return
        scroll = None
        for child in list(reversed(getattr(content_root, 'children', []) or [])):
            if isinstance(child, ScrollView):
                scroll = child
                break
        if scroll is None or not getattr(scroll, 'children', None):
            return
        box = scroll.children[0]
        if getattr(box, '_admin_users_card_added', False):
            return
        session = load_supabase_cloud_session()
        card = SectionCard('Admin Users', 'View SH Vertex account signups inside the app. This is admin-only and uses a protected Supabase Edge Function.', accent=UI_PURPLE)
        stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(72))
        stats.add_widget(build_stat_chip('YES' if _is_shv_admin_session(session) else 'NO', 'Admin Access', GREEN if _is_shv_admin_session(session) else UI_RED))
        stats.add_widget(build_stat_chip(SUPABASE_ADMIN_USERS_FUNCTION, 'Function', UI_CYAN))
        card.add_widget(stats)
        row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
        open_btn = make_button('Open User Accounts', UI_CYAN)
        copy_code_btn = make_button('Copy Function Code', GREEN)
        copy_name_btn = make_button('Copy Function Name', UI_CYAN)
        refresh_btn = make_button('Refresh Session', UI_ORANGE)
        open_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'cloud_users'))
        copy_code_btn.bind(on_release=lambda *_: copy_to_clipboard('Supabase admin users function', _SUPABASE_ADMIN_USERS_FUNCTION_TS))
        copy_name_btn.bind(on_release=lambda *_: copy_to_clipboard('Function name', SUPABASE_ADMIN_USERS_FUNCTION))
        refresh_btn.bind(on_release=lambda *_: self._test_cloud_session())
        for btn in (open_btn, copy_code_btn, copy_name_btn, refresh_btn):
            row.add_widget(btn)
        card.add_widget(row)
        card.add_widget(make_label('Deploy the copied function in Supabase Edge Functions and add the secret: SUPABASE_SERVICE_ROLE_KEY', color=SUBTEXT, height=dp(44)))
        box.add_widget(card)
        box._admin_users_card_added = True
    except Exception:
        pass

AccountsScreen.build_ui = _accounts_build_ui_with_admin_tools
