SUPABASE_CONTROL_FUNCTION = 'shv-admin-control'
_SUPABASE_CONTROL_FUNCTION_TS = rf"""import {{ createClient }} from 'https://esm.sh/@supabase/supabase-js@2'\n\nconst corsHeaders = {{\n  'Access-Control-Allow-Origin': '*',\n  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',\n}}\n\nconst ADMIN_UUID = '{SHV_ADMIN_UUID}'\nconst ADMIN_EMAIL = '{SHV_ADMIN_EMAIL}'\nconst CLOUD_BACKUPS_TABLE = '{SUPABASE_CLOUD_BACKUPS_TABLE}'\nconst EMERGENCY_TABLE = '{SUPABASE_EMERGENCY_TABLE}'\nconst FUNCTION_NAMES = ['{SUPABASE_ADMIN_USERS_FUNCTION}', 'shv-admin-control']\n\nfunction jsonResponse(payload, status = 200) {{\n  return new Response(JSON.stringify(payload), {{\n    status,\n    headers: {{ ...corsHeaders, 'Content-Type': 'application/json' }},\n  }})\n}}\n\nfunction functionUrl(projectUrl, fnName) {{\n  return String(projectUrl || '').replace(/\/$/, '') + '/functions/v1/' + String(fnName || '')\n}}\n\nDeno.serve(async (req) => {{\n  if (req.method === 'OPTIONS') {{\n    return new Response('ok', {{ headers: corsHeaders }})\n  }}\n\n  const supabaseUrl = Deno.env.get('SUPABASE_URL') ?? ''\n  const anonKey = Deno.env.get('SUPABASE_ANON_KEY') ?? ''\n  const serviceRoleKey = Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''\n\n  if (!supabaseUrl || !anonKey || !serviceRoleKey) {{\n    return jsonResponse({{ error: 'Missing Edge Function secrets.' }}, 500)\n  }}\n\n  const authHeader = req.headers.get('Authorization') ?? ''\n  if (!authHeader) {{\n    return jsonResponse({{ error: 'Missing Authorization header.' }}, 401)\n  }}\n\n  const userClient = createClient(supabaseUrl, anonKey, {{\n    global: {{ headers: {{ Authorization: authHeader }} }},\n  }})\n  const adminClient = createClient(supabaseUrl, serviceRoleKey)\n\n  const {{ data: userData, error: userError }} = await userClient.auth.getUser()\n  if (userError || !userData?.user) {{\n    return jsonResponse({{ error: userError?.message || 'Not authenticated.' }}, 401)\n  }}\n\n  const currentUser = userData.user\n  const currentEmail = String(currentUser.email || '').toLowerCase()\n  if (currentUser.id !== ADMIN_UUID && currentEmail !== ADMIN_EMAIL.toLowerCase()) {{\n    return jsonResponse({{ error: 'Admin access required.' }}, 403)\n  }}\n\n  let body = {{}}\n  try {{\n    body = await req.json()\n  }} catch (_) {{\n    body = {{}}\n  }}\n  const action = String(body.action || 'overview')\n\n  async function countTable(tableName) {{\n    const {{ count, error }} = await adminClient.from(tableName).select('*', {{ count: 'exact', head: true }})\n    if (error) throw error\n    return Number(count || 0)\n  }}\n\n  async function listAllUsers(limit = 500) {{\n    let page = 1\n    const perPage = 200\n    const users = []\n    while (true) {{\n      const {{ data, error }} = await adminClient.auth.admin.listUsers({{ page, perPage }})\n      if (error) throw error\n      const pageUsers = data?.users ?? []\n      for (const u of pageUsers) users.push(u)\n      if (pageUsers.length < perPage || users.length >= limit) break\n      page += 1\n    }}\n    return users\n  }}\n\n  try {{\n    if (action === 'overview') {{\n      const users = await listAllUsers(1000)\n      const totalUsers = users.length\n      const confirmedUsers = users.filter((u) => Boolean(u.email_confirmed_at)).length\n      const anonUsers = users.filter((u) => Boolean(u.is_anonymous)).length\n      const cloudBackups = await countTable(CLOUD_BACKUPS_TABLE)\n      const emergencyItems = await countTable(EMERGENCY_TABLE)\n      const {{ data: buckets, error: bucketsError }} = await adminClient.storage.listBuckets()\n      if (bucketsError) throw bucketsError\n      const bucketCount = Array.isArray(buckets) ? buckets.length : 0\n      const functions = FUNCTION_NAMES.map((name) => ({{ name, url: functionUrl(supabaseUrl, name) }}))\n      return jsonResponse({{\n        ok: true,\n        overview: {{\n          project_url: supabaseUrl,\n          total_users: totalUsers,\n          confirmed_users: confirmedUsers,\n          anonymous_users: anonUsers,\n          cloud_backups: cloudBackups,\n          emergency_items: emergencyItems,\n          bucket_count: bucketCount,\n          functions,\n        }},\n      }})\n    }}\n\n    if (action === 'table_preview') {{\n      const tableName = String(body.table || '')\n      const allowed = [CLOUD_BACKUPS_TABLE, EMERGENCY_TABLE]\n      if (!allowed.includes(tableName)) return jsonResponse({{ error: 'Table not allowed.' }}, 400)\n      const limit = Math.max(1, Math.min(30, Number(body.limit || 12)))\n      const orderCol = tableName === EMERGENCY_TABLE ? 'updated_at' : 'created_at'\n      const {{ data, error }} = await adminClient.from(tableName).select('*').order(orderCol, {{ ascending: false }}).limit(limit)\n      if (error) throw error\n      return jsonResponse({{ ok: true, table: tableName, rows: data || [] }})\n    }}\n\n    if (action === 'storage_summary') {{\n      const {{ data: buckets, error: bucketsError }} = await adminClient.storage.listBuckets()\n      if (bucketsError) throw bucketsError\n      const rows = (Array.isArray(buckets) ? buckets : []).map((b) => ({{\n        id: b.id || '',\n        name: b.name || '',\n        public: Boolean(b.public),\n        created_at: b.created_at || '',\n        updated_at: b.updated_at || '',\n      }}))\n      return jsonResponse({{ ok: true, buckets: rows }})\n    }}\n\n    if (action === 'functions_info') {{\n      const rows = FUNCTION_NAMES.map((name) => ({{\n        name,\n        url: functionUrl(supabaseUrl, name),\n        status: name === 'shv-admin-control' ? 'Deployed if this screen loaded' : 'Deploy separately',\n      }}))\n      return jsonResponse({{ ok: true, functions: rows }})\n    }}\n\n    if (action === 'sql_report') {{\n      const report = String(body.report || 'recent_backups')\n      if (report === 'recent_backups') {{\n        const {{ data, error }} = await adminClient.from(CLOUD_BACKUPS_TABLE).select('backup_name, created_at, bundle_type').order('created_at', {{ ascending: false }}).limit(20)\n        if (error) throw error\n        return jsonResponse({{ ok: true, report, rows: data || [] }})\n      }}\n      if (report === 'emergency_categories') {{\n        const {{ data, error }} = await adminClient.from(EMERGENCY_TABLE).select('category')\n        if (error) throw error\n        const counts = new Map()\n        for (const row of (data || [])) {{\n          const key = String(row.category || 'General')\n          counts.set(key, Number(counts.get(key) || 0) + 1)\n        }}\n        const rows = Array.from(counts.entries()).map(([category, count]) => ({{ category, count }})).sort((a, b) => b.count - a.count)\n        return jsonResponse({{ ok: true, report, rows }})\n      }}\n      if (report === 'recent_signups') {{\n        const users = await listAllUsers(60)\n        const rows = users.slice(0, 30).map((u) => ({{\n          id: u.id || '',\n          email: u.email || '',\n          created_at: u.created_at || '',\n          email_confirmed_at: u.email_confirmed_at || '',\n        }}))\n        return jsonResponse({{ ok: true, report, rows }})\n      }}\n      return jsonResponse({{ error: 'Unknown report.' }}, 400)\n    }}\n\n    return jsonResponse({{ error: 'Unknown action.' }}, 400)\n  }} catch (error) {{\n    return jsonResponse({{ error: error?.message || 'Request failed.' }}, 500)\n  }}\n}})\n"""


def _supabase_call_control_function(cfg, session, action='overview', payload=None, function_name=SUPABASE_CONTROL_FUNCTION):
    cfg = _supabase_require_config(cfg)
    session = ensure_supabase_cloud_session(cfg, session)
    headers = _supabase_auth_headers(cfg, session.get('access_token', ''))
    body = {'action': action}
    if isinstance(payload, dict):
        body.update(payload)
    resp = requests.post(
        cfg['url'] + '/functions/v1/' + str(function_name or SUPABASE_CONTROL_FUNCTION).strip(),
        headers=headers,
        json=body,
        timeout=45,
    )
    if resp.status_code not in (200, 201):
        raise RuntimeError(_supabase_error_text(resp))
    try:
        data = resp.json()
    except Exception:
        raise RuntimeError('Supabase control function returned invalid JSON.')
    if isinstance(data, dict) and data.get('ok'):
        return data, session
    if isinstance(data, dict) and data.get('error'):
        raise RuntimeError(str(data.get('error')))
    raise RuntimeError('Supabase control function returned an unexpected response.')


class SupabaseControlScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.current_tab = 'overview'
        self.current_table = SUPABASE_CLOUD_BACKUPS_TABLE
        self.current_report = 'recent_backups'
        Clock.schedule_once(self.build_ui, 0)

    def on_pre_enter(self, *_):
        Clock.schedule_once(self.refresh_ui, 0)

    def build_ui(self, *_):
        self.clear_widgets()
        self.scroll = ScrollView(do_scroll_x=False)
        self.root_box = BoxLayout(orientation='vertical', padding=[dp(10), dp(12), dp(10), dp(18)], spacing=dp(10), size_hint_y=None)
        self.root_box.bind(minimum_height=self.root_box.setter('height'))
        self.scroll.add_widget(self.root_box)
        self.add_widget(self.scroll)
        self.refresh_ui()

    def refresh_ui(self, *_):
        self.root_box.clear_widgets()
        self.root_box.add_widget(build_screen_header(
            'Supabase Control',
            'Admin-only Supabase control tools under Accounts.',
            'accounts',
            [
                ('Copy Fn Name', lambda: copy_to_clipboard('Function name', SUPABASE_CONTROL_FUNCTION)),
                ('Copy Fn Code', lambda: copy_to_clipboard('Function code', _SUPABASE_CONTROL_FUNCTION_TS)),
            ],
        ))
        self.root_box.add_widget(self._build_summary_card())
        self.root_box.add_widget(self._build_tab_row())
        self.root_box.add_widget(self._build_tab_content())

    def _collect_cfg(self):
        cfg = load_supabase_cloud_config()
        return {
            'url': str(cfg.get('url', '') or '').strip(),
            'anon_key': str(cfg.get('anon_key', '') or '').strip(),
            'email': str(cfg.get('email', '') or '').strip(),
        }

    def _call(self, action='overview', payload=None):
        cfg = self._collect_cfg()
        session = load_supabase_cloud_session()
        data, session = _supabase_call_control_function(cfg, session, action, payload)
        save_supabase_cloud_session(session)
        return data

    def _build_summary_card(self):
        session = load_supabase_cloud_session()
        email = str(session.get('email', '') or '').strip() or 'Offline'
        card = SectionCard('Control Status', 'Secure Supabase project insights for SH Vertex admins only.', accent=UI_PURPLE)
        stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(72))
        stats.add_widget(build_stat_chip('YES' if _is_shv_admin_session(session) else 'NO', 'Admin Access', GREEN if _is_shv_admin_session(session) else UI_RED))
        stats.add_widget(build_stat_chip(email[:18], 'Cloud Session', UI_CYAN if email != 'Offline' else UI_ORANGE))
        card.add_widget(stats)
        row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
        refresh_btn = make_button('Refresh', GREEN)
        copy_name_btn = make_button('Copy Function Name', UI_CYAN)
        copy_code_btn = make_button('Copy Function Code', UI_CYAN)
        back_btn = make_button('Back Accounts', UI_ORANGE)
        refresh_btn.bind(on_release=lambda *_: self.refresh_ui())
        copy_name_btn.bind(on_release=lambda *_: copy_to_clipboard('Function name', SUPABASE_CONTROL_FUNCTION))
        copy_code_btn.bind(on_release=lambda *_: copy_to_clipboard('Supabase control function', _SUPABASE_CONTROL_FUNCTION_TS))
        back_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'accounts'))
        for btn in (refresh_btn, copy_name_btn, copy_code_btn, back_btn):
            row.add_widget(btn)
        card.add_widget(row)
        card.add_widget(make_label('Deploy this function in Supabase Edge Functions and add the secret: SUPABASE_SERVICE_ROLE_KEY', color=SUBTEXT, height=dp(44)))
        return card

    def _build_tab_row(self):
        row = GridLayout(cols=5, spacing=dp(8), size_hint_y=None, height=dp(46))
        self._tab_buttons = {}
        for key, title in [
            ('overview', 'Overview'),
            ('tables', 'Tables'),
            ('sql', 'SQL'),
            ('storage', 'Storage'),
            ('functions', 'Functions'),
        ]:
            btn = make_nav_button(title)
            btn.bind(on_release=lambda *_ , tab_key=key: self._set_tab(tab_key))
            self._tab_buttons[key] = btn
            row.add_widget(btn)
        self._update_tab_styles()
        return row

    def _set_tab(self, tab_key):
        self.current_tab = tab_key
        self.refresh_ui()

    def _update_tab_styles(self):
        active_bg = get_color_from_hex(GREEN)
        inactive_bg = get_color_from_hex('#141a22')
        active_text = (0, 0, 0, 1)
        inactive_text = get_color_from_hex(TEXT)
        for key, btn in getattr(self, '_tab_buttons', {}).items():
            if key == self.current_tab:
                btn.background_color = active_bg
                btn.color = active_text
            else:
                btn.background_color = inactive_bg
                btn.color = inactive_text

    def _build_tab_content(self):
        card = SectionCard(self.current_tab.title(), 'Live data is fetched through the SH Vertex admin control function.', accent=UI_CYAN)
        try:
            if self.current_tab == 'overview':
                data = self._call('overview')
                ov = data.get('overview', {}) or {}
                stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(146))
                stats.add_widget(build_stat_chip(ov.get('total_users', 0), 'Users', GREEN))
                stats.add_widget(build_stat_chip(ov.get('confirmed_users', 0), 'Confirmed', UI_CYAN))
                stats.add_widget(build_stat_chip(ov.get('cloud_backups', 0), 'Cloud Backups', UI_ORANGE))
                stats.add_widget(build_stat_chip(ov.get('emergency_items', 0), 'Vault Items', UI_PURPLE))
                stats.add_widget(build_stat_chip(ov.get('bucket_count', 0), 'Buckets', UI_TEAL))
                stats.add_widget(build_stat_chip(len(ov.get('functions', []) or []), 'Functions', UI_BLUE))
                card.add_widget(stats)
                card.add_widget(make_label('Project URL: ' + str(ov.get('project_url', '--')), color=SUBTEXT, height=dp(28)))
                funcs = ov.get('functions', []) or []
                for item in funcs:
                    fcard = SectionCard(str(item.get('name', 'Function')), str(item.get('url', '')))
                    row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
                    copy_btn = make_button('Copy URL', UI_CYAN)
                    copy_btn.bind(on_release=lambda *_ , txt=str(item.get('url', '')): copy_to_clipboard('Function URL', txt))
                    row.add_widget(copy_btn)
                    fcard.add_widget(row)
                    card.add_widget(fcard)
            elif self.current_tab == 'tables':
                chooser = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(46))
                btn_a = make_button('Cloud Backups', GREEN if self.current_table == SUPABASE_CLOUD_BACKUPS_TABLE else UI_CYAN)
                btn_b = make_button('Emergency Vault', GREEN if self.current_table == SUPABASE_EMERGENCY_TABLE else UI_CYAN)
                btn_a.bind(on_release=lambda *_: self._set_table(SUPABASE_CLOUD_BACKUPS_TABLE))
                btn_b.bind(on_release=lambda *_: self._set_table(SUPABASE_EMERGENCY_TABLE))
                chooser.add_widget(btn_a)
                chooser.add_widget(btn_b)
                card.add_widget(chooser)
                data = self._call('table_preview', {'table': self.current_table, 'limit': 12})
                rows = data.get('rows', []) or []
                if not rows:
                    card.add_widget(make_label('No rows returned.', color=SUBTEXT, height=dp(28)))
                for row_data in rows:
                    if self.current_table == SUPABASE_CLOUD_BACKUPS_TABLE:
                        title = str(row_data.get('backup_name', 'Cloud Backup'))
                        subtitle = 'Created: ' + short_time(str(row_data.get('created_at', '') or ''))
                    else:
                        title = str(row_data.get('title', 'Vault Item'))
                        subtitle = str(row_data.get('category', 'General')) + '  •  ' + short_time(str(row_data.get('updated_at', '') or ''))
                    item_card = SectionCard(title, subtitle)
                    pretty = json.dumps(row_data, indent=2, ensure_ascii=False)
                    row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
                    copy_btn = make_button('Copy JSON', UI_CYAN)
                    copy_btn.bind(on_release=lambda *_ , txt=pretty: copy_to_clipboard('Row JSON', txt))
                    row.add_widget(copy_btn)
                    item_card.add_widget(row)
                    card.add_widget(item_card)
            elif self.current_tab == 'sql':
                chooser = GridLayout(cols=3, spacing=dp(8), size_hint_y=None, height=dp(46))
                for report_key, title in [
                    ('recent_backups', 'Backups'),
                    ('emergency_categories', 'Vault Cats'),
                    ('recent_signups', 'Signups'),
                ]:
                    btn = make_button(title, GREEN if self.current_report == report_key else UI_CYAN)
                    btn.bind(on_release=lambda *_ , rk=report_key: self._set_report(rk))
                    chooser.add_widget(btn)
                card.add_widget(chooser)
                data = self._call('sql_report', {'report': self.current_report})
                rows = data.get('rows', []) or []
                if not rows:
                    card.add_widget(make_label('No report rows returned.', color=SUBTEXT, height=dp(28)))
                for row_data in rows:
                    if self.current_report == 'recent_backups':
                        title = str(row_data.get('backup_name', '--'))
                        subtitle = str(row_data.get('bundle_type', '--')) + '  •  ' + short_time(str(row_data.get('created_at', '') or ''))
                    elif self.current_report == 'emergency_categories':
                        title = str(row_data.get('category', 'General'))
                        subtitle = 'Count: ' + str(row_data.get('count', 0))
                    else:
                        title = str(row_data.get('email', 'Unknown'))
                        subtitle = 'Created: ' + short_time(str(row_data.get('created_at', '') or ''))
                    item_card = SectionCard(title, subtitle)
                    pretty = json.dumps(row_data, indent=2, ensure_ascii=False)
                    row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
                    copy_btn = make_button('Copy Row', UI_CYAN)
                    copy_btn.bind(on_release=lambda *_ , txt=pretty: copy_to_clipboard('Report row', txt))
                    row.add_widget(copy_btn)
                    item_card.add_widget(row)
                    card.add_widget(item_card)
            elif self.current_tab == 'storage':
                data = self._call('storage_summary')
                rows = data.get('buckets', []) or []
                if not rows:
                    card.add_widget(make_label('No buckets found.', color=SUBTEXT, height=dp(28)))
                for row_data in rows:
                    title = str(row_data.get('name', 'Bucket'))
                    subtitle = ('Public' if row_data.get('public') else 'Private') + '  •  ' + short_time(str(row_data.get('updated_at', '') or row_data.get('created_at', '') or ''))
                    item_card = SectionCard(title, subtitle)
                    pretty = json.dumps(row_data, indent=2, ensure_ascii=False)
                    row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
                    copy_btn = make_button('Copy JSON', UI_CYAN)
                    copy_btn.bind(on_release=lambda *_ , txt=pretty: copy_to_clipboard('Bucket JSON', txt))
                    row.add_widget(copy_btn)
                    item_card.add_widget(row)
                    card.add_widget(item_card)
            elif self.current_tab == 'functions':
                data = self._call('functions_info')
                rows = data.get('functions', []) or []
                if not rows:
                    card.add_widget(make_label('No functions returned.', color=SUBTEXT, height=dp(28)))
                for row_data in rows:
                    item_card = SectionCard(str(row_data.get('name', 'Function')), str(row_data.get('status', '--')))
                    item_card.add_widget(make_label(str(row_data.get('url', '')), color=SUBTEXT, height=dp(28)))
                    row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
                    copy_btn = make_button('Copy URL', UI_CYAN)
                    copy_btn.bind(on_release=lambda *_ , txt=str(row_data.get('url', '')): copy_to_clipboard('Function URL', txt))
                    row.add_widget(copy_btn)
                    item_card.add_widget(row)
                    card.add_widget(item_card)
        except Exception as e:
            card.add_widget(make_label('Load failed: ' + str(e), color=RED, height=dp(44)))
        return card

    def _set_table(self, table_name):
        self.current_table = table_name
        self.refresh_ui()

    def _set_report(self, report_key):
        self.current_report = report_key
        self.refresh_ui()


_prev_accounts_build_ui_control = AccountsScreen.build_ui

def _accounts_build_ui_with_supabase_control(self, *a, **kw):
    _prev_accounts_build_ui_control(self, *a, **kw)
    try:
        outer = self.children[0] if self.children else None
        content_root = None
        if isinstance(outer, BoxLayout):
            for child in list(reversed(getattr(outer, 'children', []) or [])):
                if isinstance(child, BoxLayout):
                    content_root = child
                    break
        if content_root is None:
            return
        scroll = None
        for child in list(reversed(getattr(content_root, 'children', []) or [])):
            if isinstance(child, ScrollView):
                scroll = child
                break
        if scroll is None or not getattr(scroll, 'children', None):
            return
        box = scroll.children[0]
        if getattr(box, '_supabase_control_card_added', False):
            return
        session = load_supabase_cloud_session()
        card = SectionCard('Supabase Control', 'Admin-only Supabase project insights, safe reports, storage summary, and function URLs.', accent=UI_TEAL)
        stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(72))
        stats.add_widget(build_stat_chip('YES' if _is_shv_admin_session(session) else 'NO', 'Admin Access', GREEN if _is_shv_admin_session(session) else UI_RED))
        stats.add_widget(build_stat_chip(SUPABASE_CONTROL_FUNCTION, 'Function', UI_CYAN))
        card.add_widget(stats)
        row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
        open_btn = make_button('Open Supabase Control', UI_CYAN)
        copy_code_btn = make_button('Copy Control Code', GREEN)
        copy_name_btn = make_button('Copy Function Name', UI_CYAN)
        refresh_btn = make_button('Refresh Session', UI_ORANGE)
        open_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'supabase_control'))
        copy_code_btn.bind(on_release=lambda *_: copy_to_clipboard('Supabase control function', _SUPABASE_CONTROL_FUNCTION_TS))
        copy_name_btn.bind(on_release=lambda *_: copy_to_clipboard('Function name', SUPABASE_CONTROL_FUNCTION))
        refresh_btn.bind(on_release=lambda *_: self._test_cloud_session())
        for btn in (open_btn, copy_code_btn, copy_name_btn, refresh_btn):
            row.add_widget(btn)
        card.add_widget(row)
        card.add_widget(make_label('Deploy the copied function in Supabase Edge Functions and add the secret: SUPABASE_SERVICE_ROLE_KEY', color=SUBTEXT, height=dp(44)))
        box.add_widget(card)
        box._supabase_control_card_added = True
    except Exception:
        pass

AccountsScreen.build_ui = _accounts_build_ui_with_supabase_control
AccountsScreen._accounts_build_ui_with_supabase_control = _accounts_build_ui_with_supabase_control

