# ---- direct Supabase admin upgrade: personal access token + project admin key ----
SUPABASE_DIRECT_ADMIN_CONFIG_FILE = 'supabase_direct_admin_config.json'
SUPABASE_MANAGEMENT_API_BASE = 'https://api.supabase.com/v1'
_DIRECT_CONTROL_TABS = (
    ('overview', 'Overview'),
    ('projects', 'Projects'),
    ('users', 'Users'),
    ('tables', 'Tables'),
    ('storage', 'Storage'),
    ('functions', 'Functions'),
    ('secrets', 'Secrets'),
)


def _supabase_direct_config_path():
    return admin_data_path(SUPABASE_DIRECT_ADMIN_CONFIG_FILE)


def _supabase_direct_guess_project_ref(url):
    raw = str(url or '').strip()
    if not raw:
        return ''
    raw = raw.replace('https://', '').replace('http://', '')
    host = raw.split('/')[0].strip()
    if not host:
        return ''
    return host.split('.')[0].strip()


def load_supabase_direct_config():
    data = load_json(_supabase_direct_config_path(), {})
    if not isinstance(data, dict):
        data = {}
    cloud = load_supabase_cloud_config()
    url = str(data.get('url', '') or '').strip() or str(cloud.get('url', '') or '').strip()
    project_ref = str(data.get('project_ref', '') or '').strip() or _supabase_direct_guess_project_ref(url)
    return {
        'url': _supabase_normalize_url(url),
        'project_ref': project_ref,
        'personal_token': str(data.get('personal_token', '') or '').strip(),
        'project_key': str(data.get('project_key', '') or '').strip(),
    }


def save_supabase_direct_config(cfg):
    clean = {
        'url': _supabase_normalize_url(cfg.get('url', '')),
        'project_ref': str(cfg.get('project_ref', '') or '').strip() or _supabase_direct_guess_project_ref(cfg.get('url', '')),
        'personal_token': str(cfg.get('personal_token', '') or '').strip(),
        'project_key': str(cfg.get('project_key', '') or '').strip(),
    }
    save_json(_supabase_direct_config_path(), clean)


def _supabase_direct_current_ref(cfg):
    return str(cfg.get('project_ref', '') or '').strip() or _supabase_direct_guess_project_ref(cfg.get('url', ''))


def _supabase_direct_require_management(cfg):
    token = str(cfg.get('personal_token', '') or '').strip()
    if not token:
        raise ValueError('Save your Supabase personal access token first.')
    return token


def _supabase_direct_require_project(cfg):
    url = _supabase_normalize_url(cfg.get('url', ''))
    key = str(cfg.get('project_key', '') or '').strip()
    if not url:
        raise ValueError('Save the Supabase Project URL first.')
    if not key:
        raise ValueError('Save the project admin key first.')
    return url, key


def _supabase_direct_management_headers(cfg):
    token = _supabase_direct_require_management(cfg)
    return {
        'Authorization': f'Bearer {token}',
        'Content-Type': 'application/json',
    }


def _supabase_direct_project_headers(cfg):
    _, key = _supabase_direct_require_project(cfg)
    return {
        'apikey': key,
        'Authorization': f'Bearer {key}',
        'Content-Type': 'application/json',
    }


def _supabase_direct_request(method, url, headers, params=None, json_body=None, timeout=45):
    resp = requests.request(method, url, headers=headers, params=params, json=json_body, timeout=timeout)
    if resp.status_code not in (200, 201):
        raise RuntimeError(_supabase_error_text(resp))
    text = str(resp.text or '').strip()
    if not text:
        return {}
    try:
        return resp.json()
    except Exception:
        return {'raw_text': text}


def _supabase_direct_listify(data, *keys):
    if isinstance(data, list):
        return data
    if isinstance(data, dict):
        for key in keys:
            value = data.get(key)
            if isinstance(value, list):
                return value
        for value in data.values():
            if isinstance(value, list):
                return value
    return []


def _supabase_direct_management_get(cfg, path, params=None):
    return _supabase_direct_request('GET', SUPABASE_MANAGEMENT_API_BASE + path, _supabase_direct_management_headers(cfg), params=params, timeout=45)


def _supabase_direct_project_get(cfg, path, params=None):
    url, _ = _supabase_direct_require_project(cfg)
    return _supabase_direct_request('GET', url + path, _supabase_direct_project_headers(cfg), params=params, timeout=45)


def _supabase_direct_list_projects(cfg):
    data = _supabase_direct_management_get(cfg, '/projects')
    rows = _supabase_direct_listify(data, 'projects', 'data')
    return rows if isinstance(rows, list) else []


def _supabase_direct_get_project(cfg):
    ref = _supabase_direct_current_ref(cfg)
    if not ref:
        raise ValueError('Enter a Project URL or Project Ref first.')
    data = _supabase_direct_management_get(cfg, f'/projects/{ref}')
    return data if isinstance(data, dict) else {}


def _supabase_direct_list_functions(cfg):
    ref = _supabase_direct_current_ref(cfg)
    if not ref:
        raise ValueError('Enter a Project URL or Project Ref first.')
    data = _supabase_direct_management_get(cfg, f'/projects/{ref}/functions')
    rows = _supabase_direct_listify(data, 'functions', 'data')
    return rows if isinstance(rows, list) else []


def _supabase_direct_list_secrets(cfg):
    ref = _supabase_direct_current_ref(cfg)
    if not ref:
        raise ValueError('Enter a Project URL or Project Ref first.')
    data = _supabase_direct_management_get(cfg, f'/projects/{ref}/secrets')
    rows = _supabase_direct_listify(data, 'secrets', 'data')
    return rows if isinstance(rows, list) else []


def _supabase_direct_list_users(cfg, limit=500):
    url, _ = _supabase_direct_require_project(cfg)
    users = []
    page = 1
    per_page = 100
    while True:
        data = _supabase_direct_request(
            'GET',
            url + '/auth/v1/admin/users',
            _supabase_direct_project_headers(cfg),
            params={'page': page, 'per_page': per_page},
            timeout=45,
        )
        page_users = _supabase_direct_listify(data, 'users', 'data')
        if not page_users:
            break
        users.extend(page_users)
        if len(page_users) < per_page or len(users) >= limit:
            break
        page += 1
    return users[:limit]


def _supabase_direct_list_buckets(cfg):
    data = _supabase_direct_project_get(cfg, '/storage/v1/bucket')
    rows = _supabase_direct_listify(data, 'buckets', 'data')
    return rows if isinstance(rows, list) else []


def _supabase_direct_list_tables(cfg):
    params = {
        'limit': '200',
        'excluded_schemas': 'pg_catalog,information_schema',
    }
    try:
        data = _supabase_direct_project_get(cfg, '/pg/meta/tables', params=params)
    except Exception:
        data = _supabase_direct_project_get(cfg, '/pg/meta/tables', params={'limit': '200'})
    rows = _supabase_direct_listify(data, 'tables', 'data')
    if not isinstance(rows, list):
        rows = []
    rows = [row for row in rows if isinstance(row, dict)]
    rows.sort(key=lambda r: (str(r.get('schema', '') or ''), str(r.get('name', '') or '')))
    return rows


def _supabase_direct_preview_table(cfg, table_name, schema_name='public', limit=8):
    if str(schema_name or 'public').strip() != 'public':
        return []
    table_name = str(table_name or '').strip()
    if not table_name:
        return []
    data = _supabase_direct_project_get(cfg, '/rest/v1/' + table_name, params={'select': '*', 'limit': str(max(1, min(20, int(limit or 8))))})
    rows = data if isinstance(data, list) else _supabase_direct_listify(data, 'rows', 'data')
    return rows if isinstance(rows, list) else []


def _supabase_direct_overview_payload(cfg):
    projects = _supabase_direct_list_projects(cfg)
    current_project = _supabase_direct_get_project(cfg)
    functions = _supabase_direct_list_functions(cfg)
    secrets = _supabase_direct_list_secrets(cfg)
    users = _supabase_direct_list_users(cfg, limit=1000)
    buckets = _supabase_direct_list_buckets(cfg)
    tables = _supabase_direct_list_tables(cfg)
    return {
        'projects': projects,
        'current_project': current_project,
        'functions': functions,
        'secrets': secrets,
        'users': users,
        'buckets': buckets,
        'tables': tables,
    }


def _supabase_direct_item_card(title, subtitle, payload=None, copy_label='Copy JSON', extra_buttons=None):
    card = SectionCard(str(title or '--'), str(subtitle or '--'))
    row = BoxLayout(size_hint_y=None, height=dp(42), spacing=dp(8))
    copy_btn = make_button(copy_label, UI_CYAN)
    payload_text = json.dumps(payload if payload is not None else {'title': title, 'subtitle': subtitle}, indent=2, ensure_ascii=False)
    copy_btn.bind(on_release=lambda *_ , txt=payload_text: copy_to_clipboard('JSON', txt))
    row.add_widget(copy_btn)
    for item in (extra_buttons or []):
        if isinstance(item, Button):
            row.add_widget(item)
    card.add_widget(row)
    return card


def _supabase_direct_accounts_find_box(self):
    outer = self.children[0] if self.children else None
    content_root = None
    if isinstance(outer, BoxLayout):
        for child in list(reversed(getattr(outer, 'children', []) or [])):
            if isinstance(child, BoxLayout):
                content_root = child
                break
    if content_root is None:
        return None
    scroll = None
    for child in list(reversed(getattr(content_root, 'children', []) or [])):
        if isinstance(child, ScrollView):
            scroll = child
            break
    if scroll is None or not getattr(scroll, 'children', None):
        return None
    return scroll.children[0]


def _accounts_collect_direct_admin_cfg(self):
    return {
        'url': getattr(self, '_direct_admin_url', make_input()).text.strip() if hasattr(self, '_direct_admin_url') else load_supabase_direct_config().get('url', ''),
        'project_ref': getattr(self, '_direct_admin_ref', make_input()).text.strip() if hasattr(self, '_direct_admin_ref') else load_supabase_direct_config().get('project_ref', ''),
        'personal_token': getattr(self, '_direct_admin_pat', make_input()).text.strip() if hasattr(self, '_direct_admin_pat') else load_supabase_direct_config().get('personal_token', ''),
        'project_key': getattr(self, '_direct_admin_key', make_input()).text.strip() if hasattr(self, '_direct_admin_key') else load_supabase_direct_config().get('project_key', ''),
    }


def _accounts_save_direct_admin_settings(self):
    cfg = self._collect_direct_admin_cfg()
    if not cfg.get('project_ref') and cfg.get('url'):
        cfg['project_ref'] = _supabase_direct_guess_project_ref(cfg.get('url', ''))
    save_supabase_direct_config(cfg)
    if hasattr(self, '_direct_admin_ref') and not self._direct_admin_ref.text.strip() and cfg.get('project_ref'):
        self._direct_admin_ref.text = cfg.get('project_ref', '')
    self._refresh_direct_admin_state()
    info_popup('Saved', 'Direct Supabase admin tokens saved locally.')


def _accounts_sync_direct_admin_from_cloud(self):
    cloud = load_supabase_cloud_config()
    cfg = load_supabase_direct_config()
    if str(cloud.get('url', '') or '').strip():
        cfg['url'] = str(cloud.get('url', '') or '').strip()
    if hasattr(self, '_direct_admin_url'):
        self._direct_admin_url.text = cfg.get('url', '')
    if hasattr(self, '_direct_admin_ref') and not self._direct_admin_ref.text.strip():
        self._direct_admin_ref.text = _supabase_direct_guess_project_ref(cfg.get('url', ''))
    save_supabase_direct_config(self._collect_direct_admin_cfg())
    self._refresh_direct_admin_state()
    info_popup('Synced', 'Direct admin URL synced from the SH Vertex Cloud settings.')


def _accounts_refresh_direct_admin_state(self):
    if not hasattr(self, '_direct_admin_state_lbl'):
        return
    cfg = self._collect_direct_admin_cfg() if hasattr(self, '_collect_direct_admin_cfg') else load_supabase_direct_config()
    ref = cfg.get('project_ref', '') or _supabase_direct_guess_project_ref(cfg.get('url', ''))
    bits = [
        'Project URL: ' + (cfg.get('url', '') or 'Not set'),
        'Project Ref: ' + (ref or 'Not set'),
        'Personal Token: ' + ('Saved' if cfg.get('personal_token') else 'Missing'),
        'Project Key: ' + ('Saved' if cfg.get('project_key') else 'Missing'),
    ]
    self._direct_admin_state_lbl.text = '\n'.join(bits)
    self._direct_admin_state_lbl.color = get_color_from_hex(GREEN if cfg.get('personal_token') and cfg.get('project_key') and (cfg.get('url') or ref) else SUBTEXT)


_prev_accounts_build_ui_direct_admin = AccountsScreen.build_ui


def _accounts_build_ui_with_direct_admin(self, *a, **kw):
    _prev_accounts_build_ui_direct_admin(self, *a, **kw)
    try:
        box = _supabase_direct_accounts_find_box(self)
        if box is None or getattr(box, '_direct_admin_card_added', False):
            return
        cfg = load_supabase_direct_config()
        card = SectionCard('Supabase Direct Admin', 'Use your personal access token plus a project admin key for live projects, users, tables, storage, functions, and secrets.', accent=UI_BLUE)
        self._direct_admin_url = make_input('Supabase Project URL')
        self._direct_admin_ref = make_input('Project ref (optional if URL is set)')
        self._direct_admin_pat = make_input('Personal access token')
        self._direct_admin_key = make_input('Project admin key (service_role or secret key)')
        self._direct_admin_url.text = cfg.get('url', '')
        self._direct_admin_ref.text = cfg.get('project_ref', '')
        self._direct_admin_pat.text = cfg.get('personal_token', '')
        self._direct_admin_key.text = cfg.get('project_key', '')
        for title, widget in (
            ('Project URL', self._direct_admin_url),
            ('Project Ref', self._direct_admin_ref),
            ('Personal Access Token', self._direct_admin_pat),
            ('Project Admin Key', self._direct_admin_key),
        ):
            card.add_widget(make_label(title))
            card.add_widget(widget)
            if widget in (self._direct_admin_pat, self._direct_admin_key):
                row = BoxLayout(size_hint_y=None, height=dp(40), spacing=dp(8))
                paste_btn = make_button('Paste', UI_CYAN)
                clear_btn = make_button('Clear', RED)
                paste_btn.bind(on_release=lambda *_ , w=widget: paste_clipboard_into(w))
                clear_btn.bind(on_release=lambda *_ , w=widget: setattr(w, 'text', ''))
                row.add_widget(paste_btn)
                row.add_widget(clear_btn)
                card.add_widget(row)
        self._direct_admin_state_lbl = make_label('', color=SUBTEXT, height=dp(96))
        card.add_widget(self._direct_admin_state_lbl)
        row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
        save_btn = make_button('Save Direct Tokens', GREEN)
        open_btn = make_button('Open Direct Control', UI_CYAN)
        sync_btn = make_button('Sync URL From Cloud', UI_ORANGE)
        copy_ref_btn = make_button('Copy Project Ref', UI_CYAN)
        save_btn.bind(on_release=lambda *_: self._save_direct_admin_settings())
        open_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'supabase_control'))
        sync_btn.bind(on_release=lambda *_: self._sync_direct_admin_from_cloud())
        copy_ref_btn.bind(on_release=lambda *_: copy_to_clipboard('Project ref', self._direct_admin_ref.text.strip() or _supabase_direct_guess_project_ref(self._direct_admin_url.text.strip())))
        for btn in (save_btn, open_btn, sync_btn, copy_ref_btn):
            row.add_widget(btn)
        card.add_widget(row)
        card.add_widget(make_label('This upgrade reads live project data directly through your saved personal token and project admin key. No admin user sign-in is required for this screen.', color=SUBTEXT, height=dp(44)))
        box.add_widget(card)
        box._direct_admin_card_added = True
        self._refresh_direct_admin_state()
    except Exception:
        pass


AccountsScreen._collect_direct_admin_cfg = _accounts_collect_direct_admin_cfg
AccountsScreen._save_direct_admin_settings = _accounts_save_direct_admin_settings
AccountsScreen._sync_direct_admin_from_cloud = _accounts_sync_direct_admin_from_cloud
AccountsScreen._refresh_direct_admin_state = _accounts_refresh_direct_admin_state
AccountsScreen.build_ui = _accounts_build_ui_with_direct_admin
AccountsScreen._accounts_build_ui_with_direct_admin = _accounts_build_ui_with_direct_admin


def _direct_supabase_build_ui(self, *_):
    self.current_tab = self.current_tab if getattr(self, 'current_tab', '') in dict(_DIRECT_CONTROL_TABS) else 'overview'
    self.current_table_name = getattr(self, 'current_table_name', '')
    self.current_table_schema = getattr(self, 'current_table_schema', 'public')
    self.clear_widgets()
    self.scroll = ScrollView(do_scroll_x=False)
    self.root_box = BoxLayout(orientation='vertical', padding=[dp(10), dp(12), dp(10), dp(18)], spacing=dp(10), size_hint_y=None)
    self.root_box.bind(minimum_height=self.root_box.setter('height'))
    self.scroll.add_widget(self.root_box)
    self.add_widget(self.scroll)
    self.refresh_ui()


def _direct_supabase_on_pre_enter(self, *_):
    Clock.schedule_once(self.refresh_ui, 0)


def _direct_supabase_collect_cfg(self):
    return load_supabase_direct_config()


def _direct_supabase_set_tab(self, tab_key):
    self.current_tab = str(tab_key or 'overview')
    self.refresh_ui()


def _direct_supabase_set_table(self, table_name, schema_name='public'):
    self.current_table_name = str(table_name or '').strip()
    self.current_table_schema = str(schema_name or 'public').strip() or 'public'
    self.current_tab = 'tables'
    self.refresh_ui()


def _direct_supabase_refresh_ui(self, *_):
    if not hasattr(self, 'root_box'):
        return
    cfg = self._collect_cfg()
    project_ref = _supabase_direct_current_ref(cfg)
    self.root_box.clear_widgets()
    self.root_box.add_widget(build_screen_header(
        'Supabase Direct Control',
        'Live project data using your personal access token and project admin key.',
        'accounts',
        [
            ('Copy Ref', lambda: copy_to_clipboard('Project ref', project_ref or '--')),
            ('Back', lambda: setattr(self.manager, 'current', 'accounts')),
        ],
    ))
    self.root_box.add_widget(self._build_summary_card())
    self.root_box.add_widget(self._build_tab_row())
    self.root_box.add_widget(self._build_tab_content())


def _direct_supabase_build_summary_card(self):
    cfg = self._collect_cfg()
    ref = _supabase_direct_current_ref(cfg)
    card = SectionCard('Direct Status', 'Management API + project admin key are used here instead of the older user-session function path.', accent=UI_PURPLE)
    stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(72))
    stats.add_widget(build_stat_chip('YES' if cfg.get('personal_token') else 'NO', 'Personal Token', GREEN if cfg.get('personal_token') else UI_RED))
    stats.add_widget(build_stat_chip('YES' if cfg.get('project_key') else 'NO', 'Project Key', UI_CYAN if cfg.get('project_key') else UI_ORANGE))
    card.add_widget(stats)
    card.add_widget(make_label('Project URL: ' + (cfg.get('url', '') or 'Not set'), color=SUBTEXT, height=dp(28)))
    card.add_widget(make_label('Project Ref: ' + (ref or 'Not set'), color=SUBTEXT, height=dp(28)))
    row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
    refresh_btn = make_button('Refresh', GREEN)
    accounts_btn = make_button('Back Accounts', UI_ORANGE)
    save_btn = make_button('Save Tokens', UI_CYAN)
    sync_btn = make_button('Sync URL From Cloud', UI_CYAN)
    refresh_btn.bind(on_release=lambda *_: self.refresh_ui())
    accounts_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'accounts'))
    save_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'accounts'))
    sync_btn.bind(on_release=lambda *_: (setattr(self.manager, 'current', 'accounts'), Clock.schedule_once(lambda *_: getattr(self.manager.get_screen('accounts'), '_sync_direct_admin_from_cloud', lambda : None)(), 0)))
    for btn in (refresh_btn, accounts_btn, save_btn, sync_btn):
        row.add_widget(btn)
    card.add_widget(row)
    return card


def _direct_supabase_build_tab_row(self):
    row = GridLayout(cols=4, spacing=dp(8), size_hint_y=None, height=dp(94))
    self._tab_buttons = {}
    for key, title in _DIRECT_CONTROL_TABS:
        btn = make_nav_button(title)
        btn.bind(on_release=lambda *_ , tab_key=key: self._set_tab(tab_key))
        self._tab_buttons[key] = btn
        row.add_widget(btn)
    self._update_tab_styles()
    return row


def _direct_supabase_update_tab_styles(self):
    active_bg = get_color_from_hex(GREEN)
    inactive_bg = get_color_from_hex('#141a22')
    active_text = (0, 0, 0, 1)
    inactive_text = get_color_from_hex(TEXT)
    for key, btn in getattr(self, '_tab_buttons', {}).items():
        if key == getattr(self, 'current_tab', 'overview'):
            btn.background_color = active_bg
            btn.color = active_text
        else:
            btn.background_color = inactive_bg
            btn.color = inactive_text


def _direct_supabase_build_tab_content(self):
    card = SectionCard(dict(_DIRECT_CONTROL_TABS).get(self.current_tab, 'Overview'), 'Live project data rendered directly from the saved tokens.', accent=UI_CYAN)
    cfg = self._collect_cfg()
    if not cfg.get('url'):
        card.add_widget(make_label('Save the Project URL in Accounts → Supabase Direct Admin first.', color=UI_ORANGE, height=dp(32)))
        return card
    if not cfg.get('personal_token'):
        card.add_widget(make_label('Save the personal access token to load projects, functions, and secrets.', color=UI_ORANGE, height=dp(32)))
        return card
    if not cfg.get('project_key') and self.current_tab in ('overview', 'users', 'tables', 'storage'):
        card.add_widget(make_label('Save the project admin key to load users, tables, storage, and overview counts.', color=UI_ORANGE, height=dp(32)))
        return card
    try:
        if self.current_tab == 'overview':
            payload = _supabase_direct_overview_payload(cfg)
            current = payload.get('current_project', {}) or {}
            stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(220))
            stats.add_widget(build_stat_chip(len(payload.get('projects', []) or []), 'Projects', GREEN))
            stats.add_widget(build_stat_chip(len(payload.get('users', []) or []), 'Users', UI_CYAN))
            stats.add_widget(build_stat_chip(len(payload.get('tables', []) or []), 'Tables', UI_ORANGE))
            stats.add_widget(build_stat_chip(len(payload.get('buckets', []) or []), 'Buckets', UI_TEAL))
            stats.add_widget(build_stat_chip(len(payload.get('functions', []) or []), 'Functions', UI_BLUE))
            stats.add_widget(build_stat_chip(len(payload.get('secrets', []) or []), 'Secrets', UI_PURPLE))
            status_label = str(current.get('status', current.get('db_status', '--')) or '--')
            stats.add_widget(build_stat_chip(status_label[:14], 'Project Status', UI_CYAN))
            region = str(current.get('region', current.get('region_name', '--')) or '--')
            stats.add_widget(build_stat_chip(region[:14], 'Region', UI_ORANGE))
            card.add_widget(stats)
            pname = str(current.get('name', '') or _supabase_direct_current_ref(cfg) or 'Current Project')
            subtitle = 'Ref: ' + (_supabase_direct_current_ref(cfg) or '--')
            card.add_widget(_supabase_direct_item_card(pname, subtitle, current, copy_label='Copy Project JSON'))
            funcs = payload.get('functions', []) or []
            for item in funcs[:4]:
                title = str(item.get('name', item.get('slug', item.get('id', 'Function'))) or 'Function')
                subtitle = str(item.get('status', item.get('slug', '')) or '--')
                item_card = _supabase_direct_item_card(title, subtitle, item, copy_label='Copy JSON')
                card.add_widget(item_card)
        elif self.current_tab == 'projects':
            rows = _supabase_direct_list_projects(cfg)
            if not rows:
                card.add_widget(make_label('No projects returned for this personal access token.', color=SUBTEXT, height=dp(28)))
            current_ref = _supabase_direct_current_ref(cfg)
            for item in rows:
                ref = str(item.get('id', item.get('ref', item.get('project_ref', ''))) or '')
                name = str(item.get('name', ref or 'Project') or 'Project')
                status = str(item.get('status', item.get('db_status', '--')) or '--')
                subtitle = status + ('  •  Current' if ref == current_ref else '')
                extra = []
                use_btn = make_button('Use This', GREEN if ref == current_ref else UI_CYAN)
                use_btn.bind(on_release=lambda *_ , project=item: _direct_use_project(self, project))
                extra.append(use_btn)
                card.add_widget(_supabase_direct_item_card(name, subtitle, item, copy_label='Copy JSON', extra_buttons=extra))
        elif self.current_tab == 'users':
            rows = _supabase_direct_list_users(cfg, limit=500)
            if not rows:
                card.add_widget(make_label('No auth users returned.', color=SUBTEXT, height=dp(28)))
            card.add_widget(make_label('Showing ' + str(len(rows)) + ' auth user(s).', color=SUBTEXT, height=dp(24)))
            for item in rows:
                email = str(item.get('email', item.get('phone', 'Unknown user')) or 'Unknown user')
                created = short_time(str(item.get('created_at', '') or item.get('last_sign_in_at', '') or ''))
                role = str(item.get('role', item.get('aud', '--')) or '--')
                subtitle = role + '  •  ' + created
                card.add_widget(_supabase_direct_item_card(email, subtitle, item, copy_label='Copy JSON'))
        elif self.current_tab == 'tables':
            rows = _supabase_direct_list_tables(cfg)
            if self.current_table_name:
                preview_card = SectionCard('Preview: ' + self.current_table_name, 'Schema: ' + str(self.current_table_schema or 'public'), accent=UI_ORANGE)
                if str(self.current_table_schema or 'public').strip() != 'public':
                    preview_card.add_widget(make_label('Preview is shown only for public tables in this direct view.', color=SUBTEXT, height=dp(28)))
                else:
                    preview_rows = _supabase_direct_preview_table(cfg, self.current_table_name, self.current_table_schema, limit=6)
                    if not preview_rows:
                        preview_card.add_widget(make_label('No preview rows returned.', color=SUBTEXT, height=dp(28)))
                    else:
                        for row_data in preview_rows:
                            preview_card.add_widget(_supabase_direct_item_card('Row', 'Preview JSON', row_data, copy_label='Copy Row'))
                card.add_widget(preview_card)
            if not rows:
                card.add_widget(make_label('No tables returned.', color=SUBTEXT, height=dp(28)))
            for item in rows:
                schema = str(item.get('schema', 'public') or 'public')
                name = str(item.get('name', item.get('table_name', 'Table')) or 'Table')
                subtitle = schema
                if item.get('comment'):
                    subtitle += '  •  ' + str(item.get('comment'))[:42]
                preview_btn = make_button('Preview', UI_CYAN)
                preview_btn.bind(on_release=lambda *_ , n=name, s=schema: self._set_table(n, s))
                card.add_widget(_supabase_direct_item_card(name, subtitle, item, copy_label='Copy JSON', extra_buttons=[preview_btn]))
        elif self.current_tab == 'storage':
            rows = _supabase_direct_list_buckets(cfg)
            if not rows:
                card.add_widget(make_label('No buckets found.', color=SUBTEXT, height=dp(28)))
            for item in rows:
                title = str(item.get('name', item.get('id', 'Bucket')) or 'Bucket')
                subtitle = ('Public' if item.get('public') else 'Private') + '  •  ' + short_time(str(item.get('updated_at', '') or item.get('created_at', '') or ''))
                card.add_widget(_supabase_direct_item_card(title, subtitle, item, copy_label='Copy JSON'))
        elif self.current_tab == 'functions':
            rows = _supabase_direct_list_functions(cfg)
            if not rows:
                card.add_widget(make_label('No functions returned.', color=SUBTEXT, height=dp(28)))
            for item in rows:
                title = str(item.get('name', item.get('slug', item.get('id', 'Function'))) or 'Function')
                status = str(item.get('status', item.get('slug', '--')) or '--')
                subtitle = status
                if item.get('version'):
                    subtitle += '  •  v' + str(item.get('version'))
                card.add_widget(_supabase_direct_item_card(title, subtitle, item, copy_label='Copy JSON'))
        elif self.current_tab == 'secrets':
            rows = _supabase_direct_list_secrets(cfg)
            if not rows:
                card.add_widget(make_label('No secrets returned.', color=SUBTEXT, height=dp(28)))
            for item in rows:
                title = str(item.get('name', item.get('key', 'Secret')) or 'Secret')
                subtitle = str(item.get('digest', item.get('updated_at', '--')) or '--')
                card.add_widget(_supabase_direct_item_card(title, subtitle, item, copy_label='Copy JSON'))
    except Exception as e:
        card.add_widget(make_label('Load failed: ' + str(e), color=RED, height=dp(44)))
    return card


def _direct_use_project(screen, project_row):
    try:
        cfg = load_supabase_direct_config()
        ref = str(project_row.get('id', project_row.get('ref', project_row.get('project_ref', ''))) or '').strip()
        if ref:
            cfg['project_ref'] = ref
        save_supabase_direct_config(cfg)
        screen.refresh_ui()
        info_popup('Project selected', 'Current project reference set to ' + (ref or '--'))
    except Exception as e:
        info_popup('Project selection failed', str(e))


