# ---- final SupaBase consolidation + overview/tables reliability patch ----

def _supabase_direct_safe_fetch(label, loader, default):
    try:
        return loader(), None
    except Exception as e:
        return default, f"{label}: {e}"



def _supabase_direct_list_tables_fixed(cfg):
    attempts = [
        {'limit': '300', 'excluded_schemas': 'pg_catalog,information_schema'},
        {'limit': '300', 'included_schemas': 'public'},
        {'limit': '300'},
    ]
    last_error = None
    rows = []
    for params in attempts:
        try:
            data = _supabase_direct_project_get(cfg, '/pg/meta/tables', params=params)
            rows = _supabase_direct_listify(data, 'tables', 'data')
            if isinstance(rows, list) and rows:
                break
        except Exception as e:
            last_error = e
    if not isinstance(rows, list):
        rows = []
    rows = [row for row in rows if isinstance(row, dict)]
    if not rows:
        fallback_rows = []
        for table_name in (SUPABASE_CLOUD_BACKUPS_TABLE, SUPABASE_EMERGENCY_TABLE):
            try:
                _supabase_direct_preview_table(cfg, table_name, 'public', limit=1)
                fallback_rows.append({
                    'schema': 'public',
                    'name': table_name,
                    'comment': 'Detected from the SH Vertex app tables',
                })
            except Exception:
                pass
        if fallback_rows:
            rows = fallback_rows
        elif last_error is not None:
            raise last_error
    rows.sort(key=lambda r: (
        0 if str(r.get('schema', 'public') or 'public') == 'public' else 1,
        str(r.get('schema', '') or ''),
        str(r.get('name', '') or ''),
    ))
    return rows



def _supabase_direct_overview_payload_fixed(cfg):
    payload = {}
    errors = []
    payload['projects'], err = _supabase_direct_safe_fetch('Projects', lambda: _supabase_direct_list_projects(cfg), [])
    if err:
        errors.append(err)
    payload['current_project'], err = _supabase_direct_safe_fetch('Current project', lambda: _supabase_direct_get_project(cfg), {})
    if err:
        errors.append(err)
    payload['functions'], err = _supabase_direct_safe_fetch('Functions', lambda: _supabase_direct_list_functions(cfg), [])
    if err:
        errors.append(err)
    payload['secrets'], err = _supabase_direct_safe_fetch('Secrets', lambda: _supabase_direct_list_secrets(cfg), [])
    if err:
        errors.append(err)
    payload['users'], err = _supabase_direct_safe_fetch('Users', lambda: _supabase_direct_list_users(cfg, limit=1000), [])
    if err:
        errors.append(err)
    payload['buckets'], err = _supabase_direct_safe_fetch('Buckets', lambda: _supabase_direct_list_buckets(cfg), [])
    if err:
        errors.append(err)
    payload['tables'], err = _supabase_direct_safe_fetch('Tables', lambda: _supabase_direct_list_tables_fixed(cfg), [])
    if err:
        errors.append(err)
    payload['errors'] = errors
    return payload



def _direct_supabase_build_tab_content_fixed(self):
    card = SectionCard(dict(_DIRECT_CONTROL_TABS).get(self.current_tab, 'Overview'), 'Live project data rendered directly from the saved tokens.', accent=UI_CYAN)
    cfg = self._collect_cfg()
    if not cfg.get('url'):
        card.add_widget(make_label('Save the Project URL in Accounts → SupaBase first.', color=UI_ORANGE, height=dp(32)))
        return card
    if not cfg.get('personal_token'):
        card.add_widget(make_label('Save the personal access token in Accounts → SupaBase to load project data.', color=UI_ORANGE, height=dp(32)))
        return card
    if not cfg.get('project_key') and self.current_tab in ('overview', 'users', 'tables', 'storage'):
        card.add_widget(make_label('Save the project admin key in Accounts → SupaBase to load this tab.', color=UI_ORANGE, height=dp(32)))
        return card
    try:
        if self.current_tab == 'overview':
            payload = _supabase_direct_overview_payload_fixed(cfg)
            current = payload.get('current_project', {}) or {}
            stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(220))
            stats.add_widget(build_stat_chip(len(payload.get('projects', []) or []), 'Projects', GREEN))
            stats.add_widget(build_stat_chip(len(payload.get('users', []) or []), 'Users', UI_CYAN))
            stats.add_widget(build_stat_chip(len(payload.get('tables', []) or []), 'Tables', UI_ORANGE))
            stats.add_widget(build_stat_chip(len(payload.get('buckets', []) or []), 'Buckets', UI_TEAL))
            stats.add_widget(build_stat_chip(len(payload.get('functions', []) or []), 'Functions', UI_BLUE))
            stats.add_widget(build_stat_chip(len(payload.get('secrets', []) or []), 'Secrets', UI_PURPLE))
            status_label = str(current.get('status', current.get('db_status', '--')) or '--')
            stats.add_widget(build_stat_chip(status_label[:14], 'Project Status', UI_CYAN))
            region = str(current.get('region', current.get('region_name', '--')) or '--')
            stats.add_widget(build_stat_chip(region[:14], 'Region', UI_ORANGE))
            card.add_widget(stats)
            pname = str(current.get('name', '') or _supabase_direct_current_ref(cfg) or 'Current Project')
            subtitle = 'Ref: ' + (_supabase_direct_current_ref(cfg) or '--')
            card.add_widget(_supabase_direct_item_card(pname, subtitle, current or {'project_ref': _supabase_direct_current_ref(cfg) or '--'}, copy_label='Copy Project JSON'))
            funcs = payload.get('functions', []) or []
            if funcs:
                card.add_widget(make_label('Functions', color=SUBTEXT, height=dp(24)))
                for item in funcs[:4]:
                    title = str(item.get('name', item.get('slug', item.get('id', 'Function'))) or 'Function')
                    subtitle = str(item.get('status', item.get('slug', '')) or '--')
                    item_card = _supabase_direct_item_card(title, subtitle, item, copy_label='Copy JSON')
                    card.add_widget(item_card)
            errors = payload.get('errors', []) or []
            if errors:
                err_card = SectionCard('Overview Notes', 'Some overview sources were unavailable, but the tab still loaded.', accent=UI_ORANGE)
                for item in errors[:6]:
                    err_card.add_widget(make_label(str(item), color=SUBTEXT, height=dp(28)))
                card.add_widget(err_card)
        elif self.current_tab == 'projects':
            rows = _supabase_direct_list_projects(cfg)
            if not rows:
                card.add_widget(make_label('No projects returned for this personal access token.', color=SUBTEXT, height=dp(28)))
            current_ref = _supabase_direct_current_ref(cfg)
            for item in rows:
                ref = str(item.get('id', item.get('ref', item.get('project_ref', ''))) or '')
                name = str(item.get('name', ref or 'Project') or 'Project')
                status = str(item.get('status', item.get('db_status', '--')) or '--')
                subtitle = status + ('  •  Current' if ref == current_ref else '')
                extra = []
                use_btn = make_button('Use This', GREEN if ref == current_ref else UI_CYAN)
                use_btn.bind(on_release=lambda *_ , project=item: _direct_use_project(self, project))
                extra.append(use_btn)
                card.add_widget(_supabase_direct_item_card(name, subtitle, item, copy_label='Copy JSON', extra_buttons=extra))
        elif self.current_tab == 'users':
            rows = _supabase_direct_list_users(cfg, limit=500)
            if not rows:
                card.add_widget(make_label('No auth users returned.', color=SUBTEXT, height=dp(28)))
            card.add_widget(make_label('Showing ' + str(len(rows)) + ' auth user(s).', color=SUBTEXT, height=dp(24)))
            for item in rows:
                email = str(item.get('email', item.get('phone', 'Unknown user')) or 'Unknown user')
                created = short_time(str(item.get('created_at', '') or item.get('last_sign_in_at', '') or ''))
                role = str(item.get('role', item.get('aud', '--')) or '--')
                subtitle = role + '  •  ' + created
                card.add_widget(_supabase_direct_item_card(email, subtitle, item, copy_label='Copy JSON'))
        elif self.current_tab == 'tables':
            rows = _supabase_direct_list_tables_fixed(cfg)
            summary_card = SectionCard('Table Summary', 'Use Preview to inspect a public table quickly.', accent=UI_ORANGE)
            stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(72))
            public_count = len([r for r in rows if str(r.get('schema', 'public') or 'public') == 'public'])
            other_count = max(0, len(rows) - public_count)
            stats.add_widget(build_stat_chip(len(rows), 'Total Tables', UI_ORANGE))
            stats.add_widget(build_stat_chip(public_count, 'Public', UI_CYAN if public_count else UI_ORANGE))
            summary_card.add_widget(stats)
            if other_count:
                summary_card.add_widget(make_label(str(other_count) + ' non-public table(s) detected. Preview is limited to public tables here.', color=SUBTEXT, height=dp(28)))
            card.add_widget(summary_card)
            if self.current_table_name:
                preview_card = SectionCard('Preview: ' + self.current_table_name, 'Schema: ' + str(self.current_table_schema or 'public'), accent=UI_ORANGE)
                if str(self.current_table_schema or 'public').strip() != 'public':
                    preview_card.add_widget(make_label('Preview is shown only for public tables in this direct view.', color=SUBTEXT, height=dp(28)))
                else:
                    try:
                        preview_rows = _supabase_direct_preview_table(cfg, self.current_table_name, self.current_table_schema, limit=6)
                        if not preview_rows:
                            preview_card.add_widget(make_label('No preview rows returned.', color=SUBTEXT, height=dp(28)))
                        else:
                            for idx, row_data in enumerate(preview_rows, 1):
                                preview_card.add_widget(_supabase_direct_item_card('Row ' + str(idx), 'Preview JSON', row_data, copy_label='Copy Row'))
                    except Exception as e:
                        preview_card.add_widget(make_label('Preview failed: ' + str(e), color=UI_RED, height=dp(44)))
                card.add_widget(preview_card)
            if not rows:
                card.add_widget(make_label('No tables returned.', color=SUBTEXT, height=dp(28)))
            for item in rows:
                schema = str(item.get('schema', 'public') or 'public')
                name = str(item.get('name', item.get('table_name', 'Table')) or 'Table')
                subtitle_bits = [schema]
                if item.get('rls_enabled') is True:
                    subtitle_bits.append('RLS ON')
                elif item.get('rls_enabled') is False:
                    subtitle_bits.append('RLS OFF')
                comment = str(item.get('comment', '') or '').strip()
                if comment:
                    subtitle_bits.append(comment[:34])
                subtitle = '  •  '.join(subtitle_bits)
                preview_btn = make_button('Preview', GREEN if (name == self.current_table_name and schema == self.current_table_schema) else UI_CYAN)
                preview_btn.bind(on_release=lambda *_ , n=name, s=schema: self._set_table(n, s))
                card.add_widget(_supabase_direct_item_card(name, subtitle, item, copy_label='Copy JSON', extra_buttons=[preview_btn]))
        elif self.current_tab == 'storage':
            rows = _supabase_direct_list_buckets(cfg)
            if not rows:
                card.add_widget(make_label('No buckets found.', color=SUBTEXT, height=dp(28)))
            for item in rows:
                title = str(item.get('name', item.get('id', 'Bucket')) or 'Bucket')
                subtitle = ('Public' if item.get('public') else 'Private') + '  •  ' + short_time(str(item.get('updated_at', '') or item.get('created_at', '') or ''))
                card.add_widget(_supabase_direct_item_card(title, subtitle, item, copy_label='Copy JSON'))
        elif self.current_tab == 'functions':
            rows = _supabase_direct_list_functions(cfg)
            if not rows:
                card.add_widget(make_label('No functions returned.', color=SUBTEXT, height=dp(28)))
            for item in rows:
                title = str(item.get('name', item.get('slug', item.get('id', 'Function'))) or 'Function')
                status = str(item.get('status', item.get('slug', '--')) or '--')
                subtitle = status
                if item.get('version'):
                    subtitle += '  •  v' + str(item.get('version'))
                card.add_widget(_supabase_direct_item_card(title, subtitle, item, copy_label='Copy JSON'))
        elif self.current_tab == 'secrets':
            rows = _supabase_direct_list_secrets(cfg)
            if not rows:
                card.add_widget(make_label('No secrets returned.', color=SUBTEXT, height=dp(28)))
            for item in rows:
                title = str(item.get('name', item.get('key', 'Secret')) or 'Secret')
                subtitle = str(item.get('digest', item.get('updated_at', '--')) or '--')
                card.add_widget(_supabase_direct_item_card(title, subtitle, item, copy_label='Copy JSON'))
    except Exception as e:
        card.add_widget(make_label('Load failed: ' + str(e), color=RED, height=dp(44)))
    return card



def _accounts_build_ui_supabase_hub(self, *_):
    self._cfg = load_supabase_cloud_config()
    self._session = load_supabase_cloud_session()
    direct_cfg = load_supabase_direct_config()
    self.clear_widgets()
    root = BoxLayout(orientation='vertical', padding=[dp(10), dp(12), dp(10), dp(12)], spacing=dp(10))
    root.add_widget(build_screen_header(
        'Accounts',
        'Optional SH Vertex Cloud login, encrypted cloud backup, and one unified SupaBase module.',
        'home',
        [('Emergency Vault', 'emergency_vault')],
    ))
    scroll = ScrollView(do_scroll_x=False)
    box = BoxLayout(orientation='vertical', spacing=dp(10), size_hint_y=None)
    box.bind(minimum_height=box.setter('height'))

    sb_card = SectionCard('SupaBase', 'All Supabase setup, cloud auth, admin tools, and direct project controls in one place.', accent=UI_BLUE)
    self._sb_url = make_input('Supabase Project URL')
    self._sb_anon = make_input('Supabase Anon Key')
    self._sb_email = make_input('Account email')
    self._sb_password = make_input('Account password', password=True)
    self._sb_url.text = self._cfg.get('url', '')
    self._sb_anon.text = self._cfg.get('anon_key', '')
    self._sb_email.text = self._cfg.get('email', '')

    for title, widget in (
        ('Project URL', self._sb_url),
        ('Anon Key', self._sb_anon),
        ('Email', self._sb_email),
        ('Password', self._sb_password),
    ):
        sb_card.add_widget(make_label(title))
        sb_card.add_widget(widget)
        if widget in (self._sb_anon, self._sb_password):
            row = BoxLayout(size_hint_y=None, height=dp(40), spacing=dp(8))
            paste_btn = make_button('Paste', UI_CYAN)
            clear_btn = make_button('Clear', RED)
            paste_btn.bind(on_release=lambda *_ , w=widget: paste_clipboard_into(w))
            clear_btn.bind(on_release=lambda *_ , w=widget: setattr(w, 'text', ''))
            row.add_widget(paste_btn)
            row.add_widget(clear_btn)
            sb_card.add_widget(row)

    self._cloud_state_lbl = make_label('Not signed in.', color=SUBTEXT, height=dp(56))
    sb_card.add_widget(self._cloud_state_lbl)
    cloud_row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
    save_btn = make_button('Save Cloud Settings', UI_CYAN)
    signup_btn = make_button('Create Account', GREEN)
    login_btn = make_button('Log In', UI_CYAN)
    logout_btn = make_button('Log Out', RED)
    save_btn.bind(on_release=lambda *_: self._save_cloud_settings())
    signup_btn.bind(on_release=lambda *_: self._cloud_signup())
    login_btn.bind(on_release=lambda *_: self._cloud_login())
    logout_btn.bind(on_release=lambda *_: self._cloud_logout())
    for btn in (save_btn, signup_btn, login_btn, logout_btn):
        cloud_row.add_widget(btn)
    sb_card.add_widget(cloud_row)

    sb_card.add_widget(make_label('Supabase Setup & Direct Access', color=UI_CYAN, bold=True, height=dp(24)))
    sb_card.add_widget(make_label('Run the setup SQL once. Then save the direct token details below for live project tools.', color=SUBTEXT, height=dp(36)))

    self._direct_admin_ref = make_input('Project ref (optional if URL is set)')
    self._direct_admin_pat = make_input('Personal access token')
    self._direct_admin_key = make_input('Project admin key (service_role or secret key)')
    self._direct_admin_ref.text = direct_cfg.get('project_ref', '')
    self._direct_admin_pat.text = direct_cfg.get('personal_token', '')
    self._direct_admin_key.text = direct_cfg.get('project_key', '')

    for title, widget in (
        ('Project Ref', self._direct_admin_ref),
        ('Personal Access Token', self._direct_admin_pat),
        ('Project Admin Key', self._direct_admin_key),
    ):
        sb_card.add_widget(make_label(title))
        sb_card.add_widget(widget)
        row = BoxLayout(size_hint_y=None, height=dp(40), spacing=dp(8))
        paste_btn = make_button('Paste', UI_CYAN)
        clear_btn = make_button('Clear', RED)
        paste_btn.bind(on_release=lambda *_ , w=widget: paste_clipboard_into(w))
        clear_btn.bind(on_release=lambda *_ , w=widget: setattr(w, 'text', ''))
        row.add_widget(paste_btn)
        row.add_widget(clear_btn)
        sb_card.add_widget(row)

    self._direct_admin_state_lbl = make_label('', color=SUBTEXT, height=dp(96))
    sb_card.add_widget(self._direct_admin_state_lbl)

    direct_row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
    save_direct_btn = make_button('Save Direct Tokens', GREEN)
    open_direct_btn = make_button('Open Direct Control', UI_CYAN)
    open_users_btn = make_button('Open User Accounts', UI_CYAN)
    sync_btn = make_button('Sync URL From Cloud', UI_ORANGE)
    save_direct_btn.bind(on_release=lambda *_: self._save_direct_admin_settings())
    open_direct_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'supabase_control'))
    open_users_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'cloud_users'))
    sync_btn.bind(on_release=lambda *_: self._sync_direct_admin_from_cloud())
    for btn in (save_direct_btn, open_direct_btn, open_users_btn, sync_btn):
        direct_row.add_widget(btn)
    sb_card.add_widget(direct_row)

    tools_row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
    copy_sql_btn = make_button('Copy Setup SQL', UI_CYAN)
    test_btn = make_button('Test Session', UI_CYAN)
    copy_users_code_btn = make_button('Copy Users Fn Code', UI_CYAN)
    copy_control_code_btn = make_button('Copy Direct Fn Code', UI_CYAN)
    copy_sql_btn.bind(on_release=lambda *_: copy_to_clipboard('Supabase setup SQL', _SUPABASE_SQL_SETUP))
    test_btn.bind(on_release=lambda *_: self._test_cloud_session())
    copy_users_code_btn.bind(on_release=lambda *_: copy_to_clipboard('Supabase admin users function', _SUPABASE_ADMIN_USERS_FUNCTION_TS))
    copy_control_code_btn.bind(on_release=lambda *_: copy_to_clipboard('Supabase control function', _SUPABASE_CONTROL_FUNCTION_TS))
    for btn in (copy_sql_btn, test_btn, copy_users_code_btn, copy_control_code_btn):
        tools_row.add_widget(btn)
    sb_card.add_widget(tools_row)
    box.add_widget(sb_card)

    backup_card = SectionCard('Cloud Backup', 'Backs up all normal app content as one encrypted snapshot. This does not touch licenses, authorities, revocations, or GitHub licensing backup lanes.', accent=UI_CYAN)
    backup_card.add_widget(make_label('Includes: activity log, customer overrides, releases, websites, Synapse projects, emergency vault', color=SUBTEXT, height=dp(28)))
    backup_card.add_widget(make_label('Excludes: all licensing PEMs, authority backups, license lists, revocation exports', color=RED, height=dp(28)))
    backup_card.add_widget(make_label('Backup Password'))
    self._cloud_backup_password = make_input('Backup password for encrypted cloud snapshot', password=True)
    backup_card.add_widget(self._cloud_backup_password)
    actions = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
    backup_btn = make_button('Backup All to Cloud', GREEN)
    list_btn = make_button('Refresh Cloud List', UI_CYAN)
    latest_btn = make_button('Restore Latest', UI_ORANGE)
    vault_btn = make_button('Open Emergency Vault', UI_CYAN)
    backup_btn.bind(on_release=lambda *_: self._cloud_backup_now())
    list_btn.bind(on_release=lambda *_: self._load_cloud_backups())
    latest_btn.bind(on_release=lambda *_: self._restore_latest_cloud_backup())
    vault_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'emergency_vault'))
    for btn in (backup_btn, list_btn, latest_btn, vault_btn):
        actions.add_widget(btn)
    backup_card.add_widget(actions)
    self._backup_list_box = BoxLayout(orientation='vertical', spacing=dp(8), size_hint_y=None)
    self._backup_list_box.bind(minimum_height=self._backup_list_box.setter('height'))
    backup_card.add_widget(self._backup_list_box)
    box.add_widget(backup_card)

    scroll.add_widget(box)
    root.add_widget(scroll)
    self.add_widget(root)
    self._refresh_runtime_state()
    self._refresh_direct_admin_state()



SupabaseControlScreen._build_tab_content = _direct_supabase_build_tab_content_fixed
SupabaseControlScreen._direct_supabase_build_tab_content = _direct_supabase_build_tab_content_fixed
AccountsScreen.build_ui = _accounts_build_ui_supabase_hub
AccountsScreen._accounts_build_ui_supabase_hub = _accounts_build_ui_supabase_hub

# ---- accounts split patch: keep Open Accounts backup-only and move SupaBase into its own main-screen module ----
def _accounts_collect_cfg_split(self):
    stored = load_supabase_cloud_config()
    return {
        'url': getattr(self, '_sb_url', None).text.strip() if hasattr(self, '_sb_url') else str(stored.get('url', '') or '').strip(),
        'anon_key': getattr(self, '_sb_anon', None).text.strip() if hasattr(self, '_sb_anon') else str(stored.get('anon_key', '') or '').strip(),
        'email': getattr(self, '_sb_email', None).text.strip() if hasattr(self, '_sb_email') else str(stored.get('email', '') or '').strip(),
    }


def _accounts_collect_direct_admin_cfg_split(self):
    stored = load_supabase_direct_config()
    cloud_url = getattr(self, '_sb_url', None).text.strip() if hasattr(self, '_sb_url') else str(load_supabase_cloud_config().get('url', '') or '').strip()
    return {
        'url': getattr(self, '_direct_admin_url', None).text.strip() if hasattr(self, '_direct_admin_url') else (cloud_url or str(stored.get('url', '') or '').strip()),
        'project_ref': getattr(self, '_direct_admin_ref', None).text.strip() if hasattr(self, '_direct_admin_ref') else str(stored.get('project_ref', '') or '').strip(),
        'personal_token': getattr(self, '_direct_admin_pat', None).text.strip() if hasattr(self, '_direct_admin_pat') else str(stored.get('personal_token', '') or '').strip(),
        'project_key': getattr(self, '_direct_admin_key', None).text.strip() if hasattr(self, '_direct_admin_key') else str(stored.get('project_key', '') or '').strip(),
    }


