    self._cloud_state_lbl = make_label('Not signed in.', color=SUBTEXT, height=dp(56))
    backup_card.add_widget(self._cloud_state_lbl)
    backup_card.add_widget(make_label('Includes: activity log, customer overrides, releases, websites, Synapse projects, emergency vault', color=SUBTEXT, height=dp(28)))
    backup_card.add_widget(make_label('Excludes: all licensing PEMs, authority backups, license lists, revocation exports', color=RED, height=dp(28)))
    backup_card.add_widget(make_label('Backup Password'))
    self._cloud_backup_password = make_input('Backup password for encrypted cloud snapshot', password=True)
    backup_card.add_widget(self._cloud_backup_password)
    actions = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(94))
    backup_btn = make_button('Backup All to Cloud', GREEN)
    list_btn = make_button('Refresh Cloud List', UI_CYAN)
    latest_btn = make_button('Restore Latest', UI_ORANGE)
    backup_btn.bind(on_release=lambda *_: self._cloud_backup_now())
    list_btn.bind(on_release=lambda *_: self._load_cloud_backups())
    latest_btn.bind(on_release=lambda *_: self._restore_latest_cloud_backup())
    actions.add_widget(backup_btn)
    actions.add_widget(list_btn)
    actions.add_widget(latest_btn)
    actions.add_widget(Widget())
    backup_card.add_widget(actions)
