def _home_refresh_ui_with_supabase_module(self, *_):
    _prev_home_refresh_ui_for_cloud(self, *_)
    root_box = getattr(self, 'root_box', None)
    if root_box is None:
        return

    accounts_card = None
    bg_card = None
    exit_card = None
    for child in list(getattr(root_box, 'children', []) or []):
        if not isinstance(child, SectionCard):
            continue
        title = _home_card_title_text(child).lower()
        if title == 'accounts & cloud' and accounts_card is None:
            accounts_card = child
        elif title == 'background music' and bg_card is None:
            bg_card = child
        elif title == 'exit' and exit_card is None:
            exit_card = child

    for widget in (accounts_card, bg_card, exit_card):
        if widget is not None:
            try:
                root_box.remove_widget(widget)
            except Exception:
                pass

    card = SectionCard('ACCOUNTS & CLOUD', 'Optional SH Vertex cloud login, encrypted normal-content backup, emergency vault, and a separate SupaBase module.', accent=UI_CYAN)
    _attach_home_card_blink(card, HOME_BLINK_GREEN)
    summary = _emergency_vault_summary()
    stats = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(72))
    stats.add_widget(build_stat_chip(summary['count'], 'Vault Items', UI_CYAN))
    sess = load_supabase_cloud_session()
    state_label = str(sess.get('email', '') or '').strip() or 'Offline'
    stats.add_widget(build_stat_chip(state_label[:14], 'Cloud', GREEN if state_label != 'Offline' else UI_ORANGE))
    card.add_widget(stats)

    row = GridLayout(cols=2, spacing=dp(8), size_hint_y=None, height=dp(142))
    btn1 = make_button('Open Accounts', UI_CYAN)
    btn2 = make_button('SupaBase', UI_BLUE)
    btn3 = make_button('Open Emergency Vault', GREEN)
    btn4 = make_button('Cloud Backup', UI_CYAN)
    btn5 = make_button('Cloud Restore', UI_ORANGE)
    btn1.bind(on_release=lambda *_: setattr(self.manager, 'current', 'accounts'))
    btn2.bind(on_release=lambda *_: setattr(self.manager, 'current', 'supabase_hub'))
    btn3.bind(on_release=lambda *_: setattr(self.manager, 'current', 'emergency_vault'))
    btn4.bind(on_release=lambda *_: setattr(self.manager, 'current', 'accounts'))
    btn5.bind(on_release=lambda *_: setattr(self.manager, 'current', 'accounts'))
    for btn in (btn1, btn2, btn3, btn4, btn5):
        row.add_widget(btn)
    row.add_widget(Widget())
    card.add_widget(row)

    root_box.add_widget(card)
    if bg_card is not None:
        root_box.add_widget(bg_card)
    if exit_card is not None:
        root_box.add_widget(exit_card)


