# ABSOLUTE FINAL — force on_pre_enter to bypass weak-method caching
# by calling the class method directly. This guarantees our latest
# refresh_ui is always what runs regardless of when the screen was instantiated.
# ═══════════════════════════════════════════════════════════════════════════════

def _force_refresh_on_pre_enter(self, *_):
    Clock.schedule_once(lambda dt: self.__class__.refresh_ui(self), 0)

