# ── Patch Supa generate view: add Paste/Clear buttons for Device Code ──────────
_orig_supa_build_generate_view = SupaLicenseManagerScreen.build_generate_view

def _supa_build_generate_view_with_paste(self):
    scroll = _orig_supa_build_generate_view(self)
    # Walk into scroll -> box -> card -> find the device_input and inject buttons after it
    try:
        from kivy.uix.boxlayout import BoxLayout as _BL
        from kivy.uix.gridlayout import GridLayout as _GL
        # The structure is ScrollView > GridLayout(box) > SectionCard(card)
        box  = scroll.children[0]   # GridLayout
        card = box.children[-1]     # SectionCard (last added = first in reversed children)
        # Find device_input position in card.children (reversed order in Kivy)
        children = list(reversed(card.children))
        try:
            idx = children.index(self.device_input)
        except ValueError:
            return scroll
        # Insert paste/clear row right after device_input (idx+1)
        paste_clear_row = _BL(size_hint_y=None, height=dp(46), spacing=dp(8))
        paste_btn = make_button("Paste Device Code", UI_CYAN)
        clear_btn = make_button("Clear Device Code", RED)
        paste_btn.bind(on_release=lambda *_: setattr(
            self.device_input, 'text', __import__('kivy.core.clipboard', fromlist=['Clipboard']).Clipboard.paste() or ''))
        clear_btn.bind(on_release=lambda *_: setattr(self.device_input, 'text', ''))
        paste_clear_row.add_widget(paste_btn)
        paste_clear_row.add_widget(clear_btn)
        # In Kivy, add_widget inserts at index 0 (top of stack) by default.
        # We want after device_input visually, which means index = len(children) - idx - 2
        insert_index = len(card.children) - idx - 2
        card.add_widget(paste_clear_row, index=max(0, insert_index))
    except Exception:
        pass
    return scroll

SupaLicenseManagerScreen.build_generate_view = _supa_build_generate_view_with_paste


