# ANDROID BACK BUTTON HANDLER
# On the home screen: show exit confirmation popup.
# On any other screen: navigate to the registered back_target for that screen,
# or fall back to 'home' if none is registered.
# ═══════════════════════════════════════════════════════════════════════════════

# Registry: screen_name -> back_target
_SCREEN_BACK_TARGETS = {
    'licensing':        'home',
    'apps':             'licensing',
    'backup_vault':     'home',
    'authority_status': 'home',
    'customers':        'home',
    'activity':         'home',
    'releases':         'home',
    'docs':             'home',
    'company_modules':  'home',
    'app_data_backup':  'home',
    'websites':         'home',
    'synapse_manager':  'apps',
    'casino_manager':   'apps',
    'budget_manager':   'apps',
    'ssp_manager':      'apps',
    'supa_manager':     'apps',
    'accounts':         'home',
    'supabase_hub':     'home',
    'releases':         'home',
}

_original_shv_panel_app_build_for_back = SHVertexAdminPanelApp.build

def _back_button_shv_panel_app_build(self):
    sm = _original_shv_panel_app_build_for_back(self)

    def _on_keyboard(window, key, *args):
        KEYCODE_BACK = 27
        if key != KEYCODE_BACK:
            return False
        try:
            current = sm.current
        except Exception:
            return False

        if current == 'home':
            # Show exit confirmation
            app = App.get_running_app()
            on_confirm = getattr(app, 'play_exit_sound_then_stop', app.stop) if app else (lambda: None)
            _confirm_action_popup('Exit App', 'Close SH Vertex Admin Panel?', 'Exit', UI_RED, on_confirm)
            return True

        # Navigate to registered back target
        back_dest = _SCREEN_BACK_TARGETS.get(current, 'home')
        try:
            sm.current = back_dest
        except Exception:
            try:
                sm.current = 'home'
            except Exception:
                pass
        return True

    try:
        from kivy.core.window import Window as _Win
        _Win.bind(on_keyboard=_on_keyboard)
    except Exception:
        pass

    return sm

SHVertexAdminPanelApp.build = _back_button_shv_panel_app_build


