import base64 as _b64
_SUPA_DASH_SOURCE = _b64.b64decode(_SUPA_DASH_SOURCE_B64.encode("ascii")).decode("utf-8")
del _b64
_SUPA_DASH_NS = {'__name__': '_shv_supa_dashboard_module'}
try:
    exec(_SUPA_DASH_SOURCE, _SUPA_DASH_NS)
    _SupabaseAdminRootCls = _SUPA_DASH_NS.get('SupabaseAdminRoot')
except Exception as _supa_dash_exc:
    _SupabaseAdminRootCls = None
    _supa_dash_exec_error = str(_supa_dash_exc)


class SupabaseDashboardScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._widget_built = False
        Clock.schedule_once(self.build_ui, 0)

    def build_ui(self, *_):
        self.clear_widgets()
        root = BoxLayout(orientation='vertical', padding=[dp(8), dp(8), dp(8), dp(8)], spacing=dp(8))
        nav = BoxLayout(size_hint_y=None, height=dp(46), spacing=dp(8))
        back_btn = make_button('Back', UI_CYAN)
        home_btn = make_button('Home', UI_CYAN)
        back_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'company_modules'))
        home_btn.bind(on_release=lambda *_: setattr(self.manager, 'current', 'home'))
        nav.add_widget(back_btn)
        nav.add_widget(home_btn)
        root.add_widget(nav)
        title = Label(
            text='Supabase Dashboard',
            font_size='20sp', bold=True,
            color=get_color_from_hex('#f0c040'),
            size_hint_y=None, height=dp(36),
            halign='center', valign='middle',
        )
        title.bind(size=lambda inst, val: setattr(inst, 'text_size', val))
        root.add_widget(title)
        self._host = BoxLayout()
        root.add_widget(self._host)
        self.add_widget(root)

    def on_pre_enter(self, *_):
        if not self._widget_built:
            self._widget_built = True
            Clock.schedule_once(self._load_supa_widget, 0)

    def _load_supa_widget(self, *_):
        if not hasattr(self, '_host'):
            return
        self._host.clear_widgets()
        loading = SectionCard('Loading Supabase Dashboard...', 'Initialising connection...')
        self._host.add_widget(loading)
        Clock.schedule_once(self._do_build_supa, 0)

    def _do_build_supa(self, *_):
        if not hasattr(self, '_host'):
            return
        self._host.clear_widgets()
        if _SupabaseAdminRootCls is None:
            err_msg = globals().get('_supa_dash_exec_error', 'SupabaseAdminRoot could not be loaded.')
            err = SectionCard('Supabase Dashboard Error', err_msg[:300])
            retry_btn = make_button('Retry', GREEN)
            retry_btn.bind(on_release=lambda *_: self._load_supa_widget())
            err.add_widget(retry_btn)
            self._host.add_widget(err)
            return
        try:
            widget = _SupabaseAdminRootCls()
            self._host.add_widget(widget)
        except Exception as e:
            err = SectionCard('Supabase Dashboard Error', str(e)[:300])
            retry_btn = make_button('Retry', GREEN)
            retry_btn.bind(on_release=lambda *_: self._load_supa_widget())
            err.add_widget(retry_btn)
            self._host.add_widget(err)


# ── Register SupabaseDashboardScreen ──────────────────────────────────────────
_original_admin_build_for_supa_dash = SHVertexAdminPanelApp.build
def _supa_dash_admin_build(self):
    sm = _original_admin_build_for_supa_dash(self)
    try:
        sm.get_screen('supabase_dashboard')
    except Exception:
        sm.add_widget(SupabaseDashboardScreen(name='supabase_dashboard'))
    return sm
SHVertexAdminPanelApp.build = _supa_dash_admin_build

# ── Add to back-button registry ───────────────────────────────────────────────
_SCREEN_BACK_TARGETS['supabase_dashboard'] = 'company_modules'

# Post-render patch removed — button is embedded directly in home refresh

if __name__ == '__main__':
    SHVertexAdminPanelApp().run()
